// Cached cursors. LoadCursor() goes to the OS; calling it for every mouse move
// (which fires at 1000Hz on high-DPI mice) is a needless kernel round trip.
// SetCursor() with a handle we already own is essentially free.
static HCURSOR g_cursor_arrow = nullptr;
static HCURSOR g_cursor_hand = nullptr;
static HCURSOR g_cursor_sizewe = nullptr;
static HCURSOR g_cursor_sizens = nullptr;
static HCURSOR g_cursor_ibeam = nullptr;
static HCURSOR g_cursor_last_set = nullptr;  // last value passed to SetCursor

static inline HCURSOR cursor_arrow()  { if (!g_cursor_arrow)  g_cursor_arrow  = LoadCursor(nullptr, IDC_ARROW);  return g_cursor_arrow;  }
static inline HCURSOR cursor_hand()   { if (!g_cursor_hand)   g_cursor_hand   = LoadCursor(nullptr, IDC_HAND);   return g_cursor_hand;   }
static inline HCURSOR cursor_sizewe() { if (!g_cursor_sizewe) g_cursor_sizewe = LoadCursor(nullptr, IDC_SIZEWE); return g_cursor_sizewe; }
static inline HCURSOR cursor_sizens() { if (!g_cursor_sizens) g_cursor_sizens = LoadCursor(nullptr, IDC_SIZENS); return g_cursor_sizens; }
static inline HCURSOR cursor_ibeam()  { if (!g_cursor_ibeam)  g_cursor_ibeam  = LoadCursor(nullptr, IDC_IBEAM);  return g_cursor_ibeam;  }

static inline void set_cursor_cached(HCURSOR c) {
    if (c != g_cursor_last_set) {
        g_cursor_last_set = c;
        SetCursor(c);
    }
}
