// Frame-driven animation clock
FrameClock g_frame_clock = {};

// Animation scheduler: tracks active animations for continuous rendering
AnimationScheduler g_animation_scheduler = {};

void FrameClock::init() {
    QueryPerformanceFrequency(&frequency);
    QueryPerformanceCounter(&last_frame_time);
    last_refresh_check = last_frame_time;  // Initialize refresh check time
    refresh_period = detect_refresh_period();
    delta_time = refresh_period;  // Reasonable initial value
    initialized = true;
}

float FrameClock::update() {
    if (!initialized) {
        init();
    }

    LARGE_INTEGER now;
    QueryPerformanceCounter(&now);

    double elapsed = static_cast<double>(now.QuadPart - last_frame_time.QuadPart)
                   / static_cast<double>(frequency.QuadPart);

    // Clamp to prevent huge jumps (debugging, window drag, etc.)
    // Max 100ms = 10fps minimum
    delta_time = static_cast<float>(fmin(elapsed, 0.1));
    last_frame_time = now;

    // Periodically re-detect refresh rate for VRR/monitor changes
    maybe_update_refresh_rate();

    return delta_time;
}

float FrameClock::detect_refresh_period() {
    DWM_TIMING_INFO timing = {};
    timing.cbSize = sizeof(DWM_TIMING_INFO);

    if (SUCCEEDED(DwmGetCompositionTimingInfo(nullptr, &timing)) &&
        timing.qpcRefreshPeriod > 0) {
        // qpcRefreshPeriod is in QPC units
        return static_cast<float>(timing.qpcRefreshPeriod)
             / static_cast<float>(frequency.QuadPart);
    }
    return 1.0f / 60.0f;  // Fallback to 60Hz
}

void FrameClock::maybe_update_refresh_rate() {
    LARGE_INTEGER now;
    QueryPerformanceCounter(&now);

    double elapsed = static_cast<double>(now.QuadPart - last_refresh_check.QuadPart)
                   / static_cast<double>(frequency.QuadPart);

    if (elapsed >= REFRESH_CHECK_INTERVAL) {
        refresh_period = detect_refresh_period();
        last_refresh_check = now;
    }
}

// ============================================================================
// Spring Animation Implementation (closed-form analytical solution)
// ============================================================================
//
// Based on Ryan Juckett's damped spring implementation:
// https://www.ryanjuckett.com/damped-springs/
// Licensed under permissive license allowing commercial use with attribution.

SpringCoefficients calc_spring_coefficients(float dt, float angularFrequency, float dampingRatio) {
    SpringCoefficients c{};

    constexpr float epsilon = 0.0001f;

    // Clamp to valid range
    if (dampingRatio < 0.0f) dampingRatio = 0.0f;
    if (angularFrequency < epsilon) {
        // No spring force - maintain current state
        c.posPosCoef = 1.0f;
        c.posVelCoef = 0.0f;
        c.velPosCoef = 0.0f;
        c.velVelCoef = 1.0f;
        return c;
    }

    if (dampingRatio > 1.0f + epsilon) {
        // Overdamped: slow approach, no overshoot
        float za = -angularFrequency * dampingRatio;
        float zb = angularFrequency * sqrtf(dampingRatio * dampingRatio - 1.0f);
        float z1 = za - zb;
        float z2 = za + zb;

        float e1 = expf(z1 * dt);
        float e2 = expf(z2 * dt);

        float invTwoZb = 1.0f / (2.0f * zb);

        float e1_Over_TwoZb = e1 * invTwoZb;
        float e2_Over_TwoZb = e2 * invTwoZb;
        float z1e1_Over_TwoZb = z1 * e1_Over_TwoZb;
        float z2e2_Over_TwoZb = z2 * e2_Over_TwoZb;

        c.posPosCoef = e1_Over_TwoZb * z2 - z2e2_Over_TwoZb + e2;
        c.posVelCoef = -e1_Over_TwoZb + e2_Over_TwoZb;
        c.velPosCoef = (z1e1_Over_TwoZb - z2e2_Over_TwoZb + e2) * z2;
        c.velVelCoef = -z1e1_Over_TwoZb + z2e2_Over_TwoZb;
    }
    else if (dampingRatio < 1.0f - epsilon) {
        // Underdamped: oscillates with decay (most common for UI bounce)
        float omegaZeta = angularFrequency * dampingRatio;
        float alpha = angularFrequency * sqrtf(1.0f - dampingRatio * dampingRatio);

        float expTerm = expf(-omegaZeta * dt);
        float cosTerm = cosf(alpha * dt);
        float sinTerm = sinf(alpha * dt);

        float invAlpha = 1.0f / alpha;

        float expSin = expTerm * sinTerm;
        float expCos = expTerm * cosTerm;
        float expOmegaZetaSin_Over_Alpha = expTerm * omegaZeta * sinTerm * invAlpha;

        c.posPosCoef = expCos + expOmegaZetaSin_Over_Alpha;
        c.posVelCoef = expSin * invAlpha;
        c.velPosCoef = -expSin * alpha - omegaZeta * expOmegaZetaSin_Over_Alpha;
        c.velVelCoef = expCos - expOmegaZetaSin_Over_Alpha;
    }
    else {
        // Critically damped: fastest settle, no overshoot
        float expTerm = expf(-angularFrequency * dt);
        float timeExp = dt * expTerm;
        float timeExpFreq = timeExp * angularFrequency;

        c.posPosCoef = timeExpFreq + expTerm;
        c.posVelCoef = timeExp;
        c.velPosCoef = -angularFrequency * timeExpFreq;
        c.velVelCoef = -timeExpFreq + expTerm;
    }

    return c;
}

bool spring_update(float& value, float& velocity, float target,
                   const SpringCoefficients& c,
                   float settleThreshold,
                   float velocityThreshold) {
    // Work in equilibrium-relative space
    float oldPos = value - target;
    float oldVel = velocity;

    float newPos = oldPos * c.posPosCoef + oldVel * c.posVelCoef;
    float newVel = oldPos * c.velPosCoef + oldVel * c.velVelCoef;

    value = newPos + target;
    velocity = newVel;

    // Check if settled
    if (fabsf(newPos) < settleThreshold && fabsf(newVel) < velocityThreshold) {
        value = target;
        velocity = 0.0f;
        return false;
    }
    return true;
}

bool spring_update_windows_style(float& value, float& velocity, float target, float dt,
                                  float period, float dampingRatio,
                                  float settleThreshold,
                                  float velocityThreshold) {
    constexpr float TWO_PI = 6.28318530718f;
    float angularFrequency = (period > 0.0001f) ? (TWO_PI / period) : 0.0f;
    auto coeffs = calc_spring_coefficients(dt, angularFrequency, dampingRatio);
    return spring_update(value, velocity, target, coeffs, settleThreshold, velocityThreshold);
}

bool spring_update_stiffness_damping(float& value, float& velocity, float target, float dt,
                                      float stiffness, float damping,
                                      float settleThreshold,
                                      float velocityThreshold) {
    float angularFrequency = sqrtf(stiffness);
    float dampingRatio = damping / (2.0f * angularFrequency);
    auto coeffs = calc_spring_coefficients(dt, angularFrequency, dampingRatio);
    return spring_update(value, velocity, target, coeffs, settleThreshold, velocityThreshold);
}

#ifdef GITSMARTER_DEBUG
// Frame statistics for debug overlay (F3 to toggle)
struct FrameStats {
    float fps;
    float frame_time_ms;
    float avg_frame_time_ms;
    int active_animations;
    float refresh_rate_hz;

    // Ring buffer for averaging
    static constexpr int SAMPLE_COUNT = 60;
    float frame_times[SAMPLE_COUNT];
    int sample_index;
    int sample_count;

    void record_frame(float dt) {
        frame_time_ms = dt * 1000.0f;
        fps = dt > 0.0f ? 1.0f / dt : 0.0f;

        frame_times[sample_index] = dt;
        sample_index = (sample_index + 1) % SAMPLE_COUNT;
        if (sample_count < SAMPLE_COUNT) sample_count++;

        // Calculate average
        float sum = 0.0f;
        for (int i = 0; i < sample_count; i++) {
            sum += frame_times[i];
        }
        avg_frame_time_ms = (sum / sample_count) * 1000.0f;
    }

    void update_from_scheduler() {
        active_animations = g_animation_scheduler.active_count.load(std::memory_order_relaxed);
        refresh_rate_hz = g_frame_clock.refresh_period > 0.0f
                        ? 1.0f / g_frame_clock.refresh_period
                        : 60.0f;
    }
};

static FrameStats g_frame_stats = {};
static bool g_show_debug_overlay = false;
#endif

