// Handle branch checkout from sidebar double-click
static void handle_branch_checkout(HWND hwnd, const GitRef* ref) {
    if (!ref) return;

    // 1. Check if already on this branch (no-op)
    if (ref->type == GitRef::Type::Local) {
        bool already_on_branch = false;
        {
            RepoLockGuard lock;
            if (!g_repo.head_detached && strcmp(g_repo.head_ref, ref->name) == 0) {
                already_on_branch = true;
            }
        }
        if (already_on_branch) {
            wchar_t msg[256];
            wchar_t branch_wide[128];
            MultiByteToWideChar(CP_UTF8, 0, ref->name, -1, branch_wide, 128);
            swprintf_s(msg, L"Already on branch '%s'", branch_wide);
            MessageBoxW(hwnd, msg, L"Checkout", MB_OK | MB_ICONINFORMATION);
            return;
        }
    }

    // 2. Check if worker is busy
    bool worker_busy = worker_is_busy();

    if (worker_busy) {
        MessageBoxW(hwnd, L"Another operation is in progress.\nPlease wait for it to complete.",
                    L"Checkout", MB_OK | MB_ICONWARNING);
        return;
    }

    // 3. Check for uncommitted changes
    bool workdir_clean;
    {
        RepoLockGuard lock;
        workdir_clean = git_workdir_is_clean(&g_repo);
    }

    if (!workdir_clean) {
        int response = MessageBoxW(hwnd,
            L"You have uncommitted changes that would be overwritten by checkout.\n\n"
            L"Do you want to continue anyway?\n"
            L"(Your uncommitted changes will be lost)",
            L"Uncommitted Changes", MB_YESNO | MB_ICONWARNING | MB_DEFBUTTON2);

        if (response != IDYES) {
            return;  // User cancelled
        }
    }

    // 4. Handle remote branch - ask about creating tracking branch
    bool create_tracking = false;
    char new_branch_name[Git::MAX_REF_NAME] = {0};

    if (ref->type == GitRef::Type::Remote) {
        // Extract suggested branch name (strip remote prefix like "origin/")
        const char* slash = strchr(ref->name, '/');
        const char* suggested = slash ? slash + 1 : ref->name;

        wchar_t msg[512];
        wchar_t ref_wide[256];
        wchar_t suggested_wide[128];
        MultiByteToWideChar(CP_UTF8, 0, ref->name, -1, ref_wide, 256);
        MultiByteToWideChar(CP_UTF8, 0, suggested, -1, suggested_wide, 128);

        swprintf_s(msg,
            L"Checkout remote branch '%s'.\n\n"
            L"Would you like to:\n"
            L"\u2022 YES: Create local tracking branch '%s'\n"
            L"\u2022 NO: Checkout in detached HEAD mode\n"
            L"\u2022 CANCEL: Abort checkout",
            ref_wide, suggested_wide);

        int response = MessageBoxW(hwnd, msg, L"Remote Branch",
                                   MB_YESNOCANCEL | MB_ICONQUESTION);

        if (response == IDCANCEL) {
            return;  // User cancelled
        }

        if (response == IDYES) {
            create_tracking = true;
            strcpy_s(new_branch_name, suggested);

            // Check if branch already exists
            bool branch_exists = false;
            {
                RepoLockGuard lock;
                for (size_t i = 0; i < g_sidebar.branch_count; i++) {
                    if (g_sidebar.branches[i].type == GitRef::Type::Local &&
                        strcmp(g_sidebar.branches[i].name, new_branch_name) == 0) {
                        branch_exists = true;
                        break;
                    }
                }
            }

            if (branch_exists) {
                wchar_t exists_msg[256];
                swprintf_s(exists_msg,
                    L"A local branch '%s' already exists.\n\n"
                    L"Checking out in detached HEAD mode instead.",
                    suggested_wide);
                MessageBoxW(hwnd, exists_msg, L"Branch Exists", MB_OK | MB_ICONINFORMATION);
                create_tracking = false;
                new_branch_name[0] = '\0';
            }
        }
    }

    // 5. Handle tag checkout - warn about detached HEAD
    if (ref->type == GitRef::Type::Tag) {
        wchar_t msg[256];
        wchar_t tag_wide[128];
        MultiByteToWideChar(CP_UTF8, 0, ref->name, -1, tag_wide, 128);
        swprintf_s(msg,
            L"Checking out tag '%s' will put you in detached HEAD mode.\n\n"
            L"Any commits you make will not be on any branch.\n"
            L"Continue?", tag_wide);

        if (MessageBoxW(hwnd, msg, L"Tag Checkout",
                        MB_YESNO | MB_ICONQUESTION | MB_DEFBUTTON2) != IDYES) {
            return;  // User cancelled
        }
    }

    // 6. Start async checkout
    if (!worker_start_async_checkout(ref, create_tracking, new_branch_name[0] ? new_branch_name : nullptr)) {
        MessageBoxW(hwnd, L"Failed to start checkout operation.", L"Checkout Error", MB_OK | MB_ICONERROR);
    }
}

// Release device-dependent D2D resources (called on device recreation and cleanup)
static void release_d2d_device_resources() {
    if (g_diff_brush) {
        g_diff_brush->Release();
        g_diff_brush = nullptr;
    }
    if (g_commit_history_brush) {
        g_commit_history_brush->Release();
        g_commit_history_brush = nullptr;
    }
    if (g_blur_effect) {
        g_blur_effect->Release();
        g_blur_effect = nullptr;
    }
    if (g_d2d_device_context) {
        g_d2d_device_context->Release();
        g_d2d_device_context = nullptr;
    }
}

// Cleanup all resources
void platform_cleanup() {
    // Shutdown worker thread using API
    worker_cleanup();

    // Shutdown file watcher using API
    file_watcher_stop();

    // Welcome screen text formats
    if (g_text_format_repo_path) {
        g_text_format_repo_path->Release();
        g_text_format_repo_path = nullptr;
    }
    if (g_text_format_repo_name) {
        g_text_format_repo_name->Release();
        g_text_format_repo_name = nullptr;
    }
    if (g_text_format_button) {
        g_text_format_button->Release();
        g_text_format_button = nullptr;
    }
    if (g_text_format_welcome_subtitle) {
        g_text_format_welcome_subtitle->Release();
        g_text_format_welcome_subtitle = nullptr;
    }
    if (g_text_format_welcome_title) {
        g_text_format_welcome_title->Release();
        g_text_format_welcome_title = nullptr;
    }
    if (g_text_format_oauth_code) {
        g_text_format_oauth_code->Release();
        g_text_format_oauth_code = nullptr;
    }
    if (g_text_format_tooltip) {
        g_text_format_tooltip->Release();
        g_text_format_tooltip = nullptr;
    }

    // Sidebar text formats
    if (g_text_format_path) {
        g_text_format_path->Release();
        g_text_format_path = nullptr;
    }
    if (g_text_format_badge) {
        g_text_format_badge->Release();
        g_text_format_badge = nullptr;
    }
    if (g_text_format_hint) {
        g_text_format_hint->Release();
        g_text_format_hint = nullptr;
    }
    if (g_text_format_mono) {
        g_text_format_mono->Release();
        g_text_format_mono = nullptr;
    }
    if (g_text_format_body) {
        g_text_format_body->Release();
        g_text_format_body = nullptr;
    }
    if (g_text_format_header) {
        g_text_format_header->Release();
        g_text_format_header = nullptr;
    }
    if (g_title_format) {
        g_title_format->Release();
        g_title_format = nullptr;
    }
    if (g_dwrite_factory) {
        g_dwrite_factory->Release();
        g_dwrite_factory = nullptr;
    }
    if (g_wic_factory) {
        g_wic_factory->Release();
        g_wic_factory = nullptr;
    }
    release_d2d_device_resources();
    if (g_render_target) {
        g_render_target->Release();
        g_render_target = nullptr;
    }
    if (g_d2d_factory) {
        g_d2d_factory->Release();
        g_d2d_factory = nullptr;
    }

    // Close repository if open
    {
        RepoLockGuard lock;
        git_repo_close(&g_repo);
    }
}

// Apply DWM effects (rounded corners, shadow)
static void apply_dwm_effects(HWND hwnd) {
    // Enable rounded corners on Windows 11
    // DWMWA_WINDOW_CORNER_PREFERENCE = 33
    enum { DWMWA_WINDOW_CORNER_PREFERENCE = 33 };
    enum { DWMWCP_ROUND = 2 };
    int preference = DWMWCP_ROUND;
    DwmSetWindowAttribute(hwnd, DWMWA_WINDOW_CORNER_PREFERENCE, &preference, sizeof(preference));

    // Extend frame into client area slightly to enable DWM shadow
    MARGINS margins = { 0, 0, 0, 1 };
    DwmExtendFrameIntoClientArea(hwnd, &margins);
}

// Start close animation - simplified (no animation, just save and destroy)
static void start_close_animation(HWND hwnd) {
    // Save window placement before closing
    settings_save_window_placement(hwnd);

    // Destroy the window immediately
    DestroyWindow(hwnd);
}

// Initialize Direct2D and DirectWrite
static bool d2d_init(HWND hwnd) {
    HRESULT hr;
    // On D2DERR_RECREATE_TARGET we only need to recreate the render target.
    // The factories and text formats survive — re-creating them would leak
    // the previous instances (no Release calls before overwriting), which
    // can exhaust system resources on repeat device-lost events (e.g. laptop
    // dock/undock).
    if (!g_d2d_factory) {
        hr = D2D1CreateFactory(D2D1_FACTORY_TYPE_SINGLE_THREADED, &g_d2d_factory);
        if (FAILED(hr)) return false;
    }

    // Initialize DirectWrite for text rendering
    if (!g_dwrite_factory) {
        hr = DWriteCreateFactory(DWRITE_FACTORY_TYPE_SHARED,
            __uuidof(IDWriteFactory),
            reinterpret_cast<IUnknown**>(&g_dwrite_factory));
        if (FAILED(hr)) return false;
    }

    // Initialize WIC for icon conversion
    if (!g_wic_factory) {
        hr = CoCreateInstance(
            CLSID_WICImagingFactory,
            nullptr,
            CLSCTX_INPROC_SERVER,
            IID_PPV_ARGS(&g_wic_factory)
        );
        if (FAILED(hr)) return false;
    }

    // Text formats are device-INDEPENDENT — skip recreation on device-lost (when
    // already populated) to avoid leaking previous IDWriteTextFormat instances.
    if (g_title_format) {
        // Already initialized; jump to render target creation below.
        goto create_render_target;
    }

    // Create text format for title
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_NORMAL,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        12.0f,
        L"en-us",
        &g_title_format);
    if (FAILED(hr)) return false;

    g_title_format->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING);
    g_title_format->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Section headers: 11pt, semi-bold
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_SEMI_BOLD,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        11.0f,
        L"en-us",
        &g_text_format_header);
    if (FAILED(hr)) return false;
    g_text_format_header->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING);
    g_text_format_header->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Body text: 12pt, normal
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_NORMAL,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        12.0f,
        L"en-us",
        &g_text_format_body);
    if (FAILED(hr)) return false;
    g_text_format_body->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING);
    g_text_format_body->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Monospace: 11pt, Cascadia Code (fallback to Consolas handled by DirectWrite)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Cascadia Code",
        nullptr,
        DWRITE_FONT_WEIGHT_NORMAL,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        11.0f,
        L"en-us",
        &g_text_format_mono);
    if (FAILED(hr)) return false;
    g_text_format_mono->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING);
    g_text_format_mono->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Keyboard hints: 9pt, normal
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_NORMAL,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        9.0f,
        L"en-us",
        &g_text_format_hint);
    if (FAILED(hr)) return false;
    g_text_format_hint->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_TRAILING);
    g_text_format_hint->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // File paths: 10pt, normal (left-aligned for directory paths under filenames)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_NORMAL,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        10.0f,
        L"en-us",
        &g_text_format_path);
    if (FAILED(hr)) return false;
    g_text_format_path->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING);
    g_text_format_path->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);
    g_text_format_path->SetWordWrapping(DWRITE_WORD_WRAPPING_NO_WRAP);

    // Badge text: 10pt, bold (centered)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_BOLD,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        10.0f,
        L"en-us",
        &g_text_format_badge);
    if (FAILED(hr)) return false;
    g_text_format_badge->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
    g_text_format_badge->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Welcome screen: Title (28pt, semi-bold, centered)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_SEMI_BOLD,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        Welcome::TITLE_FONT_SIZE,
        L"en-us",
        &g_text_format_welcome_title);
    if (FAILED(hr)) return false;
    g_text_format_welcome_title->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
    g_text_format_welcome_title->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Welcome screen: Subtitle (13pt, normal, centered)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_NORMAL,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        Welcome::SUBTITLE_FONT_SIZE,
        L"en-us",
        &g_text_format_welcome_subtitle);
    if (FAILED(hr)) return false;
    g_text_format_welcome_subtitle->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
    g_text_format_welcome_subtitle->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Welcome screen: Button text (13pt, semi-bold, centered)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_SEMI_BOLD,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        13.0f,
        L"en-us",
        &g_text_format_button);
    if (FAILED(hr)) return false;
    g_text_format_button->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
    g_text_format_button->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Welcome screen: Repo name (13pt, semi-bold, leading)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_SEMI_BOLD,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        13.0f,
        L"en-us",
        &g_text_format_repo_name);
    if (FAILED(hr)) return false;
    g_text_format_repo_name->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING);
    g_text_format_repo_name->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Welcome screen: Repo path/timestamp (11pt, normal, leading)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_NORMAL,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        11.0f,
        L"en-us",
        &g_text_format_repo_path);
    if (FAILED(hr)) return false;
    g_text_format_repo_path->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING);
    g_text_format_repo_path->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // OAuth dialog: Device code (24pt, bold, centered)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI",
        nullptr,
        DWRITE_FONT_WEIGHT_BOLD,
        DWRITE_FONT_STYLE_NORMAL,
        DWRITE_FONT_STRETCH_NORMAL,
        OAuthDialog::CODE_FONT_SIZE,
        L"en-us",
        &g_text_format_oauth_code);
    if (FAILED(hr)) return false;
    g_text_format_oauth_code->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
    g_text_format_oauth_code->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

    // Tooltip text format (11pt, centered)
    hr = g_dwrite_factory->CreateTextFormat(
        L"Segoe UI", nullptr,
        DWRITE_FONT_WEIGHT_NORMAL, DWRITE_FONT_STYLE_NORMAL, DWRITE_FONT_STRETCH_NORMAL,
        11.0f, L"en-us",
        &g_text_format_tooltip);
    if (FAILED(hr)) return false;
    g_text_format_tooltip->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
    g_text_format_tooltip->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);

create_render_target:
    RECT rc;
    GetClientRect(hwnd, &rc);

    D2D1_RENDER_TARGET_PROPERTIES props = D2D1::RenderTargetProperties();
    D2D1_HWND_RENDER_TARGET_PROPERTIES hwnd_props = D2D1::HwndRenderTargetProperties(
        hwnd,
        D2D1::SizeU(rc.right - rc.left, rc.bottom - rc.top)
    );

    hr = g_d2d_factory->CreateHwndRenderTarget(props, hwnd_props, &g_render_target);
    if (FAILED(hr)) return false;

    // Query for ID2D1DeviceContext to enable effects (blur, etc.)
    hr = g_render_target->QueryInterface(__uuidof(ID2D1DeviceContext),
                                         reinterpret_cast<void**>(&g_d2d_device_context));
    if (SUCCEEDED(hr) && g_d2d_device_context) {
        // Create cached Gaussian blur effect
        hr = g_d2d_device_context->CreateEffect(CLSID_D2D1GaussianBlur, &g_blur_effect);
        if (FAILED(hr)) {
            g_blur_effect = nullptr;  // Blur unavailable, will skip during render
        }
    }

    return true;
}

// Resize render target
static void d2d_resize(UINT width, UINT height) {
    if (g_render_target) {
        g_render_target->Resize(D2D1::SizeU(width, height));
    }
}

