// Helper to calculate commit box height based on text content
static float calculate_commit_box_height() {
    if (g_sidebar.commit_message[0] == L'\0') {
        return Sidebar::COMMIT_BOX_MIN_HEIGHT;
    }

    // Count newlines to determine number of lines
    int line_count = 1;
    for (size_t i = 0; g_sidebar.commit_message[i]; i++) {
        if (g_sidebar.commit_message[i] == L'\n') {
            line_count++;
        }
    }

    // Calculate height: lines * line_height + padding
    float text_height = line_count * Sidebar::COMMIT_LINE_HEIGHT + Sidebar::COMMIT_BOX_PADDING * 2;
    // Clamp between min and max
    if (text_height < Sidebar::COMMIT_BOX_MIN_HEIGHT) text_height = Sidebar::COMMIT_BOX_MIN_HEIGHT;
    if (text_height > Sidebar::COMMIT_BOX_MAX_HEIGHT) text_height = Sidebar::COMMIT_BOX_MAX_HEIGHT;
    return text_height;
}



