// Branch tree building functions
static void flatten_subtree(BranchTreeNode* node) {
    if (!node) return;

    // Add this node to flattened list
    int node_index = (int)(node - g_branch_tree.nodes);
    if (g_branch_tree.flattened_count < 256) {
        g_branch_tree.flattened_indices[g_branch_tree.flattened_count++] = node_index;
    }

    // Add children if folder is expanded
    if (node->is_folder && node->is_expanded) {
        for (size_t i = 0; i < node->child_count; i++) {
            flatten_subtree(node->children[i]);
        }
    }
}

static void flatten_branch_tree() {
    g_branch_tree.flattened_count = 0;

    // Depth-first traversal, respecting collapse state
    for (size_t i = 0; i < g_branch_tree.root_count; i++) {
        flatten_subtree(g_branch_tree.root_nodes[i]);
    }
}

static BranchTreeNode* find_or_create_folder(BranchTreeNode* parent, const char* name, int depth) {
    // Search in parent's children (or root if parent is null)
    BranchTreeNode** search_list = parent ? parent->children : g_branch_tree.root_nodes;
    size_t search_count = parent ? parent->child_count : g_branch_tree.root_count;

    for (size_t i = 0; i < search_count; i++) {
        BranchTreeNode* node = search_list[i];
        if (node->is_folder && strcmp(node->name, name) == 0) {
            return node;  // Found existing folder
        }
    }

    // Create new folder node
    if (g_branch_tree.node_count >= 256) return nullptr;  // Out of space

    BranchTreeNode* node = &g_branch_tree.nodes[g_branch_tree.node_count++];
    strcpy_s(node->name, name);
    node->parent = parent;
    node->child_count = 0;
    node->git_ref_index = -1;
    node->is_folder = true;
    node->is_expanded = false;  // Default to collapsed
    node->depth = depth;

    // Add to parent's children or root
    if (parent) {
        if (parent->child_count < 32) {
            parent->children[parent->child_count++] = node;
        }
    } else {
        if (g_branch_tree.root_count < 32) {
            g_branch_tree.root_nodes[g_branch_tree.root_count++] = node;
        }
    }

    return node;
}

static void add_branch_leaf(BranchTreeNode* parent, const char* name, int git_ref_index, int depth) {
    if (g_branch_tree.node_count >= 256) return;  // Out of space

    BranchTreeNode* node = &g_branch_tree.nodes[g_branch_tree.node_count++];
    strcpy_s(node->name, name);
    node->parent = parent;
    node->child_count = 0;
    node->git_ref_index = git_ref_index;
    node->is_folder = false;
    node->is_expanded = false;
    node->depth = depth;

    // Add to parent's children or root
    if (parent) {
        if (parent->child_count < 32) {
            parent->children[parent->child_count++] = node;
        }
    } else {
        if (g_branch_tree.root_count < 32) {
            g_branch_tree.root_nodes[g_branch_tree.root_count++] = node;
        }
    }
}

static void build_branch_tree() {
    // Reset tree state
    g_branch_tree.node_count = 0;
    g_branch_tree.root_count = 0;
    g_branch_tree.flattened_count = 0;

    if (g_sidebar.branch_count == 0) return;

    // Pass 1: Count branches per prefix to determine grouping
    struct PrefixCount {
        char prefix[64];
        int count;
    };
    PrefixCount prefix_counts[128] = {};
    size_t prefix_count = 0;

    for (size_t i = 0; i < g_sidebar.branch_count; i++) {
        const char* name = g_sidebar.branches[i].name;
        const char* slash = strchr(name, '/');

        if (!slash) continue;  // No grouping for top-level branches

        // Extract first segment
        size_t prefix_len = slash - name;
        if (prefix_len >= 64) prefix_len = 63;
        char prefix[64];
        strncpy_s(prefix, 64, name, prefix_len);
        prefix[prefix_len] = '\0';

        // Find or add prefix
        bool found = false;
        for (size_t p = 0; p < prefix_count; p++) {
            if (strcmp(prefix_counts[p].prefix, prefix) == 0) {
                prefix_counts[p].count++;
                found = true;
                break;
            }
        }
        if (!found && prefix_count < 128) {
            strcpy_s(prefix_counts[prefix_count].prefix, prefix);
            prefix_counts[prefix_count].count = 1;
            prefix_count++;
        }
    }

    // Pass 2: Build tree
    for (size_t i = 0; i < g_sidebar.branch_count; i++) {
        const char* name = g_sidebar.branches[i].name;
        const char* slash = strchr(name, '/');

        // Check if this branch should be grouped
        bool should_group = false;
        char first_segment[64] = "";

        if (slash) {
            size_t prefix_len = slash - name;
            if (prefix_len >= 64) prefix_len = 63;
            strncpy_s(first_segment, 64, name, prefix_len);
            first_segment[prefix_len] = '\0';

            // Look up prefix count
            for (size_t p = 0; p < prefix_count; p++) {
                if (strcmp(prefix_counts[p].prefix, first_segment) == 0 && prefix_counts[p].count > 1) {
                    should_group = true;
                    break;
                }
            }
        }

        if (should_group) {
            // Parse path and create folder hierarchy
            char path_copy[256];
            strcpy_s(path_copy, name);

            BranchTreeNode* current_parent = nullptr;
            int depth = 0;
            char* context = nullptr;
            char* token = strtok_s(path_copy, "/", &context);

            while (token) {
                char* next_token = strtok_s(nullptr, "/", &context);

                if (next_token) {
                    // This is a folder segment
                    current_parent = find_or_create_folder(current_parent, token, depth);
                    depth++;
                } else {
                    // This is the final branch name
                    add_branch_leaf(current_parent, token, (int)i, depth);
                }

                token = next_token;
            }
        } else {
            // Add directly to root (no grouping)
            add_branch_leaf(nullptr, name, (int)i, 0);
        }
    }

    // Pass 3: Flatten tree into render order
    flatten_branch_tree();

    // Pass 4: Auto-expand and scroll to current branch
    if (g_sidebar.current_branch_index >= 0) {
        // Find node containing current branch
        for (size_t i = 0; i < g_branch_tree.node_count; i++) {
            BranchTreeNode* node = &g_branch_tree.nodes[i];
            if (!node->is_folder && node->git_ref_index == g_sidebar.current_branch_index) {
                // Traverse up and expand all parent folders
                BranchTreeNode* parent = node->parent;
                while (parent) {
                    parent->is_expanded = true;
                    parent = parent->parent;
                }
                break;
            }
        }

        // Rebuild flattened list after expansion
        flatten_branch_tree();
    }
}

static void scroll_to_current_branch() {
    if (g_sidebar.current_branch_index < 0) return;

    // Find flattened index of current branch
    int flat_index = -1;
    for (size_t i = 0; i < g_branch_tree.flattened_count; i++) {
        int node_index = g_branch_tree.flattened_indices[i];
        BranchTreeNode* node = &g_branch_tree.nodes[node_index];
        if (!node->is_folder && node->git_ref_index == g_sidebar.current_branch_index) {
            flat_index = (int)i;
            break;
        }
    }

    if (flat_index < 0) return;

    // Estimate viewport height (widget may not be initialized when repo loads)
    // Use a reasonable default based on typical window size
    float viewport_height = 200.0f;

    // Center this item in the viewport
    float item_top = Sidebar::SECTION_HEADER_HEIGHT + flat_index * Sidebar::BRANCH_ITEM_HEIGHT;
    float center_offset = item_top - viewport_height / 2.0f + Sidebar::BRANCH_ITEM_HEIGHT / 2.0f;

    // Clamp scroll offset
    float content_height = Sidebar::SECTION_HEADER_HEIGHT +
                           g_branch_tree.flattened_count * Sidebar::BRANCH_ITEM_HEIGHT;
    float max_scroll = content_height - viewport_height;
    if (max_scroll < 0) max_scroll = 0;
    if (center_offset < 0) center_offset = 0;
    if (center_offset > max_scroll) center_offset = max_scroll;

    g_sidebar.branches_scroll_offset = center_offset;
}

// Serialize branch expand state to JSON for persistence
static void serialize_branch_expand_state(char* out, size_t out_size) {
    if (!out || out_size < 3) return;

    size_t pos = 0;
    out[pos++] = '{';

    bool first = true;
    for (size_t i = 0; i < g_branch_tree.node_count; i++) {
        BranchTreeNode* node = &g_branch_tree.nodes[i];
        if (!node->is_folder) continue;

        if (!first && pos + 2 < out_size) {
            out[pos++] = ',';
        }
        first = false;

        // Add "name":true/false
        if (pos + strlen(node->name) + 10 < out_size) {  // Reserve space for "":false,
            out[pos++] = '\"';
            for (const char* p = node->name; *p && pos + 1 < out_size; p++) {
                out[pos++] = *p;
            }
            out[pos++] = '\"';
            out[pos++] = ':';
            if (node->is_expanded) {
                if (pos + 4 < out_size) {
                    memcpy(&out[pos], "true", 4);
                    pos += 4;
                }
            } else {
                if (pos + 5 < out_size) {
                    memcpy(&out[pos], "false", 5);
                    pos += 5;
                }
            }
        }
    }

    if (pos + 2 <= out_size) {
        out[pos++] = '}';
        out[pos] = '\0';
    }
}

