// Shell icon system
static bool icon_cache_init() {
    memset(&g_icon_cache, 0, sizeof(g_icon_cache));
    return true;  // No system imagelist needed for SHGetFileInfo approach
}

static void icon_cache_cleanup() {
    for (size_t i = 0; i < g_icon_cache.entry_count; i++) {
        if (g_icon_cache.entries[i].bitmap) {
            g_icon_cache.entries[i].bitmap->Release();
            g_icon_cache.entries[i].bitmap = nullptr;
        }
    }
    g_icon_cache.entry_count = 0;
}

// Convert HICON to ID2D1Bitmap
static ID2D1Bitmap* hicon_to_bitmap(HICON icon) {
    if (!icon || !g_wic_factory || !g_render_target) return nullptr;

    // Create WIC bitmap from HICON
    IWICBitmap* wic_bitmap = nullptr;
    HRESULT hr = g_wic_factory->CreateBitmapFromHICON(icon, &wic_bitmap);
    if (FAILED(hr) || !wic_bitmap) return nullptr;

    // Create format converter
    IWICFormatConverter* converter = nullptr;
    hr = g_wic_factory->CreateFormatConverter(&converter);
    if (FAILED(hr) || !converter) {
        wic_bitmap->Release();
        return nullptr;
    }

    // Convert to 32bpp BGRA format
    hr = converter->Initialize(
        wic_bitmap,
        GUID_WICPixelFormat32bppPBGRA,
        WICBitmapDitherTypeNone,
        nullptr,
        0.0,
        WICBitmapPaletteTypeMedianCut
    );
    wic_bitmap->Release();

    if (FAILED(hr)) {
        converter->Release();
        return nullptr;
    }

    // Create Direct2D bitmap from WIC bitmap
    ID2D1Bitmap* d2d_bitmap = nullptr;
    hr = g_render_target->CreateBitmapFromWicBitmap(converter, nullptr, &d2d_bitmap);
    converter->Release();

    return d2d_bitmap;  // May be nullptr if creation failed
}

ID2D1Bitmap* get_file_icon(const wchar_t* filename) {
    // Extract extension
    const wchar_t* dot = wcsrchr(filename, L'.');
    wchar_t extension[16] = L"";
    if (dot && wcslen(dot) < 16) {
        wcscpy_s(extension, dot);
    }

    // Check cache
    for (size_t i = 0; i < g_icon_cache.entry_count; i++) {
        if (wcscmp(g_icon_cache.entries[i].extension, extension) == 0) {
            return g_icon_cache.entries[i].bitmap;
        }
    }

    // Not in cache - load from shell
    SHFILEINFOW sfi = {};
    DWORD_PTR result = SHGetFileInfoW(
        filename,
        FILE_ATTRIBUTE_NORMAL,
        &sfi,
        sizeof(sfi),
        SHGFI_ICON | SHGFI_SMALLICON | SHGFI_USEFILEATTRIBUTES
    );

    if (!result || !sfi.hIcon) {
        return nullptr;  // No icon available
    }

    // Convert HICON to Direct2D bitmap
    ID2D1Bitmap* bitmap = hicon_to_bitmap(sfi.hIcon);
    DestroyIcon(sfi.hIcon);  // We don't need the HICON anymore

    if (!bitmap) return nullptr;

    // Add to cache (evict oldest if full)
    if (g_icon_cache.entry_count >= 64) {
        // Simple eviction: replace entry 0
        if (g_icon_cache.entries[0].bitmap) {
            g_icon_cache.entries[0].bitmap->Release();
        }
        wcscpy_s(g_icon_cache.entries[0].extension, extension);
        g_icon_cache.entries[0].bitmap = bitmap;
        g_icon_cache.entries[0].is_valid = true;
    } else {
        IconCacheEntry* entry = &g_icon_cache.entries[g_icon_cache.entry_count++];
        wcscpy_s(entry->extension, extension);
        entry->bitmap = bitmap;
        entry->is_valid = true;
    }

    return bitmap;
}

void draw_file_icon(ID2D1Bitmap* bitmap, float x, float y, float size) {
    if (!bitmap || !g_render_target) return;

    // Draw bitmap with Direct2D
    D2D1_RECT_F dest_rect = D2D1::RectF(x, y, x + size, y + size);
    g_render_target->DrawBitmap(
        bitmap,
        dest_rect,
        1.0f,  // opacity
        D2D1_BITMAP_INTERPOLATION_MODE_LINEAR,
        nullptr  // source rect (use entire bitmap)
    );
}




// Tooltip system
static void build_branch_full_path(BranchTreeNode* node, char* out, size_t out_size) {
    if (!node || !out) return;

    if (node->parent) {
        build_branch_full_path(node->parent, out, out_size);
        size_t current_len = strlen(out);
        if (current_len > 0 && current_len < out_size - 1) {
            strcat_s(out, out_size, "/");
        }
    }

    size_t current_len = strlen(out);
    if (current_len < out_size - strlen(node->name) - 1) {
        strcat_s(out, out_size, node->name);
    }
}

static void tooltip_update_hover(int file_index, bool is_staged, int branch_node_index) {
    uint64_t now = GetTickCount64();

    // Check if hovering over same item
    bool same_file = (file_index == g_tooltip.hover_file_index &&
                      is_staged == g_tooltip.hover_is_staged);
    bool same_branch = (branch_node_index == g_tooltip.hover_branch_node_index);

    if (file_index >= 0 && !same_file) {
        // Started hovering over new file
        g_tooltip.hover_file_index = file_index;
        g_tooltip.hover_is_staged = is_staged;
        g_tooltip.hover_branch_node_index = -1;
        g_tooltip.hover_start_time = now;
        g_tooltip.visible = false;
    }
    else if (branch_node_index >= 0 && !same_branch) {
        // Started hovering over new branch
        g_tooltip.hover_branch_node_index = branch_node_index;
        g_tooltip.hover_file_index = -1;
        g_tooltip.hover_start_time = now;
        g_tooltip.visible = false;
    }
    else if (file_index < 0 && branch_node_index < 0) {
        // Not hovering over anything
        g_tooltip.hover_file_index = -1;
        g_tooltip.hover_branch_node_index = -1;
        g_tooltip.visible = false;
    }

    // Show tooltip after delay
    if (!g_tooltip.visible && (g_tooltip.hover_file_index >= 0 ||
                               g_tooltip.hover_branch_node_index >= 0)) {
        if (now - g_tooltip.hover_start_time > TOOLTIP_DELAY_MS) {
            // Build tooltip text
            if (g_tooltip.hover_file_index >= 0) {
                // File tooltip: "full/path/to/file.cpp\nModified • +23 -5"
                const SidebarFile* file = g_tooltip.hover_is_staged ?
                    &g_sidebar.staged_files[g_tooltip.hover_file_index] :
                    &g_sidebar.changed_files[g_tooltip.hover_file_index];

                const wchar_t* status_text = L"Unknown";
                switch (file->status) {
                    case FileStatus::Modified: status_text = L"Modified"; break;
                    case FileStatus::Added: status_text = L"Added"; break;
                    case FileStatus::Deleted: status_text = L"Deleted"; break;
                    case FileStatus::Renamed: status_text = L"Renamed"; break;
                    case FileStatus::Untracked: status_text = L"Untracked"; break;
                }

                swprintf_s(g_tooltip.text, L"%s\n%s • +%d -%d",
                           file->filename,
                           status_text,
                           file->lines_added, file->lines_removed);
            }
            else if (g_tooltip.hover_branch_node_index >= 0) {
                // Branch tooltip: full branch name
                BranchTreeNode* node = &g_branch_tree.nodes[g_tooltip.hover_branch_node_index];

                // Build full path by traversing parents
                char full_path[256] = "";
                build_branch_full_path(node, full_path, 256);

                MultiByteToWideChar(CP_UTF8, 0, full_path, -1, g_tooltip.text, 512);
            }

            // Measure tooltip size
            if (g_dwrite_factory && g_text_format_hint) {
                IDWriteTextLayout* layout = nullptr;
                HRESULT hr = g_dwrite_factory->CreateTextLayout(
                    g_tooltip.text, (UINT32)wcslen(g_tooltip.text),
                    g_text_format_hint, 300.0f, 100.0f, &layout
                );
                if (SUCCEEDED(hr) && layout) {
                    DWRITE_TEXT_METRICS metrics;
                    layout->GetMetrics(&metrics);
                    g_tooltip.width = metrics.width + 12.0f;
                    g_tooltip.height = metrics.height + 8.0f;
                    layout->Release();
                }
            }

            g_tooltip.visible = true;
        }
    }
}

static void render_tooltip(ID2D1SolidColorBrush* brush) {
    if (!g_tooltip.visible || !g_render_target) return;

    // Position near mouse cursor
    POINT cursor;
    GetCursorPos(&cursor);
    ScreenToClient(g_main_window, &cursor);

    float x = (float)cursor.x + 12.0f;
    float y = (float)cursor.y + 12.0f;

    // Clamp to viewport
    D2D1_SIZE_F size = g_render_target->GetSize();
    if (x + g_tooltip.width > size.width) x = size.width - g_tooltip.width;
    if (y + g_tooltip.height > size.height) y = size.height - g_tooltip.height;
    if (x < 0) x = 0;
    if (y < 0) y = 0;

    g_tooltip.x = x;
    g_tooltip.y = y;

    // Background
    D2D1_ROUNDED_RECT bg_rect = D2D1::RoundedRect(
        D2D1::RectF(x, y, x + g_tooltip.width, y + g_tooltip.height),
        4.0f, 4.0f
    );
    brush->SetColor(color_from_argb(0xF0252526));  // Nearly opaque
    g_render_target->FillRoundedRectangle(bg_rect, brush);

    // Border
    brush->SetColor(color_from_argb(Theme::BORDER));
    g_render_target->DrawRoundedRectangle(bg_rect, brush, 1.0f);

    // Text
    D2D1_RECT_F text_rect = D2D1::RectF(x + 6.0f, y + 4.0f,
                                        x + g_tooltip.width - 6.0f,
                                        y + g_tooltip.height - 4.0f);
    brush->SetColor(color_from_argb(Theme::TEXT_PRIMARY));
    g_render_target->DrawText(g_tooltip.text, (UINT32)wcslen(g_tooltip.text),
                              g_text_format_hint, text_rect, brush);
}

// Main sidebar render function - now uses unified SidebarWidget
