// Helper to format relative time (e.g., "2 hours ago", "Yesterday")
static void format_relative_time(int64_t timestamp, wchar_t* buffer, size_t buffer_size) {
    int64_t now = (int64_t)time(nullptr);
    int64_t diff = now - timestamp;

    if (diff < 60) {
        wcscpy_s(buffer, buffer_size, L"Just now");
    } else if (diff < 3600) {
        int mins = (int)(diff / 60);
        swprintf_s(buffer, buffer_size, L"%d minute%s ago", mins, mins == 1 ? L"" : L"s");
    } else if (diff < 86400) {
        int hours = (int)(diff / 3600);
        swprintf_s(buffer, buffer_size, L"%d hour%s ago", hours, hours == 1 ? L"" : L"s");
    } else if (diff < 172800) {
        wcscpy_s(buffer, buffer_size, L"Yesterday");
    } else if (diff < 604800) {
        int days = (int)(diff / 86400);
        swprintf_s(buffer, buffer_size, L"%d days ago", days);
    } else if (diff < 2592000) {
        int weeks = (int)(diff / 604800);
        swprintf_s(buffer, buffer_size, L"%d week%s ago", weeks, weeks == 1 ? L"" : L"s");
    } else {
        int months = (int)(diff / 2592000);
        swprintf_s(buffer, buffer_size, L"%d month%s ago", months, months == 1 ? L"" : L"s");
    }
}

// Try to open a repository at the given path
static bool try_open_repository(const wchar_t* path) {
    // Stop existing file watcher before switching repos
    file_watcher_stop();

    // Convert to narrow string for git functions
    char narrow_path[Git::MAX_PATH_LEN];
    WideCharToMultiByte(CP_UTF8, 0, path, -1, narrow_path, sizeof(narrow_path), nullptr, nullptr);

    // Check if it's a valid git repository
    if (!git_is_repository(path)) {
        const wchar_t* err_msg = L"Selected folder is not a Git repository";
        wcscpy_s(g_welcome.error_message, err_msg);
        g_welcome.error_timer = ERROR_DISPLAY_DURATION;
        if (g_welcome_screen) g_welcome_screen->set_error(err_msg);
        SetTimer(g_main_window, ERROR_FADE_TIMER_ID, ERROR_FADE_INTERVAL_MS, nullptr);
        return false;
    }

    // Close any existing repository and open new one (with lock)
    {
        RepoLockGuard lock;
        git_repo_close(&g_repo);

        // Open the repository
        if (!git_repo_open(&g_repo, path)) {
            const wchar_t* err_msg = L"Failed to open repository";
            wcscpy_s(g_welcome.error_message, err_msg);
            g_welcome.error_timer = ERROR_DISPLAY_DURATION;
            if (g_welcome_screen) g_welcome_screen->set_error(err_msg);
            SetTimer(g_main_window, ERROR_FADE_TIMER_ID, ERROR_FADE_INTERVAL_MS, nullptr);
            return false;
        }

        // Add to recent repos
        settings_add_recent_repo(g_welcome.recent_repos, &g_welcome.recent_count,
                                Welcome::MAX_RECENT_REPOS, path);
        settings_save_recent_repos(g_welcome.recent_repos, g_welcome.recent_count);

        // Load sidebar data from repository (real git status)
        sidebar_load_status();

        // Load commit history
        commit_history_load();

        // Load branches from repository
        g_sidebar.branch_count = git_list_refs(&g_repo, g_sidebar.branches, 128);
        g_sidebar.current_branch_index = -1;

        // Find current branch
        for (size_t i = 0; i < g_sidebar.branch_count; i++) {
            if (strcmp(g_sidebar.branches[i].name, g_repo.head_ref) == 0) {
                g_sidebar.current_branch_index = static_cast<int>(i);
                break;
            }
        }

        // Build branch tree with grouping
        build_branch_tree();
        scroll_to_current_branch();

        // Load stashes
        sidebar_load_stashes();

        // Set current branch name for display
        MultiByteToWideChar(CP_UTF8, 0, g_repo.head_ref, -1,
                           g_sidebar.current_branch_name, 256);

        // Populate status bar
        MultiByteToWideChar(CP_UTF8, 0, g_repo.head_ref, -1,
                           g_status_bar.branch_name, 256);
        status_bar_update_fetch_time();

        // Calculate initial ahead/behind status
        git_sync_status(&g_repo, "origin", &g_status_bar.sync_status);
    }

    // Start background sync timer
    SetTimer(g_main_window, BACKGROUND_SYNC_TIMER_ID, BACKGROUND_SYNC_INTERVAL_MS, nullptr);

    // Start file system watcher
    wchar_t wide_path[Git::MAX_PATH_LEN];
    MultiByteToWideChar(CP_UTF8, 0, g_repo.path, -1, wide_path, Git::MAX_PATH_LEN);
    file_watcher_start(wide_path);

    // Switch to repository screen
    g_current_screen = AppScreen::Repository;
    g_welcome.error_message[0] = L'\0';
    if (g_welcome_screen) g_welcome_screen->clear_error();

    return true;
}

// Open folder picker dialog
static void open_repository_dialog() {
    IFileDialog* pfd = nullptr;
    HRESULT hr = CoCreateInstance(CLSID_FileOpenDialog, nullptr, CLSCTX_INPROC_SERVER,
                                  IID_PPV_ARGS(&pfd));
    if (FAILED(hr)) return;

    // Set options for folder picker
    DWORD dwOptions;
    pfd->GetOptions(&dwOptions);
    pfd->SetOptions(dwOptions | FOS_PICKFOLDERS | FOS_FORCEFILESYSTEM);

    // Set title
    pfd->SetTitle(L"Select Git Repository");

    // Show dialog
    hr = pfd->Show(g_main_window);
    if (SUCCEEDED(hr)) {
        IShellItem* psi = nullptr;
        hr = pfd->GetResult(&psi);
        if (SUCCEEDED(hr)) {
            PWSTR pszPath = nullptr;
            hr = psi->GetDisplayName(SIGDN_FILESYSPATH, &pszPath);
            if (SUCCEEDED(hr)) {
                try_open_repository(pszPath);
                CoTaskMemFree(pszPath);
            }
            psi->Release();
        }
    }

    pfd->Release();
}

