// Helper: Get SidebarFile from context menu state
static SidebarFile* file_ctx_get_file() {
    if (g_file_context.file_index < 0) return nullptr;
    if (g_file_context.is_staged) {
        if (static_cast<size_t>(g_file_context.file_index) >= g_sidebar.staged_count) return nullptr;
        return &g_sidebar.staged_files[g_file_context.file_index];
    } else {
        if (static_cast<size_t>(g_file_context.file_index) >= g_sidebar.changed_count) return nullptr;
        return &g_sidebar.changed_files[g_file_context.file_index];
    }
}

// Stage file callback
static void file_ctx_stage(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    SidebarFile* file = file_ctx_get_file();
    if (!file || g_file_context.is_staged) return;

    char path_utf8[512];
    WideCharToMultiByte(CP_UTF8, 0, file->full_path, -1, path_utf8, sizeof(path_utf8), nullptr, nullptr);

    RepoLockGuard lock;
    if (git_stage_file(&g_repo, path_utf8)) {
        sidebar_load_status();
        sidebar_file_list_widgets_update();
    }
    InvalidateRect(g_main_window, nullptr, FALSE);
}

