// Discard changes callback (with confirmation)
static void file_ctx_discard(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    SidebarFile* file = file_ctx_get_file();
    if (!file || g_file_context.is_staged) return;

    wchar_t confirm_msg[512];
    swprintf_s(confirm_msg, L"Discard changes to '%s'?\n\nThis cannot be undone.", file->filename);

    int result = MessageBoxW(g_main_window, confirm_msg, L"Discard Changes",
                            MB_YESNO | MB_ICONWARNING | MB_DEFBUTTON2);

    if (result == IDYES) {
        char path_utf8[512];
        WideCharToMultiByte(CP_UTF8, 0, file->full_path, -1, path_utf8, sizeof(path_utf8), nullptr, nullptr);

        RepoLockGuard lock;
        if (git_discard_file(&g_repo, path_utf8)) {
            sidebar_load_status();
            sidebar_file_list_widgets_update();
        }
    }
    InvalidateRect(g_main_window, nullptr, FALSE);
}

// Discard all changes callback (with confirmation)
static void file_ctx_discard_all(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_sidebar.changed_count == 0) return;

    wchar_t confirm_msg[256];
    swprintf_s(confirm_msg, L"Discard ALL changes to %zu file(s)?\n\nThis cannot be undone.",
               g_sidebar.changed_count);

    int result = MessageBoxW(g_main_window, confirm_msg, L"Discard All Changes",
                            MB_YESNO | MB_ICONWARNING | MB_DEFBUTTON2);

    if (result == IDYES) {
        RepoLockGuard lock;
        bool any_discarded = false;
        for (size_t i = 0; i < g_sidebar.changed_count; i++) {
            char path_utf8[512];
            WideCharToMultiByte(CP_UTF8, 0, g_sidebar.changed_files[i].full_path, -1,
                               path_utf8, sizeof(path_utf8), nullptr, nullptr);
            if (git_discard_file(&g_repo, path_utf8)) {
                any_discarded = true;
            }
        }
        if (any_discarded) {
            sidebar_load_status();
            sidebar_file_list_widgets_update();
        }
    }
    InvalidateRect(g_main_window, nullptr, FALSE);
}

// Open file callback
static void file_ctx_open(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    SidebarFile* file = file_ctx_get_file();
    if (!file) return;

    // Build absolute path: g_repo.path + file->full_path
    wchar_t abs_path[Git::MAX_PATH_LEN];
    wchar_t repo_path_wide[Git::MAX_PATH_LEN];
    MultiByteToWideChar(CP_UTF8, 0, g_repo.path, -1, repo_path_wide, Git::MAX_PATH_LEN);
    swprintf_s(abs_path, L"%s\\%s", repo_path_wide, file->full_path);

    // Normalize path separators
    for (wchar_t* p = abs_path; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }

    ShellExecuteW(nullptr, L"open", abs_path, nullptr, nullptr, SW_SHOWNORMAL);
}

// Open in Explorer callback
static void file_ctx_explorer(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    SidebarFile* file = file_ctx_get_file();
    if (!file) return;

    // Build absolute path
    wchar_t abs_path[Git::MAX_PATH_LEN];
    wchar_t repo_path_wide[Git::MAX_PATH_LEN];
    MultiByteToWideChar(CP_UTF8, 0, g_repo.path, -1, repo_path_wide, Git::MAX_PATH_LEN);
    swprintf_s(abs_path, L"%s\\%s", repo_path_wide, file->full_path);

    // Normalize path separators
    for (wchar_t* p = abs_path; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }

    // Use /select to highlight the file in Explorer
    wchar_t explorer_cmd[Git::MAX_PATH_LEN + 32];
    swprintf_s(explorer_cmd, L"/select,\"%s\"", abs_path);
    ShellExecuteW(nullptr, nullptr, L"explorer.exe", explorer_cmd, nullptr, SW_SHOWNORMAL);
}

// Copy relative path callback
static void file_ctx_copy_path(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    SidebarFile* file = file_ctx_get_file();
    if (!file) return;

    char path_utf8[512];
    WideCharToMultiByte(CP_UTF8, 0, file->full_path, -1, path_utf8, sizeof(path_utf8), nullptr, nullptr);
    copy_to_clipboard(path_utf8);
}

// Copy absolute path callback
static void file_ctx_copy_abs_path(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    SidebarFile* file = file_ctx_get_file();
    if (!file) return;

    // Build absolute path
    char rel_path_utf8[512];
    WideCharToMultiByte(CP_UTF8, 0, file->full_path, -1, rel_path_utf8, sizeof(rel_path_utf8), nullptr, nullptr);

    char abs_path[Git::MAX_PATH_LEN];
    snprintf(abs_path, sizeof(abs_path), "%s\\%s", g_repo.path, rel_path_utf8);

    // Normalize to backslashes for Windows
    for (char* p = abs_path; *p; p++) {
        if (*p == '/') *p = '\\';
    }

    copy_to_clipboard(abs_path);
}

