static void branch_ctx_delete(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;

    // Safety check - should not be able to delete current branch
    if (g_branch_context.is_current) {
        MessageBoxW(g_main_window, L"Cannot delete the current branch.",
                    L"Delete Branch", MB_OK | MB_ICONWARNING);
        return;
    }

    // Confirm deletion
    wchar_t msg[256];
    wchar_t branch_name_w[128];
    MultiByteToWideChar(CP_UTF8, 0, g_branch_context.branch_name, -1, branch_name_w, 128);
    swprintf_s(msg, L"Delete branch '%s'?\n\nThis cannot be undone.", branch_name_w);

    if (MessageBoxW(g_main_window, msg, L"Delete Branch", MB_YESNO | MB_ICONQUESTION) != IDYES) {
        return;
    }

    // Try to delete (non-force first)
    char error[512] = {};
    if (git_branch_delete(&g_repo, g_branch_context.branch_name, false, error, sizeof(error))) {
        // Success - refresh branch list
        sidebar_load_branches();
        InvalidateRect(g_main_window, nullptr, FALSE);
        return;
    }

    // Check if error is about unmerged branch
    if (strstr(error, "not fully merged") || strstr(error, "not merged")) {
        // Offer force delete with extra warning
        swprintf_s(msg, L"Branch '%s' is not fully merged.\n\n"
                        L"WARNING: Deleting this branch will lose commits that are not in any other branch.\n\n"
                        L"Are you sure you want to force delete?", branch_name_w);

        if (MessageBoxW(g_main_window, msg, L"Force Delete Branch",
                        MB_YESNO | MB_ICONWARNING | MB_DEFBUTTON2) == IDYES) {
            // Force delete
            error[0] = '\0';
            if (git_branch_delete(&g_repo, g_branch_context.branch_name, true, error, sizeof(error))) {
                sidebar_load_branches();
                InvalidateRect(g_main_window, nullptr, FALSE);
                return;
            }
        } else {
            return;  // User cancelled force delete
        }
    }

    // Show error if we get here
    if (error[0]) {
        wchar_t error_msg[512];
        MultiByteToWideChar(CP_UTF8, 0, error, -1, error_msg, 512);
        MessageBoxW(g_main_window, error_msg, L"Delete Branch Failed", MB_OK | MB_ICONERROR);
    }
}

static void branch_ctx_create_from(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_branch_context.git_ref_index < 0 ||
        g_branch_context.git_ref_index >= static_cast<int>(g_sidebar.branch_count)) return;

    // Get SHA from the sidebar branch refs
    const GitRef& ref = g_sidebar.branches[g_branch_context.git_ref_index];

    // Build display string showing branch name and short SHA
    char source_display[128];
    snprintf(source_display, sizeof(source_display), "%s (%.7s)",
             g_branch_context.branch_name, ref.sha);

    branch_dialog_widget_show(ref.sha, source_display);
}

static void branch_ctx_copy_name(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_branch_context.branch_name[0]) {
        copy_to_clipboard(g_branch_context.branch_name);
    }
}

// Show branch context menu
static void branch_ctx_show_menu(int git_ref_index, bool is_remote, const char* branch_name, float client_x, float client_y) {
    g_branch_context.git_ref_index = git_ref_index;
    g_branch_context.is_remote = is_remote;
    strncpy_s(g_branch_context.branch_name, sizeof(g_branch_context.branch_name), branch_name, _TRUNCATE);

    // Check if this is the current branch
    g_branch_context.is_current = false;
    if (!is_remote && !g_repo.head_detached) {
        // Need to compare with the full ref name since g_repo.head_ref is full path
        char full_ref_name[256];
        snprintf(full_ref_name, sizeof(full_ref_name), "refs/heads/%s", branch_name);
        g_branch_context.is_current = (strcmp(full_ref_name, g_repo.head_ref) == 0);
    }

    // Disable checkout/delete if this is current branch
    if (g_branch_context.is_current) {
        g_local_branch_menu[0].enabled = false;  // Checkout
        g_local_branch_menu[3].enabled = false;  // Delete
    } else {
        g_local_branch_menu[0].enabled = true;
        g_local_branch_menu[3].enabled = true;   // Delete enabled when not current branch
    }

    if (is_remote) {
        context_menu_show(client_x, client_y, g_remote_branch_menu,
                          sizeof(g_remote_branch_menu) / sizeof(g_remote_branch_menu[0]));
    } else {
        context_menu_show(client_x, client_y, g_local_branch_menu,
                          sizeof(g_local_branch_menu) / sizeof(g_local_branch_menu[0]));
    }
}

// Callback for branch tree context menu
static void on_branch_context_menu(BranchTree* tree, int git_ref_index, int node_index,
                                    float screen_x, float screen_y, void* user_data) {
    (void)tree; (void)node_index; (void)user_data;
    if (git_ref_index < 0 || git_ref_index >= static_cast<int>(g_sidebar.branch_count)) return;

    POINT pt = { static_cast<LONG>(screen_x), static_cast<LONG>(screen_y) };
    ScreenToClient(g_main_window, &pt);

    const GitRef* ref = &g_sidebar.branches[git_ref_index];
    bool is_remote = (ref->type == GitRef::Type::Remote);

    // Get branch name (strip refs/heads/ or refs/remotes/)
    const char* branch_name = ref->name;
    if (strncmp(branch_name, "refs/heads/", 11) == 0) {
        branch_name += 11;
    } else if (strncmp(branch_name, "refs/remotes/", 13) == 0) {
        branch_name += 13;
    }

    branch_ctx_show_menu(git_ref_index, is_remote, branch_name,
                         static_cast<float>(pt.x), static_cast<float>(pt.y));
}

