// Commit context menu callbacks
// Note: sha_to_hex() defined in ui_widgets_palette.cpp (available via unity build)
static void commit_ctx_checkout(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_commit_context.row_index < 0 || !g_commit_context.history) return;

    const GitHistory* h = g_commit_context.history;
    if (static_cast<size_t>(g_commit_context.row_index) >= h->commit_count) return;

    // Warn about detached HEAD
    int choice = MessageBoxW(g_main_window,
        L"Checking out a commit will put you in 'detached HEAD' state.\n\n"
        L"This means you are not on any branch. Any commits you make will be lost "
        L"if you switch to another branch without creating a new branch first.\n\n"
        L"Do you want to continue?",
        L"Checkout Commit", MB_YESNO | MB_ICONWARNING);

    if (choice != IDYES) return;

    // TODO: Implement native git_checkout_commit function
    MessageBoxW(g_main_window, L"Commit checkout not yet implemented natively. Use git CLI.",
                L"Not Implemented", MB_OK | MB_ICONINFORMATION);
}

static void commit_ctx_create_branch(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_commit_context.row_index < 0 || !g_commit_context.history) return;

    const GitHistory* h = g_commit_context.history;
    if (static_cast<size_t>(g_commit_context.row_index) >= h->commit_count) return;

    // Get SHA hex
    char sha_hex[41];
    sha_to_hex(h->commits[g_commit_context.row_index].sha, sha_hex, sizeof(sha_hex));

    // Build source display string (commit SHA + message excerpt)
    char source_display[128];
    const CommitMeta& commit = h->commits[g_commit_context.row_index];

    // Get message from buffer using offset and length
    char msg_excerpt[64] = {};
    if (h->message_buffer && commit.message_len > 0) {
        size_t copy_len = commit.message_len;
        if (copy_len > 50) copy_len = 50;
        strncpy_s(msg_excerpt, h->message_buffer + commit.message_offset, copy_len);
        if (commit.message_len > 50) strcat_s(msg_excerpt, "...");
    }
    snprintf(source_display, sizeof(source_display), "%.7s - %s", sha_hex, msg_excerpt);

    // Show branch dialog with this commit as source
    branch_dialog_widget_show(sha_hex, source_display);
}

