static void commit_ctx_reset_soft(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_commit_context.row_index < 0 || !g_commit_context.history) return;

    const GitHistory* h = g_commit_context.history;
    if (static_cast<size_t>(g_commit_context.row_index) >= h->commit_count) return;

    // Get short SHA for display
    char sha_hex[41];
    sha_to_hex(h->commits[g_commit_context.row_index].sha, sha_hex, sizeof(sha_hex));
    char short_sha[8];
    strncpy_s(short_sha, sha_hex, 7);

    // Confirm
    wchar_t msg[256];
    swprintf_s(msg, L"Reset (Soft) to commit %.7hs?\n\n"
                    L"This will move HEAD to this commit.\n"
                    L"Your staged and working changes will be preserved.", sha_hex);

    if (MessageBoxW(g_main_window, msg, L"Reset (Soft)", MB_YESNO | MB_ICONQUESTION) != IDYES) {
        return;
    }

    // Perform reset
    char error[512] = {};
    if (git_reset(&g_repo, sha_hex, ResetMode::Soft, error, sizeof(error))) {
        sidebar_load_status();
        sidebar_load_branches();
        InvalidateRect(g_main_window, nullptr, FALSE);
    } else {
        wchar_t error_msg[512];
        MultiByteToWideChar(CP_UTF8, 0, error, -1, error_msg, 512);
        MessageBoxW(g_main_window, error_msg, L"Reset Failed", MB_OK | MB_ICONERROR);
    }
}

static void commit_ctx_reset_mixed(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_commit_context.row_index < 0 || !g_commit_context.history) return;

    const GitHistory* h = g_commit_context.history;
    if (static_cast<size_t>(g_commit_context.row_index) >= h->commit_count) return;

    char sha_hex[41];
    sha_to_hex(h->commits[g_commit_context.row_index].sha, sha_hex, sizeof(sha_hex));

    // Confirm
    wchar_t msg[256];
    swprintf_s(msg, L"Reset (Mixed) to commit %.7hs?\n\n"
                    L"This will move HEAD and unstage your changes.\n"
                    L"Your working directory changes will be preserved.", sha_hex);

    if (MessageBoxW(g_main_window, msg, L"Reset (Mixed)", MB_YESNO | MB_ICONQUESTION) != IDYES) {
        return;
    }

    // Perform reset
    char error[512] = {};
    if (git_reset(&g_repo, sha_hex, ResetMode::Mixed, error, sizeof(error))) {
        sidebar_load_status();
        sidebar_load_branches();
        InvalidateRect(g_main_window, nullptr, FALSE);
    } else {
        wchar_t error_msg[512];
        MultiByteToWideChar(CP_UTF8, 0, error, -1, error_msg, 512);
        MessageBoxW(g_main_window, error_msg, L"Reset Failed", MB_OK | MB_ICONERROR);
    }
}

static void commit_ctx_reset_hard(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_commit_context.row_index < 0 || !g_commit_context.history) return;

    const GitHistory* h = g_commit_context.history;
    if (static_cast<size_t>(g_commit_context.row_index) >= h->commit_count) return;

    char sha_hex[41];
    sha_to_hex(h->commits[g_commit_context.row_index].sha, sha_hex, sizeof(sha_hex));

    // Confirm with extra warning
    wchar_t msg[512];
    swprintf_s(msg, L"Reset (Hard) to commit %.7hs?\n\n"
                    L"WARNING: This will PERMANENTLY DISCARD all uncommitted changes!\n\n"
                    L"Your working directory and staging area will be reset to match this commit.\n"
                    L"This action cannot be undone.\n\n"
                    L"Are you sure you want to continue?", sha_hex);

    if (MessageBoxW(g_main_window, msg, L"Reset (Hard) - Data Loss Warning",
                    MB_YESNO | MB_ICONWARNING | MB_DEFBUTTON2) != IDYES) {
        return;
    }

    // Perform reset
    char error[512] = {};
    if (git_reset(&g_repo, sha_hex, ResetMode::Hard, error, sizeof(error))) {
        sidebar_load_status();
        sidebar_load_branches();
        InvalidateRect(g_main_window, nullptr, FALSE);
    } else {
        wchar_t error_msg[512];
        MultiByteToWideChar(CP_UTF8, 0, error, -1, error_msg, 512);
        MessageBoxW(g_main_window, error_msg, L"Reset Failed", MB_OK | MB_ICONERROR);
    }
}

static void commit_ctx_copy_short_hash(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_commit_context.row_index < 0 || !g_commit_context.history) return;

    const GitHistory* h = g_commit_context.history;
    if (static_cast<size_t>(g_commit_context.row_index) >= h->commit_count) return;

    // Convert raw SHA to hex and copy first 7 characters
    char sha_hex[41];  // 40 hex chars + null
    sha_to_hex(h->commits[g_commit_context.row_index].sha, sha_hex, sizeof(sha_hex));
    sha_hex[7] = '\0';  // Truncate to short hash
    copy_to_clipboard(sha_hex);
}

static void commit_ctx_copy_full_hash(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_commit_context.row_index < 0 || !g_commit_context.history) return;

    const GitHistory* h = g_commit_context.history;
    if (static_cast<size_t>(g_commit_context.row_index) >= h->commit_count) return;

    // Convert raw SHA to hex
    char sha_hex[41];  // 40 hex chars + null
    sha_to_hex(h->commits[g_commit_context.row_index].sha, sha_hex, sizeof(sha_hex));
    copy_to_clipboard(sha_hex);
}

static void commit_ctx_copy_message(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_commit_context.row_index < 0 || !g_commit_context.history) return;

    const GitHistory* h = g_commit_context.history;
    if (static_cast<size_t>(g_commit_context.row_index) >= h->commit_count) return;

    // Get message from message buffer
    const CommitMeta& meta = h->commits[g_commit_context.row_index];
    if (h->message_buffer && meta.message_len > 0) {
        // Make a null-terminated copy of the message
        char msg_copy[256];
        size_t len = meta.message_len;
        if (len >= sizeof(msg_copy)) len = sizeof(msg_copy) - 1;
        memcpy(msg_copy, h->message_buffer + meta.message_offset, len);
        msg_copy[len] = '\0';
        copy_to_clipboard(msg_copy);
    }
}

