// Context state for diff context menu
static struct {
    int line_index;
    const FileDiff* diff;
} g_diff_context = { -1, nullptr };

// Forward declarations for diff context menu callbacks
static void diff_ctx_copy_line(MenuItem* item, void* user_data);

// Diff viewer menu items
static MenuItem g_diff_menu[] = {
    { MenuItemType::Regular, L"Copy line", L"Ctrl+C", nullptr, 0, false, true, diff_ctx_copy_line, nullptr },
};

// Helper to find a specific line in the diff by flat index
static const DiffLine* diff_get_line_by_flat_index(const FileDiff* diff, int flat_index) {
    if (!diff || flat_index < 0) return nullptr;

    int current_index = 0;
    for (size_t h = 0; h < diff->hunk_count; h++) {
        const DiffHunk& hunk = diff->hunks[h];
        if (flat_index < current_index + static_cast<int>(hunk.line_count)) {
            return &hunk.lines[flat_index - current_index];
        }
        current_index += static_cast<int>(hunk.line_count);
    }
    return nullptr;
}

// Diff context menu callbacks
static void diff_ctx_copy_line(MenuItem* item, void* user_data) {
    (void)item; (void)user_data;
    if (g_diff_context.line_index < 0 || !g_diff_context.diff) return;

    const DiffLine* line = diff_get_line_by_flat_index(g_diff_context.diff, g_diff_context.line_index);
    if (!line || !line->content) return;

    // Copy the line content (already without +/- prefix in this structure)
    copy_to_clipboard(line->content);
}

// Show diff context menu
static void diff_ctx_show_menu(int line_index, const FileDiff* diff, float client_x, float client_y) {
    g_diff_context.line_index = line_index;
    g_diff_context.diff = diff;

    // Disable if no valid line
    const DiffLine* line = diff_get_line_by_flat_index(diff, line_index);
    g_diff_menu[0].enabled = (line != nullptr && line->content != nullptr);

    context_menu_show(client_x, client_y, g_diff_menu,
                      sizeof(g_diff_menu) / sizeof(g_diff_menu[0]));
}

