// Populate recent repositories from settings
static void welcome_screen_populate_recent() {
    if (!g_welcome_screen || !g_welcome_screen->recent_list) return;

    g_welcome_screen->recent_list->clear_items();

    for (size_t i = 0; i < g_welcome.recent_count; i++) {
        RecentRepoItemWidget* item = g_widget_arena.create<RecentRepoItemWidget>();

        // Extract repo name from path
        wchar_t name[256];
        const wchar_t* last_slash = wcsrchr(g_welcome.recent_repos[i].path, L'\\');
        if (!last_slash) last_slash = wcsrchr(g_welcome.recent_repos[i].path, L'/');
        if (last_slash) {
            wcscpy_s(name, last_slash + 1);
        } else {
            wcscpy_s(name, g_welcome.recent_repos[i].path);
        }

        item->set_data(
            g_welcome.recent_repos[i].path,
            name,
            g_welcome.recent_repos[i].last_opened,
            static_cast<int>(i)
        );

        item->on_click = welcome_repo_item_clicked;
        item->on_context_menu = welcome_repo_item_context_menu;

        g_welcome_screen->recent_list->add_item(item);
    }
}

// Render the welcome screen
static void welcome_screen_render(ID2D1SolidColorBrush* brush) {
    if (!g_welcome_screen || !g_render_target || !brush) return;

    D2D1_SIZE_F size = g_render_target->GetSize();

    // Measure with constraints
    LayoutConstraints constraints;
    constraints.min_width = 0;
    constraints.min_height = 0;
    constraints.max_width = size.width;
    constraints.max_height = size.height;

    g_welcome_screen->measure(constraints);

    // Position at origin
    g_welcome_screen->rect.x = 0;
    g_welcome_screen->rect.y = 0;
    g_welcome_screen->rect.width = size.width;
    g_welcome_screen->rect.height = size.height;

    // Layout
    g_welcome_screen->layout();

    // Render using the passed brush (avoid per-frame brush creation)
    RenderContext ctx = { g_render_target, brush };
    g_welcome_screen->render(ctx);

    // Render context menu on top (if visible)
    context_menu_render(ctx);
}

