// TODO: This reads FETCH_HEAD mtime as a simple approximation.
// A more robust approach would track actual fetch operations and store timestamps.
static void status_bar_update_fetch_time() {
    wchar_t fetch_path[Git::MAX_PATH_LEN];
    swprintf_s(fetch_path, L"%hs/FETCH_HEAD", g_repo.git_dir);

    WIN32_FILE_ATTRIBUTE_DATA attr;
    if (GetFileAttributesExW(fetch_path, GetFileExInfoStandard, &attr)) {
        FILETIME ft = attr.ftLastWriteTime;
        ULARGE_INTEGER uli;
        uli.LowPart = ft.dwLowDateTime;
        uli.HighPart = ft.dwHighDateTime;

        // Convert FILETIME to Unix timestamp (seconds since 1970)
        int64_t fetch_time = static_cast<int64_t>((uli.QuadPart - 116444736000000000ULL) / 10000000ULL);
        int64_t now = static_cast<int64_t>(time(nullptr));
        int64_t diff = now - fetch_time;

        if (diff < 0) {
            wcscpy_s(g_status_bar.last_fetch, L"Fetched just now");
        } else if (diff < 60) {
            wcscpy_s(g_status_bar.last_fetch, L"Fetched just now");
        } else if (diff < 3600) {
            int64_t mins = diff / 60;
            if (mins == 1) {
                wcscpy_s(g_status_bar.last_fetch, L"Fetched 1 min ago");
            } else {
                swprintf_s(g_status_bar.last_fetch, L"Fetched %lld min ago", mins);
            }
        } else if (diff < 86400) {
            int64_t hours = diff / 3600;
            if (hours == 1) {
                wcscpy_s(g_status_bar.last_fetch, L"Fetched 1 hr ago");
            } else {
                swprintf_s(g_status_bar.last_fetch, L"Fetched %lld hr ago", hours);
            }
        } else {
            int64_t days = diff / 86400;
            if (days == 1) {
                wcscpy_s(g_status_bar.last_fetch, L"Fetched 1 day ago");
            } else {
                swprintf_s(g_status_bar.last_fetch, L"Fetched %lld days ago", days);
            }
        }
    } else {
        wcscpy_s(g_status_bar.last_fetch, L"Never fetched");
    }
}

