// Clear diff viewer state
static void diff_viewer_clear() {
    if (g_diff_viewer.has_diff) {
        diff_free(&g_diff_viewer.current_diff);
    }
    g_diff_viewer.has_diff = false;

    // Clear widget-based diff viewer (Phase 18)
    diff_viewer_widget_set_diff(nullptr);
}

// Compute diff for selected file
static void diff_viewer_compute_for_file(int file_index, bool is_staged) {
    diff_viewer_clear();

    if (file_index < 0) return;

    // Get the file path
    const SidebarFile* file = nullptr;
    if (is_staged) {
        if (static_cast<size_t>(file_index) >= g_sidebar.staged_count) return;
        file = &g_sidebar.staged_files[file_index];
    } else {
        if (static_cast<size_t>(file_index) >= g_sidebar.changed_count) return;
        file = &g_sidebar.changed_files[file_index];
    }

    // Convert wide filename to UTF-8 path
    char path_utf8[Git::MAX_PATH_LEN];
    WideCharToMultiByte(CP_UTF8, 0, file->full_path, -1, path_utf8, sizeof(path_utf8), nullptr, nullptr);

    // Compute the diff
    bool success = false;
    {
        RepoLockGuard lock;
        if (is_staged) {
            success = diff_compute_staged(&g_repo, path_utf8, &g_diff_viewer.current_diff);
        } else {
            success = diff_compute_unstaged(&g_repo, path_utf8, &g_diff_viewer.current_diff);
        }
    }

    g_diff_viewer.has_diff = success;

    // Also update the new widget-based diff viewer (Phase 18)
    if (success) {
        diff_viewer_widget_set_diff(&g_diff_viewer.current_diff);
    } else {
        diff_viewer_widget_set_diff(nullptr);
    }
}

