// Load commit history from repository
static void commit_history_load() {
    if (g_commit_history.history.commits != nullptr) {
        git_history_free(&g_commit_history.history);
    }
    memset(&g_commit_history.history, 0, sizeof(g_commit_history.history));

    if (!git_history_build(&g_repo, &g_commit_history.history)) {
        // Failed to build history - state will be empty
        commit_history_widget_set_history(nullptr);
        return;
    }

    // Reset scroll and selection
    g_commit_history.scroll_offset = 0.0f;
    g_commit_history.selected_index = -1;
    g_commit_history.hovered_index = -1;
    g_commit_history.details_visible = false;

    // Update widget with new history data
    commit_history_widget_set_history(&g_commit_history.history);
}

// Case-insensitive substring search helper
static bool strcasestr_local(const char* haystack, const char* needle, size_t needle_len) {
    if (!haystack || !needle || !needle_len) return false;
    for (const char* p = haystack; *p; p++) {
        bool match = true;
        for (size_t i = 0; i < needle_len && p[i]; i++) {
            if (tolower(static_cast<unsigned char>(p[i])) != needle[i]) {
                match = false;
                break;
            }
        }
        if (match) return true;
    }
    return false;
}

// Update commit history filter based on search query
static void update_history_filter() {
    CommitHistoryState& state = g_commit_history;
    const GitHistory* h = &state.history;

    // If query is empty, clear filter
    if (state.search_query[0] == L'\0') {
        state.filtered_count = 0;
        if (g_commit_history_widget) {
            g_commit_history_widget->clear_filter();
        }
        return;
    }

    // Ensure capacity for filtered indices
    if (h->commit_count > state.filtered_capacity) {
        if (state.filtered_indices) free(state.filtered_indices);
        state.filtered_indices = static_cast<int*>(malloc(h->commit_count * sizeof(int)));
        state.filtered_capacity = h->commit_count;
        if (!state.filtered_indices) {
            state.filtered_capacity = 0;
            state.filtered_count = 0;
            return;
        }
    }

    // Convert query to lowercase UTF-8
    char query_utf8[256] = {};
    char query_lower[256] = {};
    WideCharToMultiByte(CP_UTF8, 0, state.search_query, -1, query_utf8, 256, nullptr, nullptr);
    size_t qlen = strlen(query_utf8);
    for (size_t i = 0; i <= qlen; i++) {
        query_lower[i] = static_cast<char>(tolower(static_cast<unsigned char>(query_utf8[i])));
    }

    // Search commits
    state.filtered_count = 0;
    for (size_t i = 0; i < h->commit_count; i++) {
        bool match = false;

        // Search message
        const char* msg = git_history_get_message(h, i);
        if (msg && strcasestr_local(msg, query_lower, qlen)) {
            match = true;
        }

        // Search author
        if (!match) {
            const char* author = git_history_get_author(h, i);
            if (author && strcasestr_local(author, query_lower, qlen)) {
                match = true;
            }
        }

        // Search SHA (hex prefix)
        if (!match) {
            char sha_hex[41];
            git_history_get_sha_hex(h, i, sha_hex);
            // SHA hex is already lowercase, do case-insensitive compare anyway
            if (strncmp(sha_hex, query_lower, qlen) == 0) {
                match = true;
            }
        }

        if (match) {
            state.filtered_indices[state.filtered_count++] = static_cast<int>(i);
        }
    }

    // Update widget with filtered results
    if (g_commit_history_widget) {
        g_commit_history_widget->set_filtered_history(
            state.filtered_indices,
            state.filtered_count,
            h->commit_count
        );
    }
}

// Compare paths for qsort (used by commit view file computation)
static int commit_view_compare_paths(const void* a, const void* b) {
    const GitIndexEntry* ea = static_cast<const GitIndexEntry*>(a);
    const GitIndexEntry* eb = static_cast<const GitIndexEntry*>(b);
    return strcmp(ea->path, eb->path);
}

// Binary search for path in sorted GitIndexEntry array
static int commit_view_find_path(const GitIndexEntry* entries, size_t count, const char* path) {
    if (count == 0) return -1;
    int lo = 0, hi = static_cast<int>(count) - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        int cmp = strcmp(entries[mid].path, path);
        if (cmp == 0) return mid;
        if (cmp < 0) lo = mid + 1;
        else hi = mid - 1;
    }
    return -1;
}

// Compute changed files for a commit by comparing its tree with parent's tree
// Returns number of files written to out_files
static size_t compute_commit_changed_files(GitRepository* repo, const GitCommit* commit,
                                           SidebarFile* out_files, size_t max_files) {
    if (!repo || !commit || !out_files || max_files == 0) return 0;

    // Allocate trees
    GitIndexEntry* commit_tree = new GitIndexEntry[Git::MAX_TREE_ENTRIES];
    GitIndexEntry* parent_tree = new GitIndexEntry[Git::MAX_TREE_ENTRIES];

    // Read commit's tree
    size_t commit_count = git_read_tree_flat(repo, commit->tree_sha, commit_tree, Git::MAX_TREE_ENTRIES, "");
    size_t parent_count = 0;

    // Read parent's tree if parent exists
    if (commit->parent_sha[0]) {
        GitCommit parent = {};
        if (git_read_commit(repo, commit->parent_sha, &parent)) {
            parent_count = git_read_tree_flat(repo, parent.tree_sha, parent_tree, Git::MAX_TREE_ENTRIES, "");
        }
    }

    // Sort both arrays by path for efficient comparison
    if (commit_count > 1) {
        qsort(commit_tree, commit_count, sizeof(GitIndexEntry), commit_view_compare_paths);
    }
    if (parent_count > 1) {
        qsort(parent_tree, parent_count, sizeof(GitIndexEntry), commit_view_compare_paths);
    }

    size_t out_count = 0;

    // Find added and modified files (in commit but not parent, or different SHA)
    for (size_t i = 0; i < commit_count && out_count < max_files; i++) {
        const GitIndexEntry* entry = &commit_tree[i];
        int parent_idx = commit_view_find_path(parent_tree, parent_count, entry->path);

        FileStatus status;
        if (parent_idx < 0) {
            // File added (not in parent)
            status = FileStatus::Added;
        } else if (strcmp(entry->sha, parent_tree[parent_idx].sha) != 0) {
            // File modified (different SHA)
            status = FileStatus::Modified;
        } else {
            // File unchanged, skip
            continue;
        }

        // Populate SidebarFile
        SidebarFile* file = &out_files[out_count++];
        memset(file, 0, sizeof(SidebarFile));

        // Convert path to wide string
        MultiByteToWideChar(CP_UTF8, 0, entry->path, -1, file->full_path, 512);

        // Extract filename
        const char* last_slash = strrchr(entry->path, '/');
        const char* filename_part = last_slash ? (last_slash + 1) : entry->path;
        MultiByteToWideChar(CP_UTF8, 0, filename_part, -1, file->filename, 256);

        file->status = status;
        file->lines_added = 0;
        file->lines_removed = 0;
        file->similarity = 0;
    }

    // Find deleted files (in parent but not commit)
    for (size_t i = 0; i < parent_count && out_count < max_files; i++) {
        const GitIndexEntry* entry = &parent_tree[i];
        int commit_idx = commit_view_find_path(commit_tree, commit_count, entry->path);

        if (commit_idx < 0) {
            // File deleted
            SidebarFile* file = &out_files[out_count++];
            memset(file, 0, sizeof(SidebarFile));

            MultiByteToWideChar(CP_UTF8, 0, entry->path, -1, file->full_path, 512);

            const char* last_slash = strrchr(entry->path, '/');
            const char* filename_part = last_slash ? (last_slash + 1) : entry->path;
            MultiByteToWideChar(CP_UTF8, 0, filename_part, -1, file->filename, 256);

            file->status = FileStatus::Deleted;
            file->lines_added = 0;
            file->lines_removed = 0;
            file->similarity = 0;
        }
    }

    delete[] commit_tree;
    delete[] parent_tree;

    return out_count;
}

// Load details for a selected commit
static void commit_history_load_details(int index) {
    LOG_DEBUG(CommitView, "commit_history_load_details(index=%d)", index);
    if (index < 0 || index >= static_cast<int>(g_commit_history.history.commit_count)) {
        LOG_DEBUG(CommitView, "Invalid index - setting viewing_commit=false");
        g_commit_history.details_visible = false;
        g_sidebar.viewing_commit = false;
        return;
    }

    // Get the SHA for this commit
    const CommitMeta* meta = &g_commit_history.history.commits[index];
    char sha_hex[41];
    sha_raw_to_hex(meta->sha, sha_hex);

    // Load the full commit data
    bool success;
    {
        RepoLockGuard lock;
        success = git_read_commit(&g_repo, sha_hex, &g_commit_history.selected_commit_full);
    }

    if (success) {
        LOG_DEBUG(CommitView, "Successfully loaded commit - setting viewing_commit=true");
        g_commit_history.details_visible = true;
        g_commit_history.changed_file_count = 0;

        // Populate sidebar commit view state
        g_sidebar.viewing_commit = true;
        strcpy_s(g_sidebar.viewing_commit_sha, sha_hex);
        strncpy_s(g_sidebar.viewing_commit_short, sizeof(g_sidebar.viewing_commit_short),
                  sha_hex, 7);
        LOG_DEBUG(CommitView, "After strncpy_s: viewing_commit_short='%s' (length=%zu)",
            g_sidebar.viewing_commit_short, strlen(g_sidebar.viewing_commit_short));
        strcpy_s(g_sidebar.viewing_commit_author, g_commit_history.selected_commit_full.author_name);
        strcpy_s(g_sidebar.viewing_commit_message, g_commit_history.selected_commit_full.message);
        g_sidebar.viewing_commit_time = g_commit_history.selected_commit_full.author_time;
        g_sidebar.commit_view_selected = -1;
        g_sidebar.commit_view_scroll = 0.0f;
        g_sidebar.commit_view_hovered = -1;

        // Compute changed files by comparing trees
        {
            RepoLockGuard lock;
            g_sidebar.commit_view_file_count = compute_commit_changed_files(
                &g_repo, &g_commit_history.selected_commit_full,
                g_sidebar.commit_view_files, 256);
        }
    } else {
        LOG_DEBUG(CommitView, "Failed to load commit - setting viewing_commit=false");
        g_commit_history.details_visible = false;
        g_sidebar.viewing_commit = false;
    }
    LOG_DEBUG(CommitView, "commit_history_load_details done - viewing_commit=%d", g_sidebar.viewing_commit);
}

// Get fetch phase display name
static const wchar_t* get_fetch_phase_name(FetchPhase phase) {
    switch (phase) {
        case FetchPhase::Connecting:      return L"Connecting...";
        case FetchPhase::Authenticating:  return L"Authenticating...";
        case FetchPhase::Negotiating:     return L"Negotiating...";
        case FetchPhase::Receiving:       return L"Receiving objects...";
        case FetchPhase::ResolvingDeltas: return L"Resolving deltas...";
        case FetchPhase::Updating:        return L"Updating refs...";
        case FetchPhase::Complete:        return L"Complete";
        case FetchPhase::Failed:          return L"Failed";
        case FetchPhase::Cancelled:       return L"Cancelled";
        default:                          return L"";
    }
}

static const wchar_t* get_push_phase_name(PushPhase phase) {
    switch (phase) {
        case PushPhase::Connecting:      return L"Connecting...";
        case PushPhase::Authenticating:  return L"Authenticating...";
        case PushPhase::Negotiating:     return L"Negotiating...";
        case PushPhase::Counting:        return L"Counting objects...";
        case PushPhase::Compressing:     return L"Compressing...";
        case PushPhase::Writing:         return L"Uploading...";
        case PushPhase::UpdatingRefs:    return L"Updating refs...";
        case PushPhase::Complete:        return L"Complete";
        case PushPhase::Failed:          return L"Failed";
        case PushPhase::Rejected:        return L"Rejected";
        case PushPhase::Cancelled:       return L"Cancelled";
        default:                         return L"";
    }
}

static const wchar_t* get_pull_phase_name(PullPhase phase) {
    switch (phase) {
        case PullPhase::Fetching:           return L"Fetching...";
        case PullPhase::CheckingFastForward:return L"Checking...";
        case PullPhase::UpdatingWorkdir:    return L"Updating files...";
        case PullPhase::UpdatingIndex:      return L"Updating index...";
        case PullPhase::UpdatingRefs:       return L"Updating refs...";
        case PullPhase::Complete:           return L"Complete";
        case PullPhase::Failed:             return L"Failed";
        case PullPhase::Cancelled:          return L"Cancelled";
        case PullPhase::NotFastForward:     return L"Not fast-forward";
        case PullPhase::DirtyWorkdir:       return L"Working dir dirty";
        default:                            return L"";
    }
}

// Format bytes for display (KB, MB, etc.)
static void format_bytes(uint64_t bytes, wchar_t* buffer, size_t buffer_size) {
    if (bytes < 1024) {
        swprintf_s(buffer, buffer_size, L"%llu B", bytes);
    } else if (bytes < 1024 * 1024) {
        swprintf_s(buffer, buffer_size, L"%.1f KB", bytes / 1024.0);
    } else if (bytes < 1024 * 1024 * 1024) {
        swprintf_s(buffer, buffer_size, L"%.1f MB", bytes / (1024.0 * 1024.0));
    } else {
        swprintf_s(buffer, buffer_size, L"%.2f GB", bytes / (1024.0 * 1024.0 * 1024.0));
    }
}

// Extract host from remote URL
static bool extract_host_from_remote(GitRepository* repo, const char* remote_name,
                                      char* host, size_t host_size) {
    if (!repo || !remote_name || !host) return false;

    // Load remote by name
    GitRemote remote;
    if (!git_remote_load(repo, remote_name, &remote)) {
        return false;
    }

    // Parse URL to extract host
    // Format: https://host/path or https://username@host/path
    const char* url = remote.url;
    const char* scheme_end = strstr(url, "://");
    if (!scheme_end) return false;

    const char* host_start = scheme_end + 3;
    const char* at_sign = strchr(host_start, '@');
    if (at_sign) {
        host_start = at_sign + 1;  // Skip username@ if present
    }

    const char* path_start = strchr(host_start, '/');
    size_t host_len;
    if (path_start) {
        host_len = path_start - host_start;
    } else {
        host_len = strlen(host_start);
    }

    if (host_len >= host_size) return false;

    strncpy_s(host, host_size, host_start, host_len);
    host[host_len] = '\0';

    return true;
}

// Extract host from URL string directly (for clone operations)
static bool extract_host_from_url(const char* url, char* host, size_t host_size) {
    if (!url || !host) return false;

    // Parse URL to extract host
    // Format: https://host/path or https://username@host/path
    const char* scheme_end = strstr(url, "://");
    if (!scheme_end) return false;

    const char* host_start = scheme_end + 3;
    const char* at_sign = strchr(host_start, '@');
    if (at_sign) {
        host_start = at_sign + 1;  // Skip username@ if present
    }

    const char* path_start = strchr(host_start, '/');
    size_t host_len;
    if (path_start) {
        host_len = path_start - host_start;
    } else {
        host_len = strlen(host_start);
    }

    if (host_len >= host_size) return false;

    strncpy_s(host, host_size, host_start, host_len);
    host[host_len] = '\0';

    return true;
}

