// ============================================================================
// StatusBarWidget - Widget-based status bar
// ============================================================================

struct StatusBarWidget {
    // Container widget (not a dialog, just a regular widget)
    FlexContainer* container = nullptr;

    // Left section: branch info
    Label* branch_icon = nullptr;  // For branch icon rendering (custom)
    Label* branch_label = nullptr;
    Label* sync_label = nullptr;

    // Center section: progress (shown during operations)
    FlexContainer* progress_section = nullptr;
    Label* phase_label = nullptr;
    ProgressBar* progress_bar = nullptr;
    Label* bytes_label = nullptr;

    // Right section: last fetch time
    Label* fetch_label = nullptr;

    // State
    bool operation_in_progress = false;

    // Static text buffers
    wchar_t branch_text[256] = {};
    wchar_t sync_text[64] = {};
    wchar_t phase_text[128] = {};
    wchar_t bytes_text[64] = {};
    wchar_t fetch_text[64] = {};

    void update_normal_mode() {
        operation_in_progress = false;

        // Update branch name
        wcscpy_s(branch_text, g_status_bar.branch_name);
        branch_label->text = branch_text;

        // Update sync status
        if (g_status_bar.sync_status.valid) {
            if (g_status_bar.sync_status.ahead > 0 && g_status_bar.sync_status.behind > 0) {
                swprintf_s(sync_text, L"\u2191%d \u2193%d", g_status_bar.sync_status.ahead, g_status_bar.sync_status.behind);
            } else if (g_status_bar.sync_status.ahead > 0) {
                swprintf_s(sync_text, L"\u2191%d", g_status_bar.sync_status.ahead);
            } else if (g_status_bar.sync_status.behind > 0) {
                swprintf_s(sync_text, L"\u2193%d", g_status_bar.sync_status.behind);
            } else {
                sync_text[0] = L'\0';
            }
        } else {
            sync_text[0] = L'\0';
        }
        sync_label->text = sync_text;

        // Update fetch label
        wcscpy_s(fetch_text, g_status_bar.last_fetch);
        fetch_label->text = fetch_text;

        // Hide progress section
        progress_section->flags &= ~WidgetFlags::Visible;

        // Show normal labels
        branch_label->flags |= WidgetFlags::Visible;
        sync_label->flags |= WidgetFlags::Visible;
        fetch_label->flags |= WidgetFlags::Visible;
    }

    void update_progress_mode(const wchar_t* phase, float progress, bool indeterminate, uint64_t bytes) {
        operation_in_progress = true;

        // Update phase text
        wcscpy_s(phase_text, phase);
        phase_label->text = phase_text;

        // Update progress bar
        if (indeterminate) {
            progress_bar->set_indeterminate(true);
        } else {
            progress_bar->set_progress(progress);
        }

        // Update bytes text
        format_bytes(bytes, bytes_text, 64);
        bytes_label->text = bytes_text;

        // Show progress section
        progress_section->flags |= WidgetFlags::Visible;

        // Hide normal labels (except branch - keep it visible)
        sync_label->flags &= ~WidgetFlags::Visible;
        fetch_label->flags &= ~WidgetFlags::Visible;
    }
};

// Global status bar widget instance
static StatusBarWidget* g_status_bar_widget = nullptr;
static WidgetTree g_status_bar_tree = {};

// Forward declaration
static void status_bar_widget_init();

// Initialize the status bar widget
static void status_bar_widget_init() {
    if (g_status_bar_widget) return;  // Already initialized

    g_status_bar_widget = g_widget_arena.create<StatusBarWidget>();
    if (!g_status_bar_widget) return;

    // Create main horizontal container
    FlexContainer* container = g_widget_arena.create<FlexContainer>();
    container->direction = FlexDirection::Row;
    container->align = FlexAlign::Center;
    container->justify = FlexJustify::SpaceBetween;
    container->preferred_height = StatusBar::HEIGHT;
    container->padding_left = StatusBar::PADDING_H;
    container->padding_right = StatusBar::PADDING_H;
    g_status_bar_widget->container = container;

    // Left section container
    FlexContainer* left_section = g_widget_arena.create<FlexContainer>();
    left_section->direction = FlexDirection::Row;
    left_section->align = FlexAlign::Center;
    left_section->gap = 8.0f;

    // Branch label (icon is drawn in custom render)
    Label* branch_label = g_widget_arena.create<Label>();
    branch_label->text = L"";
    branch_label->color = 0xFFFFFFFF;  // White text on accent background
    branch_label->preferred_height = StatusBar::HEIGHT;
    branch_label->padding_left = StatusBar::ICON_SIZE + StatusBar::ICON_SPACING;  // Space for icon
    branch_label->para_align = DWRITE_PARAGRAPH_ALIGNMENT_CENTER;
    widget_add_child(left_section, branch_label);
    g_status_bar_widget->branch_label = branch_label;

    // Sync status label
    Label* sync_label = g_widget_arena.create<Label>();
    sync_label->text = L"";
    sync_label->color = 0xCCFFFFFF;  // Slightly transparent white
    sync_label->preferred_height = StatusBar::HEIGHT;
    sync_label->para_align = DWRITE_PARAGRAPH_ALIGNMENT_CENTER;
    widget_add_child(left_section, sync_label);
    g_status_bar_widget->sync_label = sync_label;

    widget_add_child(container, left_section);

    // Center section: progress (initially hidden)
    FlexContainer* progress_section = g_widget_arena.create<FlexContainer>();
    progress_section->direction = FlexDirection::Row;
    progress_section->align = FlexAlign::Center;
    progress_section->justify = FlexJustify::Center;  // Center children horizontally
    progress_section->gap = 16.0f;
    progress_section->flex = 1.0f;  // Expand to fill remaining space
    progress_section->flags &= ~WidgetFlags::Visible;  // Hidden by default
    g_status_bar_widget->progress_section = progress_section;

    // Phase label
    Label* phase_label = g_widget_arena.create<Label>();
    phase_label->text = L"";
    phase_label->color = 0xFFFFFFFF;
    phase_label->preferred_height = StatusBar::HEIGHT;
    phase_label->para_align = DWRITE_PARAGRAPH_ALIGNMENT_CENTER;
    widget_add_child(progress_section, phase_label);
    g_status_bar_widget->phase_label = phase_label;

    // Progress bar
    ProgressBar* progress_bar = g_widget_arena.create<ProgressBar>();
    widget_add_child(progress_section, progress_bar);
    g_status_bar_widget->progress_bar = progress_bar;

    // Bytes label
    Label* bytes_label = g_widget_arena.create<Label>();
    bytes_label->text = L"";
    bytes_label->color = 0xFFFFFFFF;
    bytes_label->preferred_height = StatusBar::HEIGHT;
    bytes_label->para_align = DWRITE_PARAGRAPH_ALIGNMENT_CENTER;
    widget_add_child(progress_section, bytes_label);
    g_status_bar_widget->bytes_label = bytes_label;

    widget_add_child(container, progress_section);

    // Right section: last fetch time
    Label* fetch_label = g_widget_arena.create<Label>();
    fetch_label->text = L"";
    fetch_label->color = 0xFFFFFFFF;
    fetch_label->preferred_height = StatusBar::HEIGHT;
    fetch_label->text_align = DWRITE_TEXT_ALIGNMENT_TRAILING;
    fetch_label->para_align = DWRITE_PARAGRAPH_ALIGNMENT_CENTER;
    widget_add_child(container, fetch_label);
    g_status_bar_widget->fetch_label = fetch_label;

    // Set up tree
    g_status_bar_tree.root = container;
}

// Update status bar widget state based on current operation state
static void status_bar_widget_update() {
    if (!g_status_bar_widget) {
        status_bar_widget_init();
    }
    if (!g_status_bar_widget) return;

    // Check if operation is in progress using new API
    WorkerJobType job_type = worker_get_job_type();
    bool fetch_in_progress = (job_type == WorkerJobType::Fetch);
    bool push_in_progress = (job_type == WorkerJobType::Push);
    bool pull_in_progress = (job_type == WorkerJobType::Pull);
    bool checkout_in_progress = (job_type == WorkerJobType::Checkout);

    if (fetch_in_progress || push_in_progress || pull_in_progress || checkout_in_progress) {
        // === PROGRESS MODE ===
        const wchar_t* phase_text = L"";
        uint64_t objects_done = 0;
        uint64_t objects_total = 0;
        uint64_t bytes_count = 0;
        bool is_indeterminate = false;

        if (fetch_in_progress) {
            const FetchProgress* progress = worker_get_fetch_progress();
            FetchPhase phase;
            uint32_t gen;
            do {
                gen = progress->base.generation.load();
                phase = progress->phase.load();
                objects_done = progress->objects_done.load();
                objects_total = progress->objects_total.load();
                bytes_count = progress->bytes_received.load();
            } while (gen != progress->base.generation.load());

            phase_text = get_fetch_phase_name(phase);
            is_indeterminate = (phase == FetchPhase::Receiving && bytes_count > 0 && objects_total == 0);
        } else if (push_in_progress) {
            const PushProgress* progress = worker_get_push_progress();
            PushPhase phase;
            uint32_t gen;
            do {
                gen = progress->base.generation.load();
                phase = progress->phase.load();
                objects_done = progress->objects_done.load();
                objects_total = progress->objects_total.load();
                bytes_count = progress->bytes_sent.load();
            } while (gen != progress->base.generation.load());

            phase_text = get_push_phase_name(phase);
            is_indeterminate = (phase == PushPhase::Writing && bytes_count > 0 && objects_total == 0);
        } else if (pull_in_progress) {
            const PullProgress* progress = worker_get_pull_progress();
            PullPhase phase;
            uint32_t gen;
            do {
                gen = progress->base.generation.load();
                phase = progress->phase.load();
                objects_done = progress->files_done.load();
                objects_total = progress->files_total.load();
                bytes_count = progress->fetch_bytes.load();
            } while (gen != progress->base.generation.load());

            phase_text = get_pull_phase_name(phase);
            is_indeterminate = (phase == PullPhase::Fetching);
        } else {
            const CheckoutProgress* progress = worker_get_checkout_progress();
            CheckoutPhase phase;
            uint32_t gen;
            do {
                gen = progress->base.generation.load();
                phase = progress->phase.load();
                objects_done = progress->files_done.load();
                objects_total = progress->files_total.load();
            } while (gen != progress->base.generation.load());

            switch (phase) {
                case CheckoutPhase::CheckingWorkdir: phase_text = L"Checking working directory..."; break;
                case CheckoutPhase::ReadingTree:     phase_text = L"Reading tree..."; break;
                case CheckoutPhase::UpdatingFiles:   phase_text = L"Updating files..."; break;
                case CheckoutPhase::UpdatingIndex:   phase_text = L"Updating index..."; break;
                case CheckoutPhase::UpdatingHead:    phase_text = L"Updating HEAD..."; break;
                case CheckoutPhase::Complete:        phase_text = L"Complete"; break;
                case CheckoutPhase::Failed:          phase_text = L"Failed"; break;
                case CheckoutPhase::DirtyWorkdir:    phase_text = L"Uncommitted changes"; break;
                default:                             phase_text = L"Checking out..."; break;
            }
            is_indeterminate = (objects_total == 0);
        }

        float progress = 0.0f;
        if (objects_total > 0) {
            progress = static_cast<float>(objects_done) / static_cast<float>(objects_total);
        }

        g_status_bar_widget->update_progress_mode(phase_text, progress, is_indeterminate, bytes_count);
    } else {
        // === NORMAL MODE ===
        g_status_bar_widget->update_normal_mode();
    }
}

// Layout and render the status bar widget
static void status_bar_widget_render(ID2D1SolidColorBrush* brush) {
    // Update widget state (and initialize if needed) - must be called first
    status_bar_widget_update();

    if (!g_status_bar_widget || !g_status_bar_widget->container || !g_render_target) {
        return;
    }

    float width = g_render_target->GetSize().width;
    float height = g_render_target->GetSize().height;
    float bar_top = height - StatusBar::HEIGHT;

    // Draw background (accent color)
    D2D1_RECT_F bar_rect = D2D1::RectF(0, bar_top, width, height);
    brush->SetColor(color_from_argb(Theme::ACCENT));
    g_render_target->FillRectangle(bar_rect, brush);

    // Layout the widget - measure first, then set rect, then layout
    LayoutConstraints constraints;
    constraints.max_width = width;
    constraints.max_height = StatusBar::HEIGHT;
    LayoutEngine::measure_tree(g_status_bar_widget->container, constraints);

    // Set rect AFTER measure (measure overwrites rect with preferred size)
    g_status_bar_widget->container->rect.x = 0;
    g_status_bar_widget->container->rect.y = bar_top;
    g_status_bar_widget->container->rect.width = width;  // Full status bar width for SpaceBetween
    g_status_bar_widget->container->rect.height = StatusBar::HEIGHT;

    LayoutEngine::layout_tree(g_status_bar_widget->container);

    // Render the widget tree
    g_status_bar_tree.render(g_render_target);

    // Draw branch icon manually (custom rendering for the fork shape)
    brush->SetColor(color_from_argb(0xFFFFFFFF));
    float icon_left = StatusBar::PADDING_H;
    float center_y = bar_top + StatusBar::HEIGHT / 2.0f;
    float icon_top = center_y - StatusBar::ICON_SIZE / 2.0f;

    // Vertical trunk line
    g_render_target->DrawLine(
        D2D1::Point2F(icon_left + 4.0f, icon_top + 2.0f),
        D2D1::Point2F(icon_left + 4.0f, icon_top + 12.0f),
        brush, 1.5f
    );

    // Branch line (diagonal to upper right)
    g_render_target->DrawLine(
        D2D1::Point2F(icon_left + 4.0f, icon_top + 5.0f),
        D2D1::Point2F(icon_left + 10.0f, icon_top + 2.0f),
        brush, 1.5f
    );

    // Dots at ends (commit nodes)
    D2D1_ELLIPSE dot_bottom = D2D1::Ellipse(D2D1::Point2F(icon_left + 4.0f, icon_top + 12.0f), 2.0f, 2.0f);
    D2D1_ELLIPSE dot_branch = D2D1::Ellipse(D2D1::Point2F(icon_left + 10.0f, icon_top + 2.0f), 2.0f, 2.0f);
    g_render_target->FillEllipse(dot_bottom, brush);
    g_render_target->FillEllipse(dot_branch, brush);
}

// ============================================================================
// BranchSelectorWidget - Widget-based branch selector
// ============================================================================

struct BranchSelectorWidget : Widget {
    wchar_t branch_text[256] = {};

    // Appearance
    float height = Sidebar::BRANCH_SELECTOR_HEIGHT;  // 36.0f
    uint32_t bg_color = Theme::BG_TERTIARY;
    uint32_t icon_color = Theme::TEXT_SECONDARY;
    uint32_t text_color = Theme::TEXT_PRIMARY;

    BranchSelectorWidget() {
        // Purely informational - not focusable or clickable
        preferred_height = height;
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_height = height;
        preferred_width = constraints.max_width;
        rect.width = preferred_width;
        rect.height = preferred_height;
    }

    void update_branch_name() {
        if (g_sidebar.current_branch_name[0]) {
            wcscpy_s(branch_text, g_sidebar.current_branch_name);
        } else {
            wcscpy_s(branch_text, L"(no branch)");
        }
    }

    void render(RenderContext& ctx) override {
        D2D1_RECT_F bg_rect = D2D1::RectF(
            rect.x, rect.y,
            rect.x + rect.width, rect.y + rect.height
        );

        // Background (static - no hover state)
        ctx.fill_rect(bg_rect, bg_color);

        // Branch icon (simple Y shape / git branch icon)
        float icon_x = rect.x + Theme::PADDING + 4.0f;
        float icon_y = rect.y + rect.height / 2.0f;

        ctx.brush->SetColor(color_from_argb(icon_color));
        // Left branch of Y
        ctx.target->DrawLine(
            D2D1::Point2F(icon_x, icon_y - 6.0f),
            D2D1::Point2F(icon_x + 4.0f, icon_y),
            ctx.brush, 1.5f);
        // Right branch of Y
        ctx.target->DrawLine(
            D2D1::Point2F(icon_x + 8.0f, icon_y - 6.0f),
            D2D1::Point2F(icon_x + 4.0f, icon_y),
            ctx.brush, 1.5f);
        // Trunk of Y
        ctx.target->DrawLine(
            D2D1::Point2F(icon_x + 4.0f, icon_y),
            D2D1::Point2F(icon_x + 4.0f, icon_y + 6.0f),
            ctx.brush, 1.5f);

        // Branch name (no chevron - purely informational)
        D2D1_RECT_F text_rect = D2D1::RectF(
            rect.x + Theme::PADDING + 20.0f, rect.y,
            rect.x + rect.width - Theme::PADDING, rect.y + rect.height
        );
        ctx.draw_text(branch_text, wcslen(branch_text), g_text_format_body, text_rect, text_color);
    }

    // No mouse/key handlers - purely informational display
};

// ============================================================================
// CommitBoxWidget - Widget-based commit message box and button
// ============================================================================

struct CommitBoxWidget : Widget {
    // Textarea appearance
    float textarea_height = Sidebar::COMMIT_BOX_MIN_HEIGHT;
    float button_height = Sidebar::COMMIT_BUTTON_HEIGHT;
    float padding = Sidebar::COMMIT_BOX_PADDING;

    // Colors
    uint32_t textarea_bg = Theme::BG_TERTIARY;
    uint32_t textarea_border = Theme::BORDER;
    uint32_t textarea_border_focus = Theme::ACCENT;
    uint32_t button_bg = Theme::ACCENT;
    uint32_t button_bg_hover = Theme::ACCENT_HOVER;
    uint32_t button_bg_disabled = Theme::BG_TERTIARY;
    uint32_t text_color = Theme::TEXT_PRIMARY;
    uint32_t placeholder_color = Theme::TEXT_MUTED;

    // Button hover state (widget manages its own state)
    bool button_hovered = false;

    // Callbacks
    void (*on_commit)(void* user_data) = nullptr;
    void (*on_textarea_click)(void* user_data) = nullptr;
    void* user_data = nullptr;

    CommitBoxWidget() {
        // No default focusability - textarea focus is managed separately
    }

    void measure(const LayoutConstraints& constraints) override {
        // Calculate dynamic height based on message content
        textarea_height = g_sidebar.commit_box_height;

        // Total height: padding + textarea + padding + button + padding*2
        float total = padding + textarea_height + padding + button_height + padding * 2;

        preferred_height = total;
        preferred_width = constraints.max_width;
        rect.width = preferred_width;
        rect.height = preferred_height;
    }

    void render(RenderContext& ctx) override {
        float content_width = rect.width;

        // Textarea
        D2D1_RECT_F textarea_rect = D2D1::RectF(
            rect.x + padding, rect.y + padding,
            rect.x + content_width - padding, rect.y + padding + textarea_height
        );
        D2D1_ROUNDED_RECT textarea_rounded = D2D1::RoundedRect(textarea_rect, Theme::CORNER_RADIUS, Theme::CORNER_RADIUS);

        // Textarea background
        ctx.fill_rounded_rect(textarea_rect, Theme::CORNER_RADIUS, textarea_bg);

        // Textarea border
        uint32_t border = g_sidebar.commit_box_focused ? textarea_border_focus : textarea_border;
        ctx.brush->SetColor(color_from_argb(border));
        ctx.target->DrawRoundedRectangle(textarea_rounded, ctx.brush, 1.0f);

        // Text content area
        D2D1_RECT_F text_rect = D2D1::RectF(
            textarea_rect.left + padding,
            textarea_rect.top + padding,
            textarea_rect.right - padding,
            textarea_rect.bottom - padding
        );

        // Draw placeholder or message
        if (g_sidebar.commit_message[0] == L'\0' && !g_sidebar.commit_box_focused) {
            // Placeholder
            IDWriteTextLayout* placeholder_layout = nullptr;
            if (g_dwrite_factory) {
                g_dwrite_factory->CreateTextLayout(
                    L"Commit message...", 17,
                    g_text_format_body,
                    text_rect.right - text_rect.left,
                    text_rect.bottom - text_rect.top,
                    &placeholder_layout);
                if (placeholder_layout) {
                    placeholder_layout->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_NEAR);
                    ctx.brush->SetColor(color_from_argb(placeholder_color));
                    ctx.target->DrawTextLayout(
                        D2D1::Point2F(text_rect.left, text_rect.top),
                        placeholder_layout, ctx.brush);
                    placeholder_layout->Release();
                }
            }
        } else {
            // Actual message
            size_t msg_len = wcslen(g_sidebar.commit_message);
            if (msg_len > 0) {
                IDWriteTextLayout* msg_layout = nullptr;
                if (g_dwrite_factory) {
                    g_dwrite_factory->CreateTextLayout(
                        g_sidebar.commit_message, static_cast<UINT32>(msg_len),
                        g_text_format_body,
                        text_rect.right - text_rect.left,
                        text_rect.bottom - text_rect.top,
                        &msg_layout);
                    if (msg_layout) {
                        msg_layout->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_NEAR);
                        ctx.brush->SetColor(color_from_argb(text_color));
                        ctx.target->DrawTextLayout(
                            D2D1::Point2F(text_rect.left, text_rect.top),
                            msg_layout, ctx.brush);
                        msg_layout->Release();
                    }
                }
            }

            // Draw cursor when focused
            if (g_sidebar.commit_box_focused) {
                render_cursor(ctx, text_rect, msg_len);
            }
        }

        // Commit button
        float button_y = rect.y + padding + textarea_height + padding;
        float button_width = content_width - padding * 2;
        D2D1_RECT_F button_rect = D2D1::RectF(
            rect.x + padding, button_y,
            rect.x + padding + button_width, button_y + button_height
        );

        // Button enabled state
        bool has_staged = g_sidebar.staged_count > 0;
        bool has_message = g_sidebar.commit_message[0] != L'\0';
        bool button_enabled = has_staged && has_message;

        // Button background
        uint32_t btn_bg = button_bg_disabled;
        if (button_enabled) {
            btn_bg = button_hovered ? button_bg_hover : button_bg;
        }
        ctx.fill_rounded_rect(button_rect, Theme::CORNER_RADIUS, btn_bg);

        // Button text
        wchar_t button_text[64];
        if (g_sidebar.staged_count > 0) {
            swprintf_s(button_text, L"Commit (%zu)", g_sidebar.staged_count);
        } else {
            wcscpy_s(button_text, L"Commit");
        }

        uint32_t btn_text_color = button_enabled ? 0xFFFFFFFF : placeholder_color;

        // Centered button text
        IDWriteTextLayout* button_layout = nullptr;
        if (g_dwrite_factory) {
            g_dwrite_factory->CreateTextLayout(
                button_text, static_cast<UINT32>(wcslen(button_text)),
                g_text_format_body,
                button_rect.right - button_rect.left,
                button_rect.bottom - button_rect.top,
                &button_layout);
            if (button_layout) {
                button_layout->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
                button_layout->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);
                ctx.brush->SetColor(color_from_argb(btn_text_color));
                ctx.target->DrawTextLayout(
                    D2D1::Point2F(button_rect.left, button_rect.top),
                    button_layout, ctx.brush);
                button_layout->Release();
            }
        }
    }

    void render_cursor(RenderContext& ctx, const D2D1_RECT_F& text_rect, size_t msg_len) {
        if (msg_len > 0) {
            IDWriteTextLayout* cursor_layout = nullptr;
            if (g_dwrite_factory) {
                g_dwrite_factory->CreateTextLayout(
                    g_sidebar.commit_message, static_cast<UINT32>(msg_len),
                    g_text_format_body,
                    text_rect.right - text_rect.left,
                    text_rect.bottom - text_rect.top,
                    &cursor_layout);

                if (cursor_layout) {
                    cursor_layout->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_NEAR);

                    DWRITE_HIT_TEST_METRICS metrics;
                    float cursor_x, cursor_y;
                    cursor_layout->HitTestTextPosition(
                        static_cast<UINT32>(g_sidebar.commit_cursor_pos),
                        FALSE, &cursor_x, &cursor_y, &metrics);

                    ctx.brush->SetColor(color_from_argb(text_color));
                    ctx.target->DrawLine(
                        D2D1::Point2F(text_rect.left + cursor_x, text_rect.top + cursor_y),
                        D2D1::Point2F(text_rect.left + cursor_x, text_rect.top + cursor_y + metrics.height),
                        ctx.brush, 1.0f);

                    cursor_layout->Release();
                }
            }
        } else {
            // Cursor at start when empty
            ctx.brush->SetColor(color_from_argb(text_color));
            ctx.target->DrawLine(
                D2D1::Point2F(text_rect.left, text_rect.top),
                D2D1::Point2F(text_rect.left, text_rect.top + Sidebar::COMMIT_LINE_HEIGHT),
                ctx.brush, 1.0f);
        }
    }

    bool on_mouse_move(float x, float y) override {
        // Note: x, y are RELATIVE to widget's top-left corner
        // Check if over button using relative coordinates
        float button_y_start = padding + textarea_height + padding;
        float button_bottom = button_y_start + button_height;
        float button_left = padding;
        float button_right = rect.width - padding;

        bool over_button = (x >= button_left && x < button_right &&
                           y >= button_y_start && y < button_bottom);

        if (over_button != button_hovered) {
            button_hovered = over_button;
            set_dirty();
        }

        return false;  // Don't consume - let parent handle other hover logic
    }

    bool on_mouse_leave() override {
        if (button_hovered) {
            button_hovered = false;
            set_dirty();
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x; (void)button;

        // Note: x, y are RELATIVE to widget's top-left corner
        float textarea_top = padding;
        float textarea_bottom = padding + textarea_height;

        // Check if click is in textarea
        if (y >= textarea_top && y < textarea_bottom) {
            if (on_textarea_click) {
                on_textarea_click(user_data);
            }
            return true;
        }

        return false;  // Let mouse up handle button
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)button;

        // Note: x, y are RELATIVE to widget's top-left corner
        float button_y_start = padding + textarea_height + padding;
        float button_bottom = button_y_start + button_height;
        float button_left = padding;
        float button_right = rect.width - padding;

        // Check if click is on button
        if (x >= button_left && x < button_right &&
            y >= button_y_start && y < button_bottom) {
            // Check if button is enabled
            bool has_staged = g_sidebar.staged_count > 0;
            bool has_message = g_sidebar.commit_message[0] != L'\0';
            if (has_staged && has_message && on_commit) {
                on_commit(user_data);
            }
            return true;
        }

        return false;
    }

    // Get button rect for external hit testing
    void get_button_rect(float& left, float& top, float& right, float& bottom) const {
        left = rect.x + padding;
        top = rect.y + padding + textarea_height + padding;
        right = rect.x + rect.width - padding;
        bottom = top + button_height;
    }

    // Get textarea rect for external hit testing
    void get_textarea_rect(float& left, float& top, float& right, float& bottom) const {
        left = rect.x + padding;
        top = rect.y + padding;
        right = rect.x + rect.width - padding;
        bottom = top + textarea_height;
    }
};

// ============================================================================
// SidebarHeaderWidget - Container for branch selector and commit box
// ============================================================================

struct SidebarHeaderWidget {
    FlexContainer* container = nullptr;
    BranchSelectorWidget* branch_selector = nullptr;
    CommitBoxWidget* commit_box = nullptr;

    // Text buffers for branch name
    wchar_t branch_text[256] = {};

    void update() {
        if (branch_selector) {
            branch_selector->update_branch_name();
        }
        // Commit box reads directly from g_sidebar state
    }
};

// Global sidebar header widget instance
static SidebarHeaderWidget* g_sidebar_header_widget = nullptr;
static WidgetTree g_sidebar_header_tree = {};

// Forward declarations
static void sidebar_header_widget_init();
static void perform_commit_action();
// Callback for commit button click
static void on_commit_button_click(void* user_data) {
    (void)user_data;
    perform_commit_action();
}

// Callback for commit textarea click
static void on_commit_textarea_click(void* user_data) {
    (void)user_data;
    g_sidebar.commit_box_focused = true;
    // Position cursor at end
    g_sidebar.commit_cursor_pos = wcslen(g_sidebar.commit_message);
    g_sidebar.commit_selection_start = g_sidebar.commit_cursor_pos;
    if (g_main_window) {
        InvalidateRect(g_main_window, nullptr, FALSE);
    }
}

// Perform the commit action
static void perform_commit_action() {
    bool has_staged = g_sidebar.staged_count > 0;
    bool has_message = g_sidebar.commit_message[0] != L'\0';

    if (!has_staged || !has_message) return;

    // Convert message to UTF-8
    char message_utf8[Git::MAX_COMMIT_MSG];
    WideCharToMultiByte(CP_UTF8, 0, g_sidebar.commit_message, -1,
        message_utf8, sizeof(message_utf8), nullptr, nullptr);

    {
        RepoLockGuard lock;
        if (git_commit(&g_repo, message_utf8, false)) {
            // Success - clear message and refresh
            g_sidebar.commit_message[0] = L'\0';
            g_sidebar.commit_cursor_pos = 0;
            g_sidebar.commit_selection_start = 0;
            g_sidebar.commit_box_height = Sidebar::COMMIT_BOX_MIN_HEIGHT;
            sidebar_load_status();
            git_read_head(&g_repo);
        } else {
            MessageBoxW(g_main_window, L"Commit failed. Check git configuration.", L"Error", MB_OK | MB_ICONERROR);
        }
    }

    if (g_main_window) {
        InvalidateRect(g_main_window, nullptr, FALSE);
    }
}

// Initialize the sidebar header widget
static void sidebar_header_widget_init() {
    if (g_sidebar_header_widget) return;  // Already initialized

    g_sidebar_header_widget = g_widget_arena.create<SidebarHeaderWidget>();
    if (!g_sidebar_header_widget) return;

    // Create main vertical container
    FlexContainer* container = g_widget_arena.create<FlexContainer>();
    container->direction = FlexDirection::Column;
    container->align = FlexAlign::Stretch;
    container->gap = 0.0f;
    g_sidebar_header_widget->container = container;

    // Create branch selector (purely informational - no click handler)
    BranchSelectorWidget* branch_selector = g_widget_arena.create<BranchSelectorWidget>();
    widget_add_child(container, branch_selector);
    g_sidebar_header_widget->branch_selector = branch_selector;

    // Create commit box
    CommitBoxWidget* commit_box = g_widget_arena.create<CommitBoxWidget>();
    commit_box->on_commit = on_commit_button_click;
    commit_box->on_textarea_click = on_commit_textarea_click;
    widget_add_child(container, commit_box);
    g_sidebar_header_widget->commit_box = commit_box;

    // Set up tree
    g_sidebar_header_tree.root = container;

    LOG("Sidebar header widget initialized");
}

