// ============================================================================
// Sidebar File List Widgets
// ============================================================================
// Widget-based file list rendering for staged and changed files sections

// Forward declaration of status conversion
static FileListItemStatus convert_file_status(FileStatus status);

// Global file list widget instances
struct SidebarFileListWidgets {
    ScrollContainer* container = nullptr;  // Unified scroll container
    FlexContainer* flex = nullptr;         // Vertical layout for children
    SectionHeader* staged_header = nullptr;
    FileList* staged_list = nullptr;
    SectionHeader* changed_header = nullptr;
    FileList* changed_list = nullptr;
    CommitViewHeader* commit_header = nullptr;  // Header for commit view mode
    bool initialized = false;
    bool show_commit_border = false;  // Show accent border around file list in commit view

    // Dirty tracking - only rebuild when file list content changes
    bool files_dirty = true;
    size_t last_staged_count = 0;
    size_t last_changed_count = 0;
};

static SidebarFileListWidgets g_file_list_widgets = {};
static WidgetTree g_file_list_tree = {};

// Convert platform FileStatus to widget FileListItemStatus
static FileListItemStatus convert_file_status(FileStatus status) {
    switch (status) {
        case FileStatus::Modified:  return FileListItemStatus::Modified;
        case FileStatus::Added:     return FileListItemStatus::Added;
        case FileStatus::Deleted:   return FileListItemStatus::Deleted;
        case FileStatus::Renamed:   return FileListItemStatus::Renamed;
        case FileStatus::Untracked: return FileListItemStatus::Untracked;
        default:                    return FileListItemStatus::Modified;
    }
}

// Callbacks for file list actions
static void on_staged_file_select(FileList* list, int index, void* user_data);
static void on_staged_file_action(FileList* list, int index, void* user_data);
static void on_changed_file_select(FileList* list, int index, void* user_data);
static void on_changed_file_action(FileList* list, int index, void* user_data);
static void on_changed_file_discard(FileList* list, int index, void* user_data);
static void on_commit_view_file_select(FileList* list, int index, void* user_data);
static void on_staged_header_toggle(SectionHeader* header, bool collapsed, void* user_data);
static void on_staged_header_action(SectionHeader* header, void* user_data);
static void on_changed_header_toggle(SectionHeader* header, bool collapsed, void* user_data);
static void on_changed_header_action(SectionHeader* header, void* user_data);

// Initialize file list widgets
static void sidebar_file_list_widgets_init() {
    if (g_file_list_widgets.initialized) return;

    // Create unified scroll container (critical - early return if fails)
    g_file_list_widgets.container = g_widget_arena.create<ScrollContainer>();
    if (!g_file_list_widgets.container) return;
    g_file_list_widgets.container->show_scrollbar_v = true;
    g_file_list_widgets.container->show_scrollbar_h = false;

    // Create flex container for vertical stacking (critical - early return if fails)
    g_file_list_widgets.flex = g_widget_arena.create<FlexContainer>();
    if (!g_file_list_widgets.flex) return;
    g_file_list_widgets.flex->direction = FlexDirection::Column;
    g_file_list_widgets.flex->align = FlexAlign::Stretch;
    g_file_list_widgets.flex->gap = 0.0f;

    // Create staged section header
    g_file_list_widgets.staged_header = g_widget_arena.create<SectionHeader>();
    if (g_file_list_widgets.staged_header) {
        g_file_list_widgets.staged_header->title = L"STAGED";
        g_file_list_widgets.staged_header->action_text = L"-All";
        g_file_list_widgets.staged_header->collapsible = true;
        g_file_list_widgets.staged_header->collapsed = g_sidebar.staged_collapsed;
        g_file_list_widgets.staged_header->show_action_on_hover_only = true;
        g_file_list_widgets.staged_header->on_toggle = on_staged_header_toggle;
        g_file_list_widgets.staged_header->on_action = on_staged_header_action;
    }

    // Create staged file list (external scroll mode)
    g_file_list_widgets.staged_list = g_widget_arena.create<FileList>();
    if (g_file_list_widgets.staged_list) {
        g_file_list_widgets.staged_list->is_staged_section = true;
        g_file_list_widgets.staged_list->external_scroll = true;  // Parent handles scrolling
        g_file_list_widgets.staged_list->on_file_select = on_staged_file_select;
        g_file_list_widgets.staged_list->on_file_action = on_staged_file_action;
        g_file_list_widgets.staged_list->on_file_context_menu = on_staged_file_context_menu;
        // Wire up scroll request to parent container
        g_file_list_widgets.staged_list->on_scroll_request = [](FileList* list, float scroll_y, void* ud) {
            (void)list; (void)ud;
            if (g_file_list_widgets.container) {
                g_file_list_widgets.container->scroll_y = scroll_y;
                g_file_list_widgets.container->set_layout_dirty();
                g_file_list_widgets.container->set_dirty();
            }
        };
    }

    // Create changed section header
    g_file_list_widgets.changed_header = g_widget_arena.create<SectionHeader>();
    if (g_file_list_widgets.changed_header) {
        g_file_list_widgets.changed_header->title = L"CHANGES";
        g_file_list_widgets.changed_header->action_text = L"+All";
        g_file_list_widgets.changed_header->collapsible = true;
        g_file_list_widgets.changed_header->collapsed = g_sidebar.changed_collapsed;
        g_file_list_widgets.changed_header->show_action_on_hover_only = true;
        g_file_list_widgets.changed_header->on_toggle = on_changed_header_toggle;
        g_file_list_widgets.changed_header->on_action = on_changed_header_action;
    }

    // Create changed file list (external scroll mode)
    g_file_list_widgets.changed_list = g_widget_arena.create<FileList>();
    if (g_file_list_widgets.changed_list) {
        g_file_list_widgets.changed_list->is_staged_section = false;
        g_file_list_widgets.changed_list->external_scroll = true;  // Parent handles scrolling
        g_file_list_widgets.changed_list->on_file_select = on_changed_file_select;
        g_file_list_widgets.changed_list->on_file_action = on_changed_file_action;
        g_file_list_widgets.changed_list->on_file_discard = on_changed_file_discard;
        g_file_list_widgets.changed_list->on_file_context_menu = on_changed_file_context_menu;
        // Wire up scroll request to parent container
        g_file_list_widgets.changed_list->on_scroll_request = [](FileList* list, float scroll_y, void* ud) {
            (void)list; (void)ud;
            if (g_file_list_widgets.container) {
                g_file_list_widgets.container->scroll_y = scroll_y;
                g_file_list_widgets.container->set_layout_dirty();
                g_file_list_widgets.container->set_dirty();
            }
        };
    }

    // Create commit view header (hidden by default)
    g_file_list_widgets.commit_header = g_widget_arena.create<CommitViewHeader>();
    if (g_file_list_widgets.commit_header) {
        g_file_list_widgets.commit_header->flags &= ~WidgetFlags::Visible;  // Hidden initially
        g_file_list_widgets.commit_header->on_close = [](CommitViewHeader* header, void* ud) {
            (void)header; (void)ud;
            // Close commit view mode
            g_sidebar.viewing_commit = false;
            g_sidebar.commit_view_file_count = 0;
            g_sidebar.commit_view_selected = -1;
            g_file_list_widgets.show_commit_border = false;
            sidebar_file_list_widgets_update();
            InvalidateRect(g_main_window, nullptr, FALSE);
        };
    }

    // Build widget hierarchy: ScrollContainer -> FlexContainer -> children
    // Note: commit_header is NOT added here - it's added to SidebarWidget directly
    // so it stays outside the ScrollContainer
    if (g_file_list_widgets.flex) {
        if (g_file_list_widgets.staged_header) {
            widget_add_child(g_file_list_widgets.flex, g_file_list_widgets.staged_header);
        }
        if (g_file_list_widgets.staged_list) {
            widget_add_child(g_file_list_widgets.flex, g_file_list_widgets.staged_list);
        }
        if (g_file_list_widgets.changed_header) {
            widget_add_child(g_file_list_widgets.flex, g_file_list_widgets.changed_header);
        }
        if (g_file_list_widgets.changed_list) {
            widget_add_child(g_file_list_widgets.flex, g_file_list_widgets.changed_list);
        }
    }

    if (g_file_list_widgets.container && g_file_list_widgets.flex) {
        widget_add_child(g_file_list_widgets.container, g_file_list_widgets.flex);
    }

    // Set up widget tree for rendering
    g_file_list_tree.root = g_file_list_widgets.container;

    g_file_list_widgets.initialized = true;
}

// Clear file list widget hover states (called from sidebar_clear_hover)
static void sidebar_clear_file_list_widget_hover() {
    if (g_file_list_widgets.initialized) {
        if (g_file_list_widgets.container) {
            g_file_list_widgets.container->on_mouse_leave();
        }
        if (g_file_list_widgets.staged_header) {
            g_file_list_widgets.staged_header->on_mouse_leave();
        }
        if (g_file_list_widgets.staged_list) {
            g_file_list_widgets.staged_list->on_mouse_leave();
        }
        if (g_file_list_widgets.changed_header) {
            g_file_list_widgets.changed_header->on_mouse_leave();
        }
        if (g_file_list_widgets.changed_list) {
            g_file_list_widgets.changed_list->on_mouse_leave();
        }
    }
}

// Update file list widgets from g_sidebar data
// Track commit view state for dirty detection
static bool g_last_viewing_commit = false;
static size_t g_last_commit_view_file_count = 0;

static void sidebar_file_list_widgets_update() {
    LOG_DEBUG(CommitView, "sidebar_file_list_widgets_update() called - viewing_commit=%d", g_sidebar.viewing_commit);
    if (!g_file_list_widgets.initialized) {
        sidebar_file_list_widgets_init();
    }
    if (!g_file_list_widgets.initialized) return;

    // Preserve scroll position from container
    float saved_scroll = 0.0f;
    if (g_file_list_widgets.container) {
        saved_scroll = g_file_list_widgets.container->scroll_y;
    }

    // Handle commit view mode
    if (g_sidebar.viewing_commit) {
        LOG_DEBUG(CommitView, "In commit view mode - updating widgets");
        // Check if we need to rebuild for commit view
        bool commit_view_changed = !g_last_viewing_commit ||
                                   g_last_commit_view_file_count != g_sidebar.commit_view_file_count ||
                                   g_file_list_widgets.files_dirty;

        // Hide staged section and changed_header in commit view
        if (g_file_list_widgets.staged_header) {
            g_file_list_widgets.staged_header->flags &= ~WidgetFlags::Visible;
        }
        if (g_file_list_widgets.staged_list) {
            g_file_list_widgets.staged_list->flags &= ~WidgetFlags::Visible;
        }
        if (g_file_list_widgets.changed_header) {
            g_file_list_widgets.changed_header->flags &= ~WidgetFlags::Visible;
        }

        // Show and update commit view header
        if (g_file_list_widgets.commit_header) {
            if (commit_view_changed) {
                g_file_list_widgets.commit_header->set_commit(
                    g_sidebar.viewing_commit_short,
                    g_sidebar.viewing_commit_author,
                    g_sidebar.viewing_commit_time,
                    g_sidebar.viewing_commit_message,
                    g_sidebar.commit_view_file_count
                );
            }
            g_file_list_widgets.commit_header->flags |= WidgetFlags::Visible;
        }

        // Enable accent border around file list
        g_file_list_widgets.show_commit_border = true;

        // Trigger relayout since visibility changed
        if (g_file_list_widgets.flex) {
            g_file_list_widgets.flex->set_layout_dirty();
        }
        if (g_file_list_widgets.container) {
            g_file_list_widgets.container->set_layout_dirty();
        }

        // Show and populate changed list with commit files
        if (g_file_list_widgets.changed_list) {
            g_file_list_widgets.changed_list->set_collapsed(false);
            g_file_list_widgets.changed_list->hide_action_buttons = true;
            g_file_list_widgets.changed_list->flags |= WidgetFlags::Visible;

            if (commit_view_changed) {
                g_file_list_widgets.changed_list->clear();
                g_file_list_widgets.changed_list->on_file_select = on_commit_view_file_select;
                g_file_list_widgets.changed_list->on_file_action = nullptr;  // No stage/unstage
                g_file_list_widgets.changed_list->on_file_discard = nullptr; // No discard

                for (size_t i = 0; i < g_sidebar.commit_view_file_count; i++) {
                    FileListItem* item = g_file_list_widgets.changed_list->add_item();
                    if (item) {
                        SidebarFile* sf = &g_sidebar.commit_view_files[i];
                        item->set_file(sf->filename, sf->full_path,
                                      convert_file_status(sf->status),
                                      static_cast<int>(i), false,
                                      sf->old_path, sf->similarity);

                        if (g_sidebar.commit_view_selected == static_cast<int>(i)) {
                            item->set_selected(true);
                            g_file_list_widgets.changed_list->selected_index = static_cast<int>(i);
                        }
                    }
                }
            }
        }

        // Reset scroll to top when entering commit view or switching commits
        // Use commit_view_changed (not g_last_viewing_commit) to avoid race condition:
        // - commit_view_changed is true when entering commit view OR switching to different commit
        // - Only preserve scroll when staying on the same commit across render frames
        if (g_file_list_widgets.container) {
            if (commit_view_changed) {
                // Entering commit view or switched to different commit - scroll to top
                g_file_list_widgets.container->scroll_y = 0.0f;
            } else {
                // Same commit, same file count - preserve scroll position
                g_file_list_widgets.container->scroll_y = saved_scroll;
            }
        }

        // Update tracking state
        g_last_viewing_commit = true;
        g_last_commit_view_file_count = g_sidebar.commit_view_file_count;
        g_file_list_widgets.files_dirty = false;
        return;
    }

    // Normal mode - reset from commit view if needed
    if (g_last_viewing_commit) {
        g_last_viewing_commit = false;
        g_file_list_widgets.files_dirty = true;  // Force rebuild when exiting commit view
        g_file_list_widgets.show_commit_border = false;  // Disable accent border

        // Hide commit view header
        if (g_file_list_widgets.commit_header) {
            g_file_list_widgets.commit_header->flags &= ~WidgetFlags::Visible;
        }

        // Show and restore changed header to normal
        if (g_file_list_widgets.changed_header) {
            g_file_list_widgets.changed_header->title = L"CHANGES";
            g_file_list_widgets.changed_header->action_text = L"+All";
            g_file_list_widgets.changed_header->flags |= WidgetFlags::Visible;
            g_file_list_widgets.changed_header->set_dirty();
        }

        // Restore callbacks
        if (g_file_list_widgets.changed_list) {
            g_file_list_widgets.changed_list->hide_action_buttons = false;
            g_file_list_widgets.changed_list->on_file_select = on_changed_file_select;
            g_file_list_widgets.changed_list->on_file_action = on_changed_file_action;
            g_file_list_widgets.changed_list->on_file_discard = on_changed_file_discard;
        }

        // Trigger relayout since visibility will change
        if (g_file_list_widgets.flex) {
            g_file_list_widgets.flex->set_layout_dirty();
        }
        if (g_file_list_widgets.container) {
            g_file_list_widgets.container->set_layout_dirty();
        }
    }

    // Check if file list content has changed (requires full rebuild)
    bool needs_rebuild = g_file_list_widgets.files_dirty ||
                         g_file_list_widgets.last_staged_count != g_sidebar.staged_count ||
                         g_file_list_widgets.last_changed_count != g_sidebar.changed_count;

    // Always update header counts, collapse states, and visibility (cheap operations)

    // Update staged header visibility
    if (g_file_list_widgets.staged_header) {
        g_file_list_widgets.staged_header->set_count(g_sidebar.staged_count);
        g_file_list_widgets.staged_header->set_collapsed(g_sidebar.staged_collapsed);
        // Hide staged header when no staged files
        if (g_sidebar.staged_count > 0) {
            g_file_list_widgets.staged_header->flags |= WidgetFlags::Visible;
        } else {
            g_file_list_widgets.staged_header->flags &= ~WidgetFlags::Visible;
        }
    }

    // Update staged list visibility/collapse
    if (g_file_list_widgets.staged_list) {
        g_file_list_widgets.staged_list->set_collapsed(g_sidebar.staged_collapsed);
        // Hide staged list when no staged files or collapsed
        if (g_sidebar.staged_count > 0 && !g_sidebar.staged_collapsed) {
            g_file_list_widgets.staged_list->flags |= WidgetFlags::Visible;
        } else {
            g_file_list_widgets.staged_list->flags &= ~WidgetFlags::Visible;
        }
    }

    // Update changed header (always visible)
    if (g_file_list_widgets.changed_header) {
        g_file_list_widgets.changed_header->set_count(g_sidebar.changed_count);
        g_file_list_widgets.changed_header->set_collapsed(g_sidebar.changed_collapsed);
        g_file_list_widgets.changed_header->flags |= WidgetFlags::Visible;
    }

    // Update changed list visibility/collapse
    if (g_file_list_widgets.changed_list) {
        g_file_list_widgets.changed_list->set_collapsed(g_sidebar.changed_collapsed);
        // Hide changed list when collapsed
        if (!g_sidebar.changed_collapsed) {
            g_file_list_widgets.changed_list->flags |= WidgetFlags::Visible;
        } else {
            g_file_list_widgets.changed_list->flags &= ~WidgetFlags::Visible;
        }
    }

    // Skip expensive rebuild if file lists haven't changed
    if (!needs_rebuild) {
        // Restore scroll position
        if (g_file_list_widgets.container) {
            g_file_list_widgets.container->scroll_y = saved_scroll;
        }
        return;
    }

    // Clear dirty flag and update tracking
    g_file_list_widgets.files_dirty = false;
    g_file_list_widgets.last_staged_count = g_sidebar.staged_count;
    g_file_list_widgets.last_changed_count = g_sidebar.changed_count;

    // Rebuild staged file list items
    if (g_file_list_widgets.staged_list) {
        g_file_list_widgets.staged_list->clear();

        for (size_t i = 0; i < g_sidebar.staged_count; i++) {
            FileListItem* item = g_file_list_widgets.staged_list->add_item();
            if (item) {
                SidebarFile* sf = &g_sidebar.staged_files[i];
                item->set_file(sf->filename, sf->full_path,
                              convert_file_status(sf->status),
                              static_cast<int>(i), true,
                              sf->old_path, sf->similarity);

                // Set selection state
                if (g_sidebar.selected_is_staged &&
                    g_sidebar.selected_file_index == static_cast<int>(i)) {
                    item->set_selected(true);
                    g_file_list_widgets.staged_list->selected_index = static_cast<int>(i);
                }
            }
        }
    }

    // Rebuild changed file list items
    if (g_file_list_widgets.changed_list) {
        g_file_list_widgets.changed_list->clear();

        for (size_t i = 0; i < g_sidebar.changed_count; i++) {
            FileListItem* item = g_file_list_widgets.changed_list->add_item();
            if (item) {
                SidebarFile* sf = &g_sidebar.changed_files[i];
                item->set_file(sf->filename, sf->full_path,
                              convert_file_status(sf->status),
                              static_cast<int>(i), false,
                              sf->old_path, sf->similarity);

                // Set selection state
                if (!g_sidebar.selected_is_staged &&
                    g_sidebar.selected_file_index == static_cast<int>(i)) {
                    item->set_selected(true);
                    g_file_list_widgets.changed_list->selected_index = static_cast<int>(i);
                }
            }
        }
    }

    // Restore scroll position (will be clamped during layout)
    if (g_file_list_widgets.container) {
        g_file_list_widgets.container->scroll_y = saved_scroll;
    }
}

// Callback implementations
static void on_staged_file_select(FileList* list, int index, void* user_data) {
    (void)list; (void)user_data;

    // Update g_sidebar selection state
    g_sidebar.selected_file_index = index;
    g_sidebar.selected_is_staged = true;

    // Clear selection in changed list
    if (g_file_list_widgets.changed_list) {
        g_file_list_widgets.changed_list->set_selected(-1);
    }

    // Compute diff for the selected file
    diff_viewer_compute_for_file(index, true);

    InvalidateRect(g_main_window, nullptr, FALSE);
}

static void on_staged_file_action(FileList* list, int index, void* user_data) {
    (void)list; (void)user_data;

    // Unstage file
    if (index >= 0 && static_cast<size_t>(index) < g_sidebar.staged_count) {
        char path_utf8[512];
        WideCharToMultiByte(CP_UTF8, 0, g_sidebar.staged_files[index].full_path,
                           -1, path_utf8, sizeof(path_utf8), nullptr, nullptr);

        RepoLockGuard lock;
        if (git_unstage_file(&g_repo, path_utf8)) {
            sidebar_load_status();
            sidebar_file_list_widgets_update();
        }
    }

    InvalidateRect(g_main_window, nullptr, FALSE);
}

static void on_changed_file_select(FileList* list, int index, void* user_data) {
    (void)list; (void)user_data;

    // Update g_sidebar selection state
    g_sidebar.selected_file_index = index;
    g_sidebar.selected_is_staged = false;

    // Clear selection in staged list
    if (g_file_list_widgets.staged_list) {
        g_file_list_widgets.staged_list->set_selected(-1);
    }

    // Compute diff for the selected file
    diff_viewer_compute_for_file(index, false);

    InvalidateRect(g_main_window, nullptr, FALSE);
}

static void on_changed_file_action(FileList* list, int index, void* user_data) {
    (void)list; (void)user_data;

    // Stage file
    if (index >= 0 && static_cast<size_t>(index) < g_sidebar.changed_count) {
        char path_utf8[512];
        WideCharToMultiByte(CP_UTF8, 0, g_sidebar.changed_files[index].full_path,
                           -1, path_utf8, sizeof(path_utf8), nullptr, nullptr);

        RepoLockGuard lock;
        if (git_stage_file(&g_repo, path_utf8)) {
            sidebar_load_status();
            sidebar_file_list_widgets_update();
        }
    }

    InvalidateRect(g_main_window, nullptr, FALSE);
}

static void on_changed_file_discard(FileList* list, int index, void* user_data) {
    (void)list; (void)user_data;

    // Discard changes to file
    if (index >= 0 && static_cast<size_t>(index) < g_sidebar.changed_count) {
        SidebarFile* file = &g_sidebar.changed_files[index];

        // Show confirmation dialog
        wchar_t confirm_msg[512];
        swprintf_s(confirm_msg, L"Discard changes to '%s'?\n\nThis cannot be undone.",
                  file->filename);

        int result = MessageBoxW(g_main_window, confirm_msg, L"Discard Changes",
                                MB_YESNO | MB_ICONWARNING | MB_DEFBUTTON2);

        if (result == IDYES) {
            char path_utf8[512];
            WideCharToMultiByte(CP_UTF8, 0, file->full_path, -1,
                               path_utf8, sizeof(path_utf8), nullptr, nullptr);

            RepoLockGuard lock;
            if (git_discard_file(&g_repo, path_utf8)) {
                sidebar_load_status();
                sidebar_file_list_widgets_update();
            }
        }
    }

    InvalidateRect(g_main_window, nullptr, FALSE);
}

static void on_staged_header_toggle(SectionHeader* header, bool collapsed, void* user_data) {
    (void)header; (void)user_data;
    g_sidebar.staged_collapsed = collapsed;
    if (g_file_list_widgets.staged_list) {
        g_file_list_widgets.staged_list->set_collapsed(collapsed);
    }
    InvalidateRect(g_main_window, nullptr, FALSE);
}

static void on_staged_header_action(SectionHeader* header, void* user_data) {
    (void)header; (void)user_data;

    // Unstage all files (batch operation)
    RepoLockGuard lock;
    if (git_unstage_all(&g_repo)) {
        sidebar_load_status();
    }
    InvalidateRect(g_main_window, nullptr, FALSE);
}

static void on_changed_header_toggle(SectionHeader* header, bool collapsed, void* user_data) {
    (void)header; (void)user_data;
    g_sidebar.changed_collapsed = collapsed;
    if (g_file_list_widgets.changed_list) {
        g_file_list_widgets.changed_list->set_collapsed(collapsed);
    }
    InvalidateRect(g_main_window, nullptr, FALSE);
}

static void on_changed_header_action(SectionHeader* header, void* user_data) {
    (void)header; (void)user_data;

    // In commit view mode, close the commit view
    if (g_sidebar.viewing_commit) {
        g_sidebar.viewing_commit = false;
        g_sidebar.commit_view_file_count = 0;
        g_sidebar.commit_view_selected = -1;
        sidebar_file_list_widgets_update();
        InvalidateRect(g_main_window, nullptr, FALSE);
        return;
    }

    // Stage all files (batch operation)
    RepoLockGuard lock;
    if (git_stage_all(&g_repo)) {
        sidebar_load_status();
    }
    InvalidateRect(g_main_window, nullptr, FALSE);
}

// Commit view file selection callback
static void on_commit_view_file_select(FileList* list, int index, void* user_data) {
    (void)list; (void)user_data;

    g_sidebar.commit_view_selected = index;

    // Clear previous diff
    diff_viewer_clear();

    if (index >= 0 && static_cast<size_t>(index) < g_sidebar.commit_view_file_count) {
        SidebarFile* file = &g_sidebar.commit_view_files[index];

        // Convert wide path to UTF-8
        char path_utf8[Git::MAX_PATH_LEN];
        WideCharToMultiByte(CP_UTF8, 0, file->full_path, -1,
                           path_utf8, sizeof(path_utf8), nullptr, nullptr);

        // Compute diff for this file in the commit
        bool success = false;
        {
            RepoLockGuard lock;
            success = diff_compute_commit(&g_repo, g_sidebar.viewing_commit_sha, path_utf8, &g_diff_viewer.current_diff);
        }

        g_diff_viewer.has_diff = success;

        // Update widget-based diff viewer
        if (success) {
            diff_viewer_widget_set_diff(&g_diff_viewer.current_diff);
        } else {
            diff_viewer_widget_set_diff(nullptr);
        }
    }

    InvalidateRect(g_main_window, nullptr, FALSE);
}

