// ============================================================================
// Sidebar Branch List Widgets (ScrollContainer-based)
// ============================================================================
// Widget-based branch list rendering with unified scroll container
// Fixes scrollbar sticking bug by using widget framework's state management

// Forward declarations for callbacks
static void on_branches_header_action(SectionHeader* header, void* user_data);
static void on_stashes_header_toggle(SectionHeader* header, bool collapsed, void* user_data);
static void on_stash_select(StashList* list, int index, void* user_data);
static void on_stash_apply(StashList* list, int index, void* user_data);

struct SidebarBranchListWidgets {
    ScrollContainer* container = nullptr;   // Unified scroll container
    FlexContainer* flex = nullptr;          // Vertical layout for children
    SectionHeader* branches_header = nullptr;
    BranchTree* branch_tree = nullptr;
    SectionHeader* stashes_header = nullptr;  // Stashes section header
    StashList* stash_list = nullptr;          // Stash list widget
    bool initialized = false;

    // Count tracking for rebuild optimization (dirty flags are global: g_branches_list_dirty, g_stashes_list_dirty)
    size_t last_branch_count = 0;
    size_t last_stash_count = 0;
};

static SidebarBranchListWidgets g_branch_list_widgets = {};
static WidgetTree g_branch_list_tree = {};

// Initialize branch list widgets
static void sidebar_branch_list_widgets_init() {
    if (g_branch_list_widgets.initialized) return;

    // Create unified scroll container
    g_branch_list_widgets.container = g_widget_arena.create<ScrollContainer>();
    if (!g_branch_list_widgets.container) return;
    g_branch_list_widgets.container->show_scrollbar_v = true;
    g_branch_list_widgets.container->show_scrollbar_h = false;

    // Create flex container for vertical stacking
    g_branch_list_widgets.flex = g_widget_arena.create<FlexContainer>();
    if (!g_branch_list_widgets.flex) return;
    g_branch_list_widgets.flex->direction = FlexDirection::Column;
    g_branch_list_widgets.flex->align = FlexAlign::Stretch;
    g_branch_list_widgets.flex->gap = 0.0f;

    // Create branches section header
    g_branch_list_widgets.branches_header = g_widget_arena.create<SectionHeader>();
    if (g_branch_list_widgets.branches_header) {
        g_branch_list_widgets.branches_header->title = L"BRANCHES";
        g_branch_list_widgets.branches_header->action_text = L"+";
        g_branch_list_widgets.branches_header->collapsible = false;  // Branches section not collapsible
        g_branch_list_widgets.branches_header->show_action_on_hover_only = true;
        g_branch_list_widgets.branches_header->on_action = on_branches_header_action;
    }

    // Create branch tree widget (external scroll mode - parent handles scrolling)
    g_branch_list_widgets.branch_tree = g_widget_arena.create<BranchTree>();
    if (g_branch_list_widgets.branch_tree) {
        g_branch_list_widgets.branch_tree->external_scroll = true;
        g_branch_list_widgets.branch_tree->on_folder_toggle = on_branch_folder_toggle;
        g_branch_list_widgets.branch_tree->on_branch_checkout = on_branch_checkout;
        g_branch_list_widgets.branch_tree->on_hover_change = on_branch_hover_change;
        g_branch_list_widgets.branch_tree->on_branch_context_menu = on_branch_context_menu;
        // Wire up scroll request to parent container
        g_branch_list_widgets.branch_tree->on_scroll_request = [](BranchTree* tree, float scroll_y, void* ud) {
            (void)tree; (void)ud;
            if (g_branch_list_widgets.container) {
                g_branch_list_widgets.container->scroll_y = scroll_y;
                g_branch_list_widgets.container->set_layout_dirty();
                g_branch_list_widgets.container->set_dirty();
            }
        };
    }

    // Create stashes section header (collapsible)
    g_branch_list_widgets.stashes_header = g_widget_arena.create<SectionHeader>();
    if (g_branch_list_widgets.stashes_header) {
        g_branch_list_widgets.stashes_header->title = L"STASHES";
        g_branch_list_widgets.stashes_header->collapsible = true;
        g_branch_list_widgets.stashes_header->collapsed = g_sidebar.stashes_collapsed;
        g_branch_list_widgets.stashes_header->show_action_on_hover_only = false;
        g_branch_list_widgets.stashes_header->on_toggle = on_stashes_header_toggle;
    }

    // Create stash list widget (external scroll mode)
    g_branch_list_widgets.stash_list = g_widget_arena.create<StashList>();
    if (g_branch_list_widgets.stash_list) {
        g_branch_list_widgets.stash_list->external_scroll = true;
        g_branch_list_widgets.stash_list->on_stash_select = on_stash_select;
        g_branch_list_widgets.stash_list->on_stash_apply = on_stash_apply;
        g_branch_list_widgets.stash_list->on_stash_context_menu = on_stash_context_menu;
        // Wire up scroll request to parent container
        g_branch_list_widgets.stash_list->on_scroll_request = [](StashList* list, float scroll_y, void* ud) {
            (void)list; (void)ud;
            if (g_branch_list_widgets.container) {
                g_branch_list_widgets.container->scroll_y = scroll_y;
                g_branch_list_widgets.container->set_layout_dirty();
                g_branch_list_widgets.container->set_dirty();
            }
        };
    }

    // Build widget hierarchy: container -> flex -> [branches_header, branch_tree, stashes_header, stash_list]
    if (g_branch_list_widgets.flex) {
        if (g_branch_list_widgets.branches_header) {
            widget_add_child(g_branch_list_widgets.flex, g_branch_list_widgets.branches_header);
        }
        if (g_branch_list_widgets.branch_tree) {
            widget_add_child(g_branch_list_widgets.flex, g_branch_list_widgets.branch_tree);
        }
        if (g_branch_list_widgets.stashes_header) {
            widget_add_child(g_branch_list_widgets.flex, g_branch_list_widgets.stashes_header);
        }
        if (g_branch_list_widgets.stash_list) {
            widget_add_child(g_branch_list_widgets.flex, g_branch_list_widgets.stash_list);
        }
    }

    if (g_branch_list_widgets.container && g_branch_list_widgets.flex) {
        widget_add_child(g_branch_list_widgets.container, g_branch_list_widgets.flex);
    }

    g_branch_list_tree.root = g_branch_list_widgets.container;
    g_branch_list_widgets.initialized = true;

    LOG("Branch list widgets initialized");
}


