// Callback for stash selection
static void on_stash_select(StashList* list, int index, void* user_data) {
    (void)list; (void)user_data;
    g_sidebar.selected_stash_index = index;
    InvalidateRect(g_main_window, nullptr, FALSE);
}

// Callback for stash apply (double-click)
static void on_stash_apply(StashList* list, int index, void* user_data) {
    (void)list; (void)user_data;
    // Apply the stash
    if (index >= 0 && index < static_cast<int>(g_stash_count)) {
        StashApplyOptions options = {};
        StashResult result = {};
        git_stash_apply(&g_repo, index, &options, &result);
        // Refresh status
        sidebar_load_status();
        sidebar_load_stashes();
        InvalidateRect(g_main_window, nullptr, FALSE);
    }
}

// Implementation of StashList::rebuild_from_cache (declared in ui_framework.cpp)
void StashList::rebuild_from_cache() {
    item_count = static_cast<int>(g_stash_count);
    if (item_count > static_cast<int>(MAX_STASH_ITEMS)) {
        item_count = static_cast<int>(MAX_STASH_ITEMS);
    }

    for (int i = 0; i < item_count; i++) {
        item_data[i].index = g_stashes[i].index;

        // Convert message to wide string (truncate if needed)
        wchar_t temp[256];
        MultiByteToWideChar(CP_UTF8, 0, g_stashes[i].message, -1, temp, 256);

        // Truncate to fit display
        if (wcslen(temp) > 50) {
            wcsncpy_s(item_data[i].message, temp, 47);
            wcscat_s(item_data[i].message, L"...");
        } else {
            wcscpy_s(item_data[i].message, temp);
        }
    }

    // Sync selection state
    selected_index = g_sidebar.selected_stash_index;

    set_dirty();
}

