// Callback when sidebar width changes via drag handle (called during drag)
static void on_sidebar_width_changed(SidebarWidget* sidebar, float new_width, void* user_data) {
    (void)user_data;
    (void)sidebar;

    // Keep g_sidebar.width in sync (for code that still uses it)
    g_sidebar.width = new_width;

    // Update setting (but don't save yet - save on drag end)
    g_app_settings.sidebar_width = new_width;

    // Trigger redraw
    if (g_main_window) {
        InvalidateRect(g_main_window, nullptr, FALSE);
    }
}

// Callback when files/branches split ratio changes (called during drag)
static void on_sidebar_split_changed(SidebarWidget* sidebar, float new_ratio, void* user_data) {
    (void)user_data;
    (void)sidebar;

    // Keep g_sidebar.branches_section_split in sync (for code that still uses it)
    g_sidebar.branches_section_split = new_ratio;

    // Update setting (but don't save yet - save on drag end)
    g_app_settings.branch_section_split = new_ratio;

    // Trigger redraw
    if (g_main_window) {
        InvalidateRect(g_main_window, nullptr, FALSE);
    }
}

