// Initialize the unified sidebar widget
static void sidebar_widget_init() {
    if (g_sidebar_widget) return;  // Already initialized

    // Initialize child widget systems first
    sidebar_header_widget_init();
    sidebar_file_list_widgets_init();
    sidebar_branch_list_widgets_init();

    // Create the main sidebar widget
    g_sidebar_widget = g_widget_arena.create<SidebarWidget>();
    if (!g_sidebar_widget) return;

    // Load saved settings
    g_sidebar_widget->sidebar_width = g_app_settings.sidebar_width;
    g_sidebar_widget->split_ratio = g_app_settings.branch_section_split;

    // Keep g_sidebar in sync (for code that still uses it)
    g_sidebar.width = g_app_settings.sidebar_width;
    g_sidebar.branches_section_split = g_app_settings.branch_section_split;

    // Wire up child widgets with proper parent-child relationships
    // Order matters for hit-testing (last added = topmost)
    if (g_sidebar_header_widget && g_sidebar_header_widget->container) {
        g_sidebar_widget->header = g_sidebar_header_widget->container;
        widget_add_child(g_sidebar_widget, g_sidebar_widget->header);
    }

    // Commit header sits between sidebar header and file_scroll (outside scrollviewer)
    if (g_file_list_widgets.commit_header) {
        g_sidebar_widget->commit_header = g_file_list_widgets.commit_header;
        widget_add_child(g_sidebar_widget, g_sidebar_widget->commit_header);
    }

    if (g_file_list_widgets.container) {
        g_sidebar_widget->file_scroll = g_file_list_widgets.container;
        widget_add_child(g_sidebar_widget, g_sidebar_widget->file_scroll);
    }

    // Create split handle
    g_sidebar_widget->split_handle = g_widget_arena.create<SplitHandle>();
    if (g_sidebar_widget->split_handle) {
        g_sidebar_widget->split_handle->on_drag = on_split_handle_drag;
        g_sidebar_widget->split_handle->on_drag_end = on_split_handle_drag_end;
        g_sidebar_widget->split_handle->user_data = g_sidebar_widget;
        widget_add_child(g_sidebar_widget, g_sidebar_widget->split_handle);
    }

    if (g_branch_list_widgets.container) {
        g_sidebar_widget->branch_scroll = g_branch_list_widgets.container;
        widget_add_child(g_sidebar_widget, g_sidebar_widget->branch_scroll);
    }

    // Create drag handle (last so it's topmost for hit-testing)
    g_sidebar_widget->drag_handle = g_widget_arena.create<DragHandle>();
    if (g_sidebar_widget->drag_handle) {
        g_sidebar_widget->drag_handle->on_drag = on_drag_handle_drag;
        g_sidebar_widget->drag_handle->on_drag_end = on_drag_handle_drag_end;
        g_sidebar_widget->drag_handle->user_data = g_sidebar_widget;
        widget_add_child(g_sidebar_widget, g_sidebar_widget->drag_handle);
    }

    // Wire up callbacks for persistence
    g_sidebar_widget->on_width_changed = on_sidebar_width_changed;
    g_sidebar_widget->on_split_changed = on_sidebar_split_changed;

    // Set up widget tree
    g_sidebar_tree.root = g_sidebar_widget;

    // Set up sidebar event dispatcher
    g_sidebar_dispatcher.root = g_sidebar_widget;
}

// Update sidebar widget data before render
static void sidebar_widget_update() {
    if (!g_sidebar_widget) {
        sidebar_widget_init();
    }
    if (!g_sidebar_widget) return;

    // Update child widget data
    sidebar_file_list_widgets_update();

    // Update branch list content (only rebuild if dirty or count changed)
    bool branches_need_rebuild =
        g_branches_list_dirty ||
        g_branch_list_widgets.last_branch_count != g_sidebar.branch_count;

    if (branches_need_rebuild && g_branch_list_widgets.branch_tree) {
        g_branch_list_widgets.branch_tree->rebuild_from_state();
        g_branches_list_dirty = false;
        g_branch_list_widgets.last_branch_count = g_sidebar.branch_count;
    }

    bool stashes_need_rebuild =
        g_stashes_list_dirty ||
        g_branch_list_widgets.last_stash_count != g_stash_count;

    if (stashes_need_rebuild && g_branch_list_widgets.stash_list) {
        g_branch_list_widgets.stash_list->rebuild_from_cache();
        g_stashes_list_dirty = false;
        g_branch_list_widgets.last_stash_count = g_stash_count;
    }

    // Update header
    if (g_sidebar_header_widget) {
        g_sidebar_header_widget->update();
    }

    // Sync commit view border state to sidebar widget
    g_sidebar_widget->show_file_border = g_file_list_widgets.show_commit_border;
}

// Render the sidebar using widget system
static void sidebar_widget_render(ID2D1SolidColorBrush* brush) {
    if (!g_sidebar_widget || !g_render_target) return;

    // Update widget data
    sidebar_widget_update();

    // Calculate layout constraints
    float height = g_render_target->GetSize().height;
    float content_top = Config::TITLE_BAR_HEIGHT;
    float content_bottom = height - StatusBar::HEIGHT;

    LayoutConstraints constraints = {};
    constraints.max_width = g_sidebar_widget->sidebar_width;
    constraints.max_height = content_bottom - content_top;

    // Position and size the widget
    g_sidebar_widget->rect.x = 0;
    g_sidebar_widget->rect.y = content_top;
    g_sidebar_widget->rect.width = g_sidebar_widget->sidebar_width;
    g_sidebar_widget->rect.height = constraints.max_height;

    // Measure and layout
    LayoutEngine::measure_tree(g_sidebar_widget, constraints);
    LayoutEngine::layout_tree(g_sidebar_widget);

    // Render using widget tree
    g_sidebar_tree.render(g_render_target);

    // Tooltip (on top of everything)
    if (g_tooltip.visible) {
        render_tooltip(brush);
    }
}

