static void commit_history_widget_init() {
    if (g_commit_history_widget) return;  // Already initialized

    LOG("Initializing CommitHistoryPanelWidget...");

    // Create the panel widget
    g_commit_history_widget = g_widget_arena.create<CommitHistoryPanelWidget>();
    if (!g_commit_history_widget) {
        LOG("ERROR: Failed to create commit history widget");
        return;
    }
    g_commit_history_widget->flags |= WidgetFlags::Visible | WidgetFlags::Enabled;

    // Initialize the panel (creates header + scroll container + list)
    g_commit_history_widget->init(g_widget_arena);

    // Set up selection callback to sync with global state
    g_commit_history_widget->on_selection_changed = [](CommitHistoryPanelWidget* panel, int index, void* ud) {
        (void)panel; (void)ud;
        g_commit_history.selected_index = index;
        // Load commit details when selected
        if (index >= 0 && static_cast<size_t>(index) < g_commit_history.history.commit_count) {
            commit_history_load_details(static_cast<size_t>(index));
            // Update sidebar to show commit view
            sidebar_file_list_widgets_update();
            InvalidateRect(g_main_window, nullptr, FALSE);
        }
    };

    // Set up search callback to filter commit history
    g_commit_history_widget->on_search_changed = [](CommitHistoryPanelWidget* panel, const wchar_t* query, void* ud) {
        (void)panel; (void)ud;
        // Copy query to global state
        if (query) {
            wcsncpy_s(g_commit_history.search_query, query, _TRUNCATE);
        } else {
            g_commit_history.search_query[0] = L'\0';
        }
        // Update filter
        update_history_filter();
        InvalidateRect(g_main_window, nullptr, FALSE);
    };

    // Set up context menu callback for commit list
    if (g_commit_history_widget->list) {
        g_commit_history_widget->list->on_context_menu = on_commit_context_menu;
    }

    // Set up main content dispatcher for focus management
    g_main_content_dispatcher.root = g_commit_history_widget;

    // Phase 25: Create split handle widget for diff/history divider
    g_commit_history_split = g_widget_arena.create<SplitHandle>();
    if (g_commit_history_split) {
        g_commit_history_split->on_drag = [](SplitHandle*, float delta_y, void*) {
            float height = g_render_target ? g_render_target->GetSize().height : 0;
            float content_height = height - Config::TITLE_BAR_HEIGHT - StatusBar::HEIGHT;
            if (content_height > 0) {
                float delta_ratio = delta_y / content_height;
                float new_ratio = g_commit_history.split_ratio + delta_ratio;
                new_ratio = fmaxf(CommitHistory::SPLIT_MIN_RATIO, fminf(CommitHistory::SPLIT_MAX_RATIO, new_ratio));
                if (g_commit_history.split_ratio != new_ratio) {
                    g_commit_history.split_ratio = new_ratio;
                    InvalidateRect(g_main_window, nullptr, FALSE);
                }
            }
        };
    }

    LOG("CommitHistoryPanelWidget initialized successfully");
}

// Set history data for the widget
static void commit_history_widget_set_history(const GitHistory* history) {
    if (!g_commit_history_widget) {
        commit_history_widget_init();
    }
    if (!g_commit_history_widget) return;

    g_commit_history_widget->set_history(history);
}

// Render the commit history widget
static void commit_history_widget_render(float x, float y, float width, float height) {
    // Widget initialization is handled by commit_history_widget_set_history()
    if (!g_commit_history_widget || !g_render_target) return;

    // Position the panel
    g_commit_history_widget->rect.x = x;
    g_commit_history_widget->rect.y = y;
    g_commit_history_widget->rect.width = width;
    g_commit_history_widget->rect.height = height;

    // Measure and layout
    LayoutConstraints constraints = {};
    constraints.max_width = width;
    constraints.max_height = height;
    LayoutEngine::measure_tree(g_commit_history_widget, constraints);
    LayoutEngine::layout_tree(g_commit_history_widget);

    // Create cached brush if needed
    if (!g_commit_history_brush && g_render_target) {
        g_render_target->CreateSolidColorBrush(D2D1::ColorF(D2D1::ColorF::White), &g_commit_history_brush);
    }
    if (!g_commit_history_brush) return;

    RenderContext ctx = {};
    ctx.target = g_render_target;
    ctx.brush = g_commit_history_brush;
    g_commit_history_widget->render(ctx);
}

// Handle mouse events for commit history widget (now via dispatcher)
static bool commit_history_widget_handle_mouse_down(float x, float y, int button) {
    if (!g_commit_history_widget) return false;
    // Clear sidebar focus when clicking in main content area
    g_sidebar_dispatcher.set_focus(nullptr);
    g_sidebar.commit_box_focused = false;
    return g_main_content_dispatcher.dispatch_mouse_down(x, y, button);
}

static bool commit_history_widget_handle_mouse_up(float x, float y, int button) {
    if (!g_commit_history_widget) return false;
    return g_main_content_dispatcher.dispatch_mouse_up(x, y, button);
}

static bool commit_history_widget_handle_mouse_move(float x, float y) {
    if (!g_commit_history_widget) return false;
    return g_main_content_dispatcher.dispatch_mouse_move(x, y);
}

static bool commit_history_widget_handle_mouse_wheel(float x, float y, float delta) {
    if (!g_commit_history_widget) return false;

    float rel_x = x - g_commit_history_widget->rect.x;
    float rel_y = y - g_commit_history_widget->rect.y;

    return g_commit_history_widget->on_mouse_wheel(rel_x, rel_y, delta);
}

static bool commit_history_widget_handle_mouse_leave() {
    if (!g_commit_history_widget) return false;
    return g_commit_history_widget->on_mouse_leave();
}

// Check if point is inside commit history bounds
static bool commit_history_widget_hit_test(float x, float y) {
    if (!g_commit_history_widget) return false;
    return g_commit_history_widget->rect.contains(x, y);
}

