// Recursively tick a widget and its children
static void tick_widget_tree(Widget* widget, float dt) {
    if (!widget || !widget->is_visible()) return;
    widget->tick(dt);
    for (Widget* child = widget->first_child; child; child = child->next_sibling) {
        tick_widget_tree(child, dt);
    }
}

// Tick all widget trees and standalone widgets for animation updates
static void tick_all_animations(float dt) {
    // Tick all widget trees
    g_sidebar_tree.tick(dt);
    tick_branch_dialog_tree(dt);
    tick_branch_rename_dialog_tree(dt);
    tick_tag_dialog_tree(dt);
    tick_auth_dialog_tree(dt);
    tick_oauth_dialog_tree(dt);
    tick_stash_dialog_tree(dt);
    tick_clone_dialog_tree(dt);
    #ifdef GITSMARTER_DEBUG
    tick_debug_test_dialog_tree(dt);
    #endif
    g_status_bar_tree.tick(dt);
    g_sidebar_header_tree.tick(dt);
    g_file_list_tree.tick(dt);
    g_branch_tree_widget_tree.tick(dt);
    g_branch_list_tree.tick(dt);

    // Tick standalone widgets (not in WidgetTrees)
    tick_widget_tree(g_diff_scroll_container, dt);
    tick_widget_tree(g_commit_history_widget, dt);

    // Tick context menu and submenus
    for (ContextMenuWidget* menu = g_active_context_menu;
         menu && menu->visible;
         menu = menu->active_submenu) {
        menu->tick(dt);
    }

    // Tick command palette animation
    command_palette_tick(dt);
}

#ifdef GITSMARTER_DEBUG
// Debug overlay showing frame statistics (F3 to toggle)
static void render_debug_overlay(ID2D1SolidColorBrush* brush) {
    if (!g_show_debug_overlay) return;

    g_frame_stats.update_from_scheduler();

    // Position in top-right corner, below title bar
    float panel_width = 160.0f;
    float panel_height = 110.0f;
    float window_width = g_render_target->GetSize().width;
    float x = window_width - panel_width - 8.0f;
    float y = static_cast<float>(Config::TITLE_BAR_HEIGHT) + 8.0f;
    float line_height = 16.0f;
    float padding = 8.0f;

    // Semi-transparent background panel
    D2D1_ROUNDED_RECT bg_rect = D2D1::RoundedRect(
        D2D1::RectF(x, y, x + panel_width, y + panel_height), 4.0f, 4.0f);
    brush->SetColor(D2D1::ColorF(0x000000, 0.85f));
    g_render_target->FillRoundedRectangle(bg_rect, brush);
    brush->SetColor(D2D1::ColorF(0x333333, 1.0f));
    g_render_target->DrawRoundedRectangle(bg_rect, brush, 1.0f);

    // Text rendering
    float text_x = x + padding;
    float text_y = y + padding;
    wchar_t buf[64];

    // Helper to draw label:value pairs with color coding
    auto draw_stat = [&](const wchar_t* label, const wchar_t* value, UINT32 value_color) {
        D2D1_RECT_F label_rect = D2D1::RectF(text_x, text_y, x + 70.0f, text_y + line_height);
        D2D1_RECT_F value_rect = D2D1::RectF(x + 70.0f, text_y, x + panel_width - padding, text_y + line_height);

        brush->SetColor(D2D1::ColorF(0x888888));
        g_render_target->DrawText(label, (UINT32)wcslen(label), g_text_format_mono, label_rect, brush);
        brush->SetColor(D2D1::ColorF(value_color));
        g_render_target->DrawText(value, (UINT32)wcslen(value), g_text_format_mono, value_rect, brush);
        text_y += line_height;
    };

    // FPS (green if smooth, yellow if low, red if very low)
    swprintf(buf, _countof(buf), L"%.1f", g_frame_stats.fps);
    UINT32 fps_color = g_frame_stats.fps >= 55.0f ? 0x00FF00 :
                       g_frame_stats.fps >= 30.0f ? 0xFFFF00 : 0xFF4444;
    draw_stat(L"FPS:", buf, fps_color);

    // Frame time
    swprintf(buf, _countof(buf), L"%.2f ms", g_frame_stats.frame_time_ms);
    draw_stat(L"Frame:", buf, 0x00FF00);

    // Average frame time
    swprintf(buf, _countof(buf), L"%.2f ms", g_frame_stats.avg_frame_time_ms);
    draw_stat(L"Avg:", buf, 0x00FF00);

    // Monitor refresh rate
    swprintf(buf, _countof(buf), L"%.0f Hz", g_frame_stats.refresh_rate_hz);
    draw_stat(L"Monitor:", buf, 0x00AAFF);

    // Active animations (highlight when animating)
    swprintf(buf, _countof(buf), L"%d", g_frame_stats.active_animations);
    UINT32 anim_color = g_frame_stats.active_animations > 0 ? 0x00FF00 : 0x666666;
    draw_stat(L"Anims:", buf, anim_color);

    // VSync status
    const wchar_t* vsync_status = g_frame_stats.active_animations > 0 ? L"Active" : L"Idle";
    draw_stat(L"VSync:", vsync_status, g_frame_stats.active_animations > 0 ? 0x00FF00 : 0x666666);
}
#endif

// Render a frame
static void render_frame() {
    if (!g_render_target) return;

    // === Frame-driven animation: Calculate real delta time ===
    float dt = g_frame_clock.update();

#ifdef GITSMARTER_DEBUG
    g_frame_stats.record_frame(dt);
#endif

    // === Tick all animations BEFORE rendering ===
    // Always tick on repaint so animations can start (register with scheduler).
    // The tick functions are cheap when nothing is animating.
    tick_all_animations(dt);

    g_render_target->BeginDraw();
    g_render_target->Clear(color_from_argb(Theme::BG_PRIMARY));

    float width = g_render_target->GetSize().width;

    ID2D1SolidColorBrush* brush = nullptr;
    g_render_target->CreateSolidColorBrush(color_from_argb(Theme::TEXT_PRIMARY), &brush);
    if (brush) {
        // Draw title bar (widget-based)
        title_bar_render(brush, width);

        // Draw screen content based on current screen
        if (g_current_screen == AppScreen::Welcome) {
            welcome_screen_render(brush);
        } else {
            render_sidebar(brush);

            // Calculate diff viewer position
            float content_width = g_render_target->GetSize().width;
            float content_height = g_render_target->GetSize().height;
            float total_content_top = Config::TITLE_BAR_HEIGHT;
            float total_content_bottom = content_height - StatusBar::HEIGHT;
            float total_content_height = total_content_bottom - total_content_top;
            float diff_content_height = total_content_height * g_commit_history.split_ratio;

            // Use new widget-based diff viewer (Phase 18)
            diff_viewer_widget_render(
                g_sidebar.width,
                total_content_top,
                content_width - g_sidebar.width,
                diff_content_height
            );

            // Draw split handle between diff and history (Phase 25: widget-based)
            float split_y = total_content_top + diff_content_height;
            if (g_commit_history_split) {
                g_commit_history_split->rect = { g_sidebar.width, split_y, content_width - g_sidebar.width, CommitHistory::SPLIT_HANDLE_HEIGHT };
                RenderContext split_ctx = { g_render_target, brush };
                g_commit_history_split->render(split_ctx);
            }

            // Use new widget-based commit history (Phase 19)
            float history_top = split_y + CommitHistory::SPLIT_HANDLE_HEIGHT;
            float history_height = total_content_bottom - history_top;
            commit_history_widget_render(
                g_sidebar.width,
                history_top,
                content_width - g_sidebar.width,
                history_height
            );

            status_bar_widget_render(brush);

            // Render context menu on top of repository content (if visible)
            RenderContext ctx = { g_render_target, brush };
            context_menu_render(ctx);
        }

        // Render dialog widgets on top of everything (if active)
        dialog_widgets_render();

        // Render UI framework test dialog (debug, F12 to toggle)
        ui_framework_test_render();

        // Render command palette on top of everything
        command_palette_render();

#ifdef GITSMARTER_DEBUG
        // Debug overlay renders on top of everything (F3 to toggle)
        render_debug_overlay(brush);
#endif

        brush->Release();
    }

    HRESULT hr = g_render_target->EndDraw();
    if (hr == D2DERR_RECREATE_TARGET) {
        // Release device-dependent resources before recreating target
        release_d2d_device_resources();
        g_render_target->Release();
        g_render_target = nullptr;
        d2d_init(g_main_window);
    }

    // Request another frame if animations are active (self-driving render loop)
    if (g_animation_scheduler.needs_continuous_render()) {
        InvalidateRect(g_main_window, nullptr, FALSE);
    }
}

// Hit testing for custom title bar
static LRESULT handle_nchittest(HWND hwnd, LPARAM lParam) {
    POINT pt = { GET_X_LPARAM(lParam), GET_Y_LPARAM(lParam) };
    ScreenToClient(hwnd, &pt);

    RECT rc;
    GetClientRect(hwnd, &rc);

    const int border = Config::RESIZE_BORDER;

    // Check resize borders first
    bool top = pt.y < border;
    bool bottom = pt.y > rc.bottom - border;
    bool left = pt.x < border;
    bool right = pt.x > rc.right - border;

    if (top && left) return HTTOPLEFT;
    if (top && right) return HTTOPRIGHT;
    if (bottom && left) return HTBOTTOMLEFT;
    if (bottom && right) return HTBOTTOMRIGHT;
    if (top) return HTTOP;
    if (bottom) return HTBOTTOM;
    if (left) return HTLEFT;
    if (right) return HTRIGHT;

    // Title bar area (for dragging)
    if (pt.y < static_cast<int>(Config::TITLE_BAR_HEIGHT)) {
        // Check if over the draggable caption area (not buttons)
        if (title_bar_is_over_caption(static_cast<float>(pt.x), static_cast<float>(pt.y))) {
            return HTCAPTION;
        }
        return HTCLIENT;
    }

    return HTCLIENT;
}

// WM_CREATE handler
static LRESULT handle_wm_create(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)wParam; (void)lParam;
    if (!d2d_init(hwnd)) {
        return -1;  // Fail window creation
    }
    apply_dwm_effects(hwnd);

    // Load recent repositories (settings_init already called in app_run)
    settings_load_recent_repos(g_welcome.recent_repos, &g_welcome.recent_count,
                               Welcome::MAX_RECENT_REPOS);

    // Initialize welcome screen widget and populate recent repos
    welcome_screen_init();
    welcome_screen_populate_recent();

    // Initialize title bar widget
    title_bar_init();

    // Clean up stale fetch state files (older than 7 days)
    fetch_state_cleanup_stale(7);

    // Initialize frame-driven animation system
    g_frame_clock.init();
    g_animation_scheduler.init(hwnd);
    return 0;
}

// WM_DESTROY handler
static LRESULT handle_wm_destroy(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)wParam; (void)lParam;
    // Cancel close animation if interrupted (ensures balanced scheduler accounting)
    g_close_anim.cancel();
    KillTimer(hwnd, BACKGROUND_SYNC_TIMER_ID);
    KillTimer(hwnd, 9);
    // Note: Window placement is saved in start_close_animation() before scaling
    file_watcher_stop();
    platform_cleanup();
    PostQuitMessage(0);
    return 0;
}

// WM_TIMER handler
static LRESULT handle_wm_timer(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)lParam;
    if (wParam == ERROR_FADE_TIMER_ID) {
        // Decrement error timer - update widget state
        if (g_welcome_screen) {
            g_welcome_screen->update_error_animation(ERROR_FADE_INTERVAL_MS / 1000.0f);
            if (g_welcome_screen->error_timer <= 0.0f) {
                KillTimer(hwnd, ERROR_FADE_TIMER_ID);
            }
        } else {
            // Fallback to old state
            g_welcome.error_timer -= ERROR_FADE_INTERVAL_MS / 1000.0f;
            if (g_welcome.error_timer <= 0.0f) {
                g_welcome.error_timer = 0.0f;
                g_welcome.error_message[0] = L'\0';
                KillTimer(hwnd, ERROR_FADE_TIMER_ID);
            }
        }
        InvalidateRect(hwnd, nullptr, FALSE);
        return 0;
    }
    if (wParam == TOOLTIP_ANIM_TIMER_ID) {
        // Animate tooltip opacity - update widget state
        float delta = TOOLTIP_ANIM_INTERVAL_MS / 1000.0f;
        if (g_welcome_screen) {
            g_welcome_screen->update_tooltip_animation(delta);
            // Kill timer when animation complete
            if ((g_welcome_screen->tooltip_visible && g_welcome_screen->tooltip_opacity >= 1.0f) ||
                (!g_welcome_screen->tooltip_visible && g_welcome_screen->tooltip_opacity <= 0.0f)) {
                KillTimer(hwnd, TOOLTIP_ANIM_TIMER_ID);
            }
        } else {
            // Fallback to old state
            float anim_delta = TOOLTIP_FADE_SPEED * delta;
            if (g_welcome.tooltip_visible) {
                g_welcome.tooltip_opacity += anim_delta;
                if (g_welcome.tooltip_opacity >= 1.0f) {
                    g_welcome.tooltip_opacity = 1.0f;
                    KillTimer(hwnd, TOOLTIP_ANIM_TIMER_ID);
                }
            } else {
                g_welcome.tooltip_opacity -= anim_delta;
                if (g_welcome.tooltip_opacity <= 0.0f) {
                    g_welcome.tooltip_opacity = 0.0f;
                    KillTimer(hwnd, TOOLTIP_ANIM_TIMER_ID);
                }
            }
        }
        InvalidateRect(hwnd, nullptr, FALSE);
        return 0;
    }
    if (wParam == FETCH_PROGRESS_TIMER_ID || wParam == PUSH_PROGRESS_TIMER_ID ||
        wParam == PULL_PROGRESS_TIMER_ID || wParam == CHECKOUT_PROGRESS_TIMER_ID ||
        wParam == CLONE_PROGRESS_TIMER_ID) {
        // Update progress UI - trigger a repaint to show status bar updates
        if (wParam == CLONE_PROGRESS_TIMER_ID) {
            // Update clone dialog progress (on Welcome screen, status bar isn't visible)
            clone_dialog_update_progress();
        }
        InvalidateRect(hwnd, nullptr, FALSE);
        return 0;
    }
    if (wParam == BACKGROUND_SYNC_TIMER_ID) {
        // Background sync: silently fetch and update ahead/behind status
        // Only start fetch if not already in progress
        bool repo_valid;
        {
            RepoLockGuard lock;
            repo_valid = g_repo.is_valid;
        }
        if (repo_valid && worker_get_job_type() == WorkerJobType::None) {
            // Start a quiet background fetch (QuickSync mode - current branch only)
            worker_start_async_fetch("origin", true);  // silent=true for background sync
        }
        return 0;
    }
    if (wParam == OAUTH_COUNTDOWN_TIMER_ID) {
        // OAuth countdown - decrement remaining time (widget-based dialog)
        oauth_dialog_handle_timer();
        return 0;
    }
    if (wParam == EDITOR_COALESCE_TIMER_ID) {
        // Code editor undo coalescing timer expired
        CodeEditor::editor_handle_coalesce_timer();
        return 0;
    }
    if (wParam == 9) {
        // File change debounce complete - refresh status now
        KillTimer(hwnd, 9);
        bool repo_valid;
        {
            RepoLockGuard lock;
            repo_valid = g_repo.is_valid;
        }
        if (repo_valid) {
            LOG("[FileWatcher] Refreshing after file changes");
            RepoLockGuard lock;

            // Save currently selected file path before reload (indices may change)
            wchar_t selected_path[512] = {};
            bool had_selection = false;
            bool was_staged = g_sidebar.selected_is_staged;
            if (g_sidebar.selected_file_index >= 0) {
                if (was_staged && static_cast<size_t>(g_sidebar.selected_file_index) < g_sidebar.staged_count) {
                    wcscpy_s(selected_path, g_sidebar.staged_files[g_sidebar.selected_file_index].full_path);
                    had_selection = true;
                } else if (!was_staged && static_cast<size_t>(g_sidebar.selected_file_index) < g_sidebar.changed_count) {
                    wcscpy_s(selected_path, g_sidebar.changed_files[g_sidebar.selected_file_index].full_path);
                    had_selection = true;
                }
            }

            // Re-read HEAD in case of external commit
            git_read_head(&g_repo);

            // Reload file status
            sidebar_load_status();

            // Reload stashes (in case refs/stash changed externally)
            sidebar_load_stashes();

            // Reload commit history in case of external commit
            commit_history_load();

            // Restore selection and refresh diff if file still exists
            if (had_selection && selected_path[0] != L'\0') {
                // Find the file by path in the new lists
                int new_index = -1;
                bool found_staged = false;

                // Check staged files first if it was staged
                if (was_staged) {
                    for (size_t i = 0; i < g_sidebar.staged_count; i++) {
                        if (wcscmp(g_sidebar.staged_files[i].full_path, selected_path) == 0) {
                            new_index = static_cast<int>(i);
                            found_staged = true;
                            break;
                        }
                    }
                }

                // If not found in staged (or wasn't staged), check changed files
                if (new_index < 0) {
                    for (size_t i = 0; i < g_sidebar.changed_count; i++) {
                        if (wcscmp(g_sidebar.changed_files[i].full_path, selected_path) == 0) {
                            new_index = static_cast<int>(i);
                            found_staged = false;
                            break;
                        }
                    }
                }

                if (new_index >= 0) {
                    // File still exists - update selection and refresh diff
                    g_sidebar.selected_file_index = new_index;
                    g_sidebar.selected_is_staged = found_staged;
                    diff_viewer_compute_for_file(new_index, found_staged);
                } else {
                    // File no longer in lists (fully staged, committed, or reverted)
                    g_sidebar.selected_file_index = -1;
                    diff_viewer_clear();
                }
            }

            // Update branch display name
            if (g_repo.head_detached) {
                wchar_t sha_wide[16];
                MultiByteToWideChar(CP_UTF8, 0, g_repo.head_sha, 7, sha_wide, 16);
                sha_wide[7] = L'\0';
                swprintf_s(g_sidebar.current_branch_name, L"HEAD (%s...)", sha_wide);
            } else {
                MultiByteToWideChar(CP_UTF8, 0, g_repo.head_ref, -1,
                                   g_sidebar.current_branch_name, 256);
            }

            // Update status bar branch name
            MultiByteToWideChar(CP_UTF8, 0, g_repo.head_ref, -1,
                               g_status_bar.branch_name, 256);

            InvalidateRect(hwnd, nullptr, FALSE);
        }
        return 0;
    }
    return 0;  // Not handled - DefWindowProc also returns 0 for WM_TIMER
}

// WM_FETCH_COMPLETE handler
static LRESULT handle_wm_fetch_complete(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)wParam; (void)lParam;
    // Get result from worker API
    const FetchResult* result_ptr = worker_get_fetch_result();
    FetchResult result = *result_ptr;  // Copy result struct

    // NOTE: silent flag and remote_name are not exposed via API
    // For now, we'll determine if silent based on whether progress timer was running
    // A proper fix would be to add these to the worker API
    bool silent = false;  // TODO: Get from worker state

    char remote_name[64] = "origin";  // TODO: Get from worker state

    // Stop progress timer
    KillTimer(hwnd, FETCH_PROGRESS_TIMER_ID);

    bool success = (wParam != 0);

    if (success) {
        // Show message only for manual fetches
        if (!silent) {
            wchar_t msg[512];
            swprintf_s(msg, L"Fetch successful!\n\nRefs updated: %zu\nObjects received: %zu\nBytes received: %llu\nDuration: %lld ms",
                       result.refs_updated, result.objects_received,
                       result.bytes_received, result.duration_ms);
            MessageBoxW(hwnd, msg, L"Fetch Complete", MB_OK | MB_ICONINFORMATION);
        }

        // Refresh status and HEAD
        {
            RepoLockGuard lock;
            git_read_head(&g_repo);
            sidebar_load_status();
            status_bar_update_fetch_time();

            // Calculate ahead/behind status
            git_sync_status(&g_repo, remote_name, &g_status_bar.sync_status);

            // Delete any saved fetch state (successful completion)
            fetch_state_delete(g_repo.path);
        }
    } else {
        LOG("WM_FETCH_COMPLETE - Fetch failed: %s", result.error_message);

        // Check if authentication is required
        if (strstr(result.error_message, "Authentication") || strstr(result.error_message, "authentication")) {
            LOG("WM_FETCH_COMPLETE - Authentication error detected, triggering auth dialog");

            // Extract host from remote URL
            char host[256];
            {
                RepoLockGuard lock;
                if (extract_host_from_remote(&g_repo, remote_name, host, sizeof(host))) {
                    LOG("WM_FETCH_COMPLETE - Extracted host: %s", host);

                    // Save pending operation for retry after auth
                    g_pending_operation.type = PendingOpType::Fetch;
                    strncpy_s(g_pending_operation.remote_name, remote_name, sizeof(g_pending_operation.remote_name) - 1);
                    g_pending_operation.silent = silent;

                    LOG("WM_FETCH_COMPLETE - Showing auth dialog for host: %s", host);

                    // Choose authentication method based on host
                    if (is_github_host(host)) {
                        // GitHub uses OAuth Device Flow
                        LOG("WM_FETCH_COMPLETE - Using OAuth for GitHub");
                        if (!start_oauth_flow(host)) {
                            // OAuth failed to start, fall back to username/password
                            LOG("WM_FETCH_COMPLETE - OAuth failed, falling back to username/password");
                            show_auth_dialog(host);
                        }
                    } else {
                        // All other hosts use username/password
                        show_auth_dialog(host);
                    }
                } else {
                    LOG("WM_FETCH_COMPLETE - Failed to extract host from remote URL");

                    // Couldn't extract host, show error
                    if (!silent) {
                        wchar_t msg[512];
                        wchar_t error_wide[256];
                        MultiByteToWideChar(CP_UTF8, 0, result.error_message, -1, error_wide, 256);
                        swprintf_s(msg, L"Fetch failed:\n%s", error_wide);
                        MessageBoxW(hwnd, msg, L"Fetch Error", MB_OK | MB_ICONERROR);
                    }
                }
            }
        } else {
            // Show error only for manual fetches
            if (!silent) {
                wchar_t msg[512];
                wchar_t error_wide[256];
                MultiByteToWideChar(CP_UTF8, 0, result.error_message, -1, error_wide, 256);
                swprintf_s(msg, L"Fetch failed:\n%s", error_wide);
                MessageBoxW(hwnd, msg, L"Fetch Error", MB_OK | MB_ICONERROR);
            }
        }
    }

    InvalidateRect(hwnd, nullptr, FALSE);
    return 0;
}

// WM_PUSH_COMPLETE handler
static LRESULT handle_wm_push_complete(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)wParam; (void)lParam;
    // Get result from worker API
    const PushResult* push_result_ptr = worker_get_push_result();
    PushResult push_result = *push_result_ptr;  // Copy result struct

    char remote_name[64] = "origin";  // TODO: Get from worker state

    // Stop progress timer
    KillTimer(hwnd, PUSH_PROGRESS_TIMER_ID);

    bool success = (wParam != 0);

    if (success) {
        wchar_t msg[512];
        swprintf_s(msg, L"Push successful!\n\nObjects sent: %zu\nBytes sent: %llu\nDuration: %lld ms",
                   push_result.objects_sent,
                   push_result.bytes_sent,
                   push_result.duration_ms);
        MessageBoxW(hwnd, msg, L"Push Complete", MB_OK | MB_ICONINFORMATION);

        // Refresh sync status (now 0 ahead)
        {
            RepoLockGuard lock;
            git_sync_status(&g_repo, remote_name, &g_status_bar.sync_status);
        }
    } else {
        // Check if authentication is required
        if (strstr(push_result.error_message, "Authentication") || strstr(push_result.error_message, "authentication")) {
            // Extract host from remote URL
            char host[256];
            char ref_name[128];
            {
                RepoLockGuard lock;
                // Get current branch ref name for retry
                if (g_repo.head_detached) {
                    ref_name[0] = '\0';  // Can't push detached HEAD
                } else {
                    strncpy_s(ref_name, sizeof(ref_name), g_repo.head_ref, sizeof(ref_name) - 1);
                }

                if (extract_host_from_remote(&g_repo, remote_name, host, sizeof(host))) {
                    // Save pending operation for retry after auth
                    g_pending_operation.type = PendingOpType::Push;
                    strncpy_s(g_pending_operation.remote_name, remote_name, sizeof(g_pending_operation.remote_name) - 1);
                    strncpy_s(g_pending_operation.ref_name, ref_name, sizeof(g_pending_operation.ref_name) - 1);

                    // Choose authentication method based on host
                    if (is_github_host(host)) {
                        // GitHub uses OAuth Device Flow
                        if (!start_oauth_flow(host)) {
                            show_auth_dialog(host);
                        }
                    } else {
                        show_auth_dialog(host);
                    }
                } else {
                    // Couldn't extract host, show error
                    wchar_t msg[512];
                    wchar_t error_wide[256];
                    MultiByteToWideChar(CP_UTF8, 0, push_result.error_message, -1, error_wide, 256);
                    swprintf_s(msg, L"Push failed:\n%s", error_wide);
                    MessageBoxW(hwnd, msg, L"Push Error", MB_OK | MB_ICONERROR);
                }
            }
        } else {
            // Check for non-fast-forward rejection
            wchar_t msg[512];
            if (push_result.ref_count > 0 &&
                push_result.ref_results[0].status == PushRefStatus::NonFastForward) {
                swprintf_s(msg, L"Push rejected: non-fast-forward.\n\nThe remote has changes you don't have locally.\nPull first, then try pushing again.");
                MessageBoxW(hwnd, msg, L"Push Rejected", MB_OK | MB_ICONWARNING);
            } else {
                wchar_t error_wide[256];
                MultiByteToWideChar(CP_UTF8, 0, push_result.error_message, -1, error_wide, 256);
                swprintf_s(msg, L"Push failed:\n%s", error_wide);
                MessageBoxW(hwnd, msg, L"Push Error", MB_OK | MB_ICONERROR);
            }
        }
    }

    InvalidateRect(hwnd, nullptr, FALSE);
    return 0;
}

// WM_PULL_COMPLETE handler
static LRESULT handle_wm_pull_complete(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)wParam; (void)lParam;
    // Get result from worker API
    const PullResult* pull_result_ptr = worker_get_pull_result();
    PullResult pull_result = *pull_result_ptr;  // Copy result struct

    const PullProgress* progress_ptr = worker_get_pull_progress();

    char remote_name[64] = "origin";  // TODO: Get from worker state

    // Stop progress timer
    KillTimer(hwnd, PULL_PROGRESS_TIMER_ID);

    bool success = (wParam != 0);

    if (success) {
        wchar_t msg[512];
        if (pull_result.commits_pulled == 0) {
            swprintf_s(msg, L"Already up to date.");
        } else {
            swprintf_s(msg, L"Pull successful!\n\nCommits pulled: %d\nFiles updated: %zu\nDuration: %lld ms",
                       pull_result.commits_pulled,
                       pull_result.files_updated,
                       pull_result.duration_ms);
        }
        MessageBoxW(hwnd, msg, L"Pull Complete", MB_OK | MB_ICONINFORMATION);

        // Refresh state
        {
            RepoLockGuard lock;
            git_read_head(&g_repo);
            sidebar_load_status();
            status_bar_update_fetch_time();
            git_sync_status(&g_repo, remote_name, &g_status_bar.sync_status);
        }

        // Clear diff viewer (files may have changed)
        diff_viewer_clear();
    } else {
        // Check if authentication is required
        if (strstr(pull_result.error_message, "Authentication") || strstr(pull_result.error_message, "authentication")) {
            // Extract host from remote URL
            char host[256];
            {
                RepoLockGuard lock;
                if (extract_host_from_remote(&g_repo, remote_name, host, sizeof(host))) {
                    // Save pending operation for retry after auth
                    g_pending_operation.type = PendingOpType::Pull;
                    strncpy_s(g_pending_operation.remote_name, remote_name, sizeof(g_pending_operation.remote_name) - 1);

                    // Choose authentication method based on host
                    if (is_github_host(host)) {
                        // GitHub uses OAuth Device Flow
                        if (!start_oauth_flow(host)) {
                            show_auth_dialog(host);
                        }
                    } else {
                        show_auth_dialog(host);
                    }
                } else {
                    // Couldn't extract host, show error
                    wchar_t msg[512];
                    wchar_t error_wide[256];
                    MultiByteToWideChar(CP_UTF8, 0, pull_result.error_message, -1, error_wide, 256);
                    swprintf_s(msg, L"Pull failed:\n%s", error_wide);
                    MessageBoxW(hwnd, msg, L"Pull Error", MB_OK | MB_ICONERROR);
                }
            }
        } else {
            wchar_t msg[512];
            wchar_t error_wide[256];
            MultiByteToWideChar(CP_UTF8, 0, pull_result.error_message, -1, error_wide, 256);

            PullPhase phase = progress_ptr->phase.load();
            if (phase == PullPhase::NotFastForward) {
                swprintf_s(msg,
                    L"Cannot fast-forward pull.\n\n"
                    L"Your branch has local commits that are not on the remote.\n"
                    L"Push your changes first, or create a merge commit manually.");
            } else if (phase == PullPhase::DirtyWorkdir) {
                swprintf_s(msg,
                    L"Cannot pull with uncommitted changes.\n\n"
                    L"Commit or stash your changes first.");
            } else {
                swprintf_s(msg, L"Pull failed:\n%s", error_wide);
            }
            MessageBoxW(hwnd, msg, L"Pull Error", MB_OK | MB_ICONERROR);
        }
    }

    InvalidateRect(hwnd, nullptr, FALSE);
    return 0;
}

// WM_CHECKOUT_COMPLETE handler
static LRESULT handle_wm_checkout_complete(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)wParam; (void)lParam;
    // Get result from worker API
    const CheckoutResult* checkout_result_ptr = worker_get_checkout_result();
    CheckoutResult checkout_result = *checkout_result_ptr;

    char ref_name[Git::MAX_REF_NAME] = "HEAD";  // TODO: Get from worker state

    // Stop progress timer
    KillTimer(hwnd, CHECKOUT_PROGRESS_TIMER_ID);

    bool success = (wParam != 0);

    if (success) {
        // Refresh all UI state
        {
            RepoLockGuard lock;
            git_read_head(&g_repo);

            // Reload branches (in case tracking branch was created)
            g_sidebar.branch_count = git_list_refs(&g_repo, g_sidebar.branches, 128);

            // Find current branch index
            g_sidebar.current_branch_index = -1;
            for (size_t i = 0; i < g_sidebar.branch_count; i++) {
                if (g_sidebar.branches[i].type == GitRef::Type::Local &&
                    strcmp(g_sidebar.branches[i].name, g_repo.head_ref) == 0) {
                    g_sidebar.current_branch_index = static_cast<int>(i);
                    break;
                }
            }

            // Update current branch name for display
            if (g_repo.head_detached) {
                // Show short SHA for detached HEAD
                wchar_t sha_wide[16];
                MultiByteToWideChar(CP_UTF8, 0, g_repo.head_sha, 7, sha_wide, 16);
                sha_wide[7] = L'\0';
                swprintf_s(g_sidebar.current_branch_name, L"HEAD (%s...)", sha_wide);
            } else {
                MultiByteToWideChar(CP_UTF8, 0, g_repo.head_ref, -1,
                                   g_sidebar.current_branch_name, 256);
            }
        }

        // Rebuild branch tree
        build_branch_tree();
        sidebar_branch_tree_widget_invalidate();

        // Reload commit history for new branch
        commit_history_load();

        // Reload status and diff viewer
        sidebar_load_status();

        // Clear diff viewer if no files changed
        if (g_sidebar.staged_count == 0 && g_sidebar.changed_count == 0) {
            diff_viewer_clear();
        }

        // Update status bar branch name
        MultiByteToWideChar(CP_UTF8, 0, g_repo.head_ref, -1, g_status_bar.branch_name, 256);

        // Update sync status
        git_sync_status(&g_repo, "origin", &g_status_bar.sync_status);
    } else {
        wchar_t msg[512];
        wchar_t error_wide[256];
        MultiByteToWideChar(CP_UTF8, 0, checkout_result.error_message, -1, error_wide, 256);
        swprintf_s(msg, L"Checkout failed:\n%s", error_wide);
        MessageBoxW(hwnd, msg, L"Checkout Error", MB_OK | MB_ICONERROR);
    }

    InvalidateRect(hwnd, nullptr, FALSE);
    return 0;
}

// WM_CLONE_COMPLETE handler
static LRESULT handle_wm_clone_complete(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)lParam;

    // Stop progress timer
    KillTimer(hwnd, CLONE_PROGRESS_TIMER_ID);

    // Close the clone dialog (it stays open during progress)
    clone_dialog_close();

    // Get result from worker API
    const CloneResult* clone_result = worker_get_clone_result();
    bool success = (wParam != 0);

    if (success) {
        // Open the cloned repository
        const wchar_t* dest_path = worker_get_clone_destination();
        try_open_repository(dest_path);
    } else {
        // Check if clone was cancelled - don't show error in that case
        const CloneProgress* progress = worker_get_clone_progress();
        bool was_cancelled = progress->phase.load() == ClonePhase::Cancelled ||
                             progress->base.cancel_requested.load();

        // Clean up partial clone directory
        const wchar_t* dest_path = worker_get_clone_destination();
#ifdef GITSMARTER_DEBUG
        LOG("WM_CLONE_COMPLETE - DEBUG: Keeping failed clone directory for inspection: %ls", dest_path);
#else
        if (dest_path && dir_exists(dest_path)) {
            if (!delete_directory_recursive(dest_path)) {
                LOG("WM_CLONE_COMPLETE - Failed to clean up partial clone directory: %ls", dest_path);
                wchar_t cleanup_msg[512];
                swprintf_s(cleanup_msg, _countof(cleanup_msg),
                           L"Failed to clean up partial clone directory:\n%ls\n\n"
                           L"You may need to delete this folder manually.",
                           dest_path);
                MessageBoxW(hwnd, cleanup_msg, L"Cleanup Warning", MB_OK | MB_ICONWARNING);
            }
        }
#endif

        if (!was_cancelled) {
            // Check if authentication is required
            if (strstr(clone_result->error_message, "Authentication") ||
                strstr(clone_result->error_message, "authentication")) {
                LOG("WM_CLONE_COMPLETE - Authentication error detected, triggering auth dialog");

                // Extract host from clone URL
                const char* clone_url = worker_get_clone_url();
                char host[256];
                if (extract_host_from_url(clone_url, host, sizeof(host))) {
                    LOG("WM_CLONE_COMPLETE - Extracted host: %s", host);

                    // Save pending operation for retry after auth
                    g_pending_operation.type = PendingOpType::Clone;
                    strncpy_s(g_pending_operation.clone_url, clone_url, sizeof(g_pending_operation.clone_url) - 1);
                    wcscpy_s(g_pending_operation.clone_destination, dest_path);

                    LOG("WM_CLONE_COMPLETE - Showing auth dialog for host: %s", host);

                    // Choose authentication method based on host
                    if (is_github_host(host)) {
                        // GitHub uses OAuth Device Flow
                        LOG("WM_CLONE_COMPLETE - Using OAuth for GitHub");
                        if (!start_oauth_flow(host)) {
                            // OAuth failed to start, fall back to username/password
                            LOG("WM_CLONE_COMPLETE - OAuth failed, falling back to username/password");
                            show_auth_dialog(host);
                        }
                    } else {
                        // All other hosts use username/password
                        show_auth_dialog(host);
                    }

                    InvalidateRect(hwnd, nullptr, FALSE);
                    return 0;  // Don't show error message, auth dialog handles it
                } else {
                    LOG("WM_CLONE_COMPLETE - Failed to extract host from clone URL");
                }
            }

            // Show error message (not auth error, or couldn't extract host)
            wchar_t msg[512];
            wchar_t error_wide[256];
            MultiByteToWideChar(CP_UTF8, 0, clone_result->error_message, -1, error_wide, 256);
            swprintf_s(msg, L"Clone failed:\n%s", error_wide);
            MessageBoxW(hwnd, msg, L"Clone Error", MB_OK | MB_ICONERROR);
        }
    }

    InvalidateRect(hwnd, nullptr, FALSE);
    return 0;
}

// WM_FILE_CHANGED handler
static LRESULT handle_wm_file_changed(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)wParam;
    // File watcher sent a change notification
    const wchar_t* path = reinterpret_cast<const wchar_t*>(lParam);

    // Debounce rapid changes by starting/restarting a timer
    // This batches multiple file changes into a single refresh
    SetTimer(hwnd, 9, 200, nullptr);

    // Free the path if it was allocated
    if (path) {
        delete[] path;
    }

    return 0;
}

// WM_AUTH_COMPLETE handler
static LRESULT handle_wm_auth_complete(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    (void)lParam;
    bool success = (wParam != 0);

    LOG("WM_AUTH_COMPLETE - success=%d, pending_op_type=%d", success, (int)g_pending_operation.type);

    // Close widget-based dialogs (auth and OAuth)
    dialog_widgets_close_all();

    if (success) {
        // Retry the failed operation
        bool retry_started = false;

        if (g_pending_operation.type == PendingOpType::Fetch) {
            LOG("WM_AUTH_COMPLETE - Retrying fetch operation (remote: %s, silent: %d)",
                g_pending_operation.remote_name, g_pending_operation.silent);
            retry_started = worker_start_async_fetch(g_pending_operation.remote_name,
                                              g_pending_operation.silent);
        } else if (g_pending_operation.type == PendingOpType::Push) {
            LOG("WM_AUTH_COMPLETE - Retrying push operation (remote: %s, ref: %s)",
                g_pending_operation.remote_name, g_pending_operation.ref_name);
            retry_started = worker_start_async_push(g_pending_operation.remote_name,
                                             g_pending_operation.ref_name, false);
        } else if (g_pending_operation.type == PendingOpType::Pull) {
            LOG("WM_AUTH_COMPLETE - Retrying pull operation (remote: %s)",
                g_pending_operation.remote_name);
            retry_started = worker_start_async_pull(g_pending_operation.remote_name);
        } else if (g_pending_operation.type == PendingOpType::Clone) {
            LOG("WM_AUTH_COMPLETE - Retrying clone operation (url: %s)",
                g_pending_operation.clone_url);
            retry_started = worker_start_async_clone(g_pending_operation.clone_url,
                                                     g_pending_operation.clone_destination);
        }

        LOG("WM_AUTH_COMPLETE - Retry result: %s", retry_started ? "SUCCESS" : "FAILED");

        // Clear pending operation
        g_pending_operation.type = PendingOpType::None;

        if (!retry_started && g_pending_operation.type != PendingOpType::None) {
            LOG("WM_AUTH_COMPLETE - Failed to start retry operation");
            MessageBoxW(hwnd, L"Failed to retry operation after authentication.",
                       L"Error", MB_OK | MB_ICONERROR);
        }
    } else {
        // Auth cancelled - clear pending operation
        LOG("WM_AUTH_COMPLETE - Auth cancelled by user");
        g_pending_operation.type = PendingOpType::None;
    }

    InvalidateRect(hwnd, nullptr, FALSE);
    return 0;
}

