// WM_MOUSEWHEEL handler
static LRESULT handle_wm_mousewheel(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    // Get mouse position in client coords for WM_MOUSEWHEEL
    POINT pt = { GET_X_LPARAM(lParam), GET_Y_LPARAM(lParam) };
    ScreenToClient(hwnd, &pt);
    int x = pt.x;
    int y = pt.y;

    int delta = GET_WHEEL_DELTA_WPARAM(wParam);
    float wheel_delta_normalized = static_cast<float>(delta) / WHEEL_DELTA;

    // Widget framework gets first priority - blocks input when modal dialog active
    // (handles branch dialog, stash dialog, etc.)
    if (g_event_dispatcher.dispatch_mouse_wheel(static_cast<float>(x), static_cast<float>(y), wheel_delta_normalized)) {
        InvalidateRect(hwnd, nullptr, FALSE);
        return 0;
    }

    if (g_current_screen == AppScreen::Repository) {
        // Check if mouse is over sidebar - use widget system for routing
        float sidebar_width = g_sidebar_widget ? g_sidebar_widget->sidebar_width : g_sidebar.width;
        if (x < static_cast<int>(sidebar_width)) {
            float fx = static_cast<float>(x);
            float fy = static_cast<float>(y);

            // Route through sidebar widget dispatcher (handles section targeting internally)
            if (g_sidebar_widget && g_sidebar_dispatcher.dispatch_mouse_wheel(fx, fy, wheel_delta_normalized)) {
                InvalidateRect(hwnd, nullptr, FALSE);
                return 0;
            }
        }

        // Check if mouse is over commit history panel (use widget system)
        if (commit_history_widget_hit_test(static_cast<float>(x), static_cast<float>(y))) {
            if (commit_history_widget_handle_mouse_wheel(static_cast<float>(x), static_cast<float>(y), wheel_delta_normalized)) {
                InvalidateRect(hwnd, nullptr, FALSE);
                return 0;
            }
        } else if (diff_viewer_widget_hit_test(static_cast<float>(x), static_cast<float>(y))) {
            // Scroll widget-based diff viewer (Phase 18)
            float wheel_delta = static_cast<float>(delta) / WHEEL_DELTA;

            // Shift+Wheel = horizontal scroll
            bool shift_held = (GetKeyState(VK_SHIFT) & 0x8000) != 0;
            if (shift_held && g_diff_scroll_container) {
                // Horizontal scroll
                g_diff_scroll_container->scroll_by_column(wheel_delta > 0 ? -3 : 3);
            } else {
                // Vertical scroll (positive = scroll up, matching widget framework convention)
                diff_viewer_widget_handle_mouse_wheel(static_cast<float>(x), static_cast<float>(y), wheel_delta);
            }
            InvalidateRect(hwnd, nullptr, FALSE);
        }
    }

    return 0;
}

// WM_MOUSEHWHEEL handler
static LRESULT handle_wm_mousehwheel(HWND hwnd, WPARAM wParam, LPARAM lParam) {
    // Horizontal mouse wheel (for mice/trackpads with horizontal scroll)
    POINT pt = { GET_X_LPARAM(lParam), GET_Y_LPARAM(lParam) };
    ScreenToClient(hwnd, &pt);
    int x = pt.x;
    int y = pt.y;

    int delta = GET_WHEEL_DELTA_WPARAM(wParam);
    float wheel_delta_normalized = static_cast<float>(delta) / WHEEL_DELTA;

    // Widget framework gets first priority (handles dialogs with code editors, etc.)
    if (g_event_dispatcher.dispatch_mouse_hwheel(static_cast<float>(x), static_cast<float>(y), wheel_delta_normalized)) {
        InvalidateRect(hwnd, nullptr, FALSE);
        return 0;
    }

    // Fall back to direct handling for diff viewer
    if (g_current_screen == AppScreen::Repository) {
        if (diff_viewer_widget_hit_test(static_cast<float>(x), static_cast<float>(y))) {
            // In side-by-side mode, use DiffViewerWidget's horizontal scrolling
            if (g_diff_viewer_widget && g_diff_viewer_widget->view_mode == DiffViewMode::SideBySide) {
                // Positive delta = scroll right, negative = scroll left
                // Use larger scroll increment for wheel (3 columns)
                g_diff_viewer_widget->scroll_by_column_h(delta > 0 ? 3 : -3);
                InvalidateRect(hwnd, nullptr, FALSE);
            } else if (g_diff_scroll_container) {
                // Inline mode: use ScrollContainer's horizontal scroll
                g_diff_scroll_container->scroll_by_column(delta > 0 ? 3 : -3);
                InvalidateRect(hwnd, nullptr, FALSE);
            }
        }
    }
    return 0;
}

