// Command execution wrappers (called from command_registry.cpp)
void cmd_stage_all() {
    if (g_sidebar.changed_count > 0) {
        RepoLockGuard lock;
        if (git_stage_all(&g_repo)) {
            sidebar_load_status();
            InvalidateRect(g_main_window, nullptr, FALSE);
        }
    }
}

void cmd_unstage_all() {
    if (g_sidebar.staged_count > 0) {
        RepoLockGuard lock;
        if (git_unstage_all(&g_repo)) {
            sidebar_load_status();
            InvalidateRect(g_main_window, nullptr, FALSE);
        }
    }
}

void cmd_fetch() {
    if (worker_is_busy()) {
        return;
    }
    GitRemote remote;
    bool has_remote;
    {
        RepoLockGuard lock;
        has_remote = git_remote_load(&g_repo, "origin", &remote);
    }
    if (has_remote) {
        worker_start_async_fetch("origin");
    }
}

void cmd_push() {
    if (worker_is_busy()) return;
    if (g_repo.head_ref[0] == '\0' || g_repo.head_detached) return;

    char head_ref_copy[Git::MAX_REF_NAME];
    {
        RepoLockGuard lock;
        strcpy_s(head_ref_copy, g_repo.head_ref);
    }
    worker_start_async_push("origin", head_ref_copy, false);
}

void cmd_pull() {
    if (worker_is_busy()) return;
    worker_start_async_pull("origin");
}

void cmd_commit() {
    // Focus the commit box and let user enter message
    g_sidebar.commit_box_focused = true;
    InvalidateRect(g_main_window, nullptr, FALSE);
}

void cmd_stash() {
    stash_dialog_widget_show();
}

